# Commands that generate images and are user-triggered in groups
IMAGE_COMMANDS = {"strikemap", "momentum", "scorecard", "mystats", "leaderboard", "lb", "players", "soloplayers"}

def check_image_cooldown(group_id: int) -> Optional[float]:
    """
    Returns remaining cooldown seconds if still in cooldown, else None.
    Should only be called for GROUP chats (not DMs).
    """
    last = image_cooldown_tracker.get(group_id, 0.0)
    elapsed = time.time() - last
    remaining = IMAGE_COOLDOWN_SECONDS - elapsed
    if remaining > 0:
        return remaining
    return None

def set_image_cooldown(group_id: int):
    """Mark image just sent in this group."""
    image_cooldown_tracker[group_id] = time.time()

async def send_cooldown_warning(update: Update, remaining: float):
    """Send a short ephemeral-style cooldown warning."""
    secs = math.ceil(remaining)
    bars_filled = int((IMAGE_COOLDOWN_SECONDS - remaining) / IMAGE_COOLDOWN_SECONDS * 10)
    bar = "รขโห" * bars_filled + "รขโโ" * (10 - bars_filled)
    msg = (
        f"รขยยณ <b>Image Cooldown Active</b>\n"
        f"รขโลรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโย\n"
        f"รขโโ  <code>[{bar}]</code>  รขโโ\n"
        f"รขโโ  รขยยฑ Wait <b>{secs}s</b> moreรขโฌยฆ      รขโโ\n"
        f"รขโโรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโห\n"
        f"<i>Image commands cool down every {IMAGE_COOLDOWN_SECONDS}s to reduce server load.</i>"
    )
    try:
        warn = await update.message.reply_text(msg, parse_mode=ParseMode.HTML)
        # Auto-delete warning after the remaining cooldown
        asyncio.get_event_loop().call_later(
            remaining + 1,
            lambda: asyncio.ensure_future(warn.delete())
        )
    except Exception:
        pass

# Game Constants
class GamePhase(Enum):
    IDLE = "idle"
    # ... Team Phases ...
    TEAM_JOINING = "team_joining"
    HOST_SELECTION = "host_selection"
    CAPTAIN_SELECTION = "captain_selection"
    TEAM_EDIT = "team_edit"
    OVER_SELECTION = "over_selection"
    TOSS = "toss"
    MATCH_IN_PROGRESS = "match_in_progress"
    INNINGS_BREAK = "innings_break"
    MATCH_ENDED = "match_ended"
    SUPER_OVER = "super_over"
    SUPER_OVER_BREAK = "super_over_break"
    
    # ... MAGIC BALL MODE ...
    MAGIC_BALL = "magic_ball"    

    # ... SOLO PHASES (New) ...
    SOLO_JOINING = "solo_joining"
    SOLO_MATCH = "solo_match"
    
    # ... AI MODE (DM Play vs AI) ...
    AI_MODE = "ai_mode"

class AuctionPhase(Enum):
    IDLE = "idle"
    BIDDER_SELECTION = "bidder_selection"
    PLAYER_ADDITION = "player_addition"
    AUCTION_LIVE = "auction_live"
    AUCTION_ENDED = "auction_ended"

class AuctionTeam:
    """Represents a team in auction"""
    def __init__(self, name: str):
        self.name = name
        self.bidder_id: Optional[int] = None
        self.bidder_name: str = ""
        self.players: List[Dict] = []  # {player_id, player_name, price}
        self.purse_remaining = 1000
        self.total_spent = 0
    
    def add_player(self, player_id: int, player_name: str, price: int):
        self.players.append({
            "player_id": player_id,
            "player_name": player_name,
            "price": price
        })
        self.purse_remaining -= price
        self.total_spent += price

class MatchEvent(Enum):
    DOT_BALL = "dot"
    RUNS_1 = "1run"
    RUNS_2 = "2runs"
    RUNS_3 = "3runs"
    RUNS_4 = "4runs"
    RUNS_5 = "5runs"
    RUNS_6 = "6runs"
    WICKET = "wicket"
    NO_BALL = "noball"
    WIDE = "wide"
    FREE_HIT = "freehit"
    DRS_REVIEW = "drs_review"
    DRS_OUT = "drs_out"
    DRS_NOT_OUT = "drs_notout"
    INNINGS_BREAK = "innings_break"
    VICTORY = "victory"


class Auction:
    """Main auction class"""
    def __init__(self, group_id: int, group_name: str, host_id: int, host_name: str):
        self.group_id = group_id
        self.group_name = group_name
        self.host_id = host_id
        self.host_name = host_name
        self.phase = AuctionPhase.BIDDER_SELECTION
        self.created_at = datetime.now()
        
        # Teams
        self.teams: Dict[str, AuctionTeam] = {}
        
        # Auctioneer
        self.auctioneer_id: Optional[int] = None
        self.auctioneer_name: str = ""
        self.auctioneer_change_votes: Set[int] = set()
        
        # Current auction
        self.current_player_id: Optional[int] = None
        self.current_player_name: str = ""
        self.current_base_price = 0
        self.current_highest_bid = 0
        self.current_highest_bidder: Optional[str] = None
        self.bid_timer_task: Optional[asyncio.Task] = None
        self.bid_end_time: Optional[float] = None
        
        # Player pool
        self.player_pool: List[Dict] = []  # {player_id, player_name, base_price}
        self.sold_players: List[Dict] = []
        self.unsold_players: List[Dict] = []
        
        # Assist mode
        self.assist_mode: Dict[str, bool] = {}  # team_name: is_assisted
        
        # UI
        self.main_message_id: Optional[int] = None
        
        # Auction history log (Feature: Auction History Log)
        self.auction_history: List[Dict] = []  # {player_name, player_id, team, price, sold}
        self.history_message_id: Optional[int] = None  # pinned running log message
        
        # Countdown message (Feature: Live countdown timer)
        self.countdown_message_id: Optional[int] = None
        
        # Sold confirmation (auctioneer must confirm within 10s or auto-sold)
        self.pending_sold_confirmation: bool = False  # waiting for auctioneer to confirm
        self.sold_confirmation_task: Optional[asyncio.Task] = None
        self.bids_frozen: bool = False  # no bids accepted during transition



