# รฐลธลฝยจ THEMED MESSAGE FORMATTER (รขโขยญรขโยรขโยรขโฦรขโขยฐ style)
# รขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขย
def themed(title: str, lines: list, emoji: str = "รฐลธยย") -> str:
    """
    Build a themed bordered message.
    title  รขโฌโ header text after รขโขยญรขโยรขโย
    lines  รขโฌโ list of strings; each becomes a รขโฦ line
    emoji  รขโฌโ decorative emoji appended to the border title
    Returns a fully-formatted HTML-safe string.
    """
    dashes = "รขโย" * max(1, 22 - len(title))
    header = f"รขโขยญรขโยรขโย {title} {dashes} {emoji}"
    body = "\n".join(f"รขโฦ {l}" for l in lines)
    footer = "รขโขยฐ" + "รขโย" * 26
    return f"{header}\n{body}\n{footer}"


# --- GLOBAL HELPER FUNCTION (FIXED) ---
def get_user_tag(user):
    """Returns a clickable HTML link for the user"""
    if not user:
        return "Unknown"
    
    # รขลโฆ FIX: Handle both User objects AND Player objects
    try:
        # Case 1: Telegram User object (has .id)
        if hasattr(user, 'id'):
            user_id = user.id
            first_name = user.first_name
        # Case 2: Player object (has .user_id)
        elif hasattr(user, 'user_id'):
            user_id = user.user_id
            first_name = user.first_name
        else:
            return "Unknown"
        
        # Clean the name to prevent HTML errors
        clean_name = html.escape(first_name)
        return f'<a href=\"tg://user?id={user_id}\">{clean_name}</a>'
    except Exception as e:
        logger.error(f"Error creating user tag: {e}")
        return "Unknown"

