_ai_commentary_cache: Dict[str, List[str]] = defaultdict(list)  # style+event -> cached lines
_ai_commentary_lock = asyncio.Lock()

_AI_COMMENTARY_STYLE_PROMPTS = {
    "english": (
        "You are a professional cricket commentator. Generate ONE short, punchy commentary line "
        "(max 12 words) for the following ball event. Be vivid, dramatic, and varied. "
        "No quotation marks. Just the commentary sentence."
    ),
    "shubh": (
        "You are Shubh, a savage Hinglish cricket commentator. Generate ONE brutal roast-style "
        "commentary line (max 15 words, mix Hindi and English) for the following ball event. "
        "Be very funny and savage. No quotation marks."
    ),
    "sidhu": (
        "You are Navjot Singh Sidhu, the legendary cricket commentator known for hilarious Punjabi "
        "proverbs and metaphors. Generate ONE commentary line (max 15 words) for the following "
        "ball event using Sidhu-style Punjabi wisdom or metaphor. No quotation marks."
    ),
}

_AI_EVENT_DESCRIPTIONS = {
    "dot": "the batsman played and missed, no run scored - a dot ball",
    "single": "the batsman hit the ball and ran a single run",
    "double": "the batsman hit the ball and they ran two runs",
    "triple": "the batsman hit the ball and they ran three runs",
    "boundary": "the batsman hit a beautiful boundary for four runs",
    "five": "five runs scored - likely overthrows or misfield",
    "six": "the batsman smashed a massive six over the boundary",
    "wicket": "the batsman is OUT! A wicket has fallen",
    "noball": "the bowler has bowled a no ball - illegal delivery",
    "wide": "the bowler has bowled a wide - extra run conceded",
    "freehit": "it's a free hit! The batsman cannot be dismissed",
}

async def get_ai_commentary_async(event_type: str, style: str = "english") -> str:
    """Fetch one AI-generated commentary line. Falls back to static if API fails."""
    cache_key = f"{style}:{event_type}"
    
    # Serve from pre-fetched cache if available
    if _ai_commentary_cache[cache_key]:
        return _ai_commentary_cache[cache_key].pop()
    
    system_prompt = _AI_COMMENTARY_STYLE_PROMPTS.get(style, _AI_COMMENTARY_STYLE_PROMPTS["english"])
    event_desc = _AI_EVENT_DESCRIPTIONS.get(event_type, event_type)
    
    try:
        import aiohttp
        payload = {
            "model": "claude-haiku-4-5-20251001",
            "max_tokens": 60,
            "system": system_prompt,
            "messages": [{"role": "user", "content": f"Ball event: {event_desc}. Generate commentary:"}]
        }
        async with aiohttp.ClientSession() as session:
            async with session.post(
                "https://api.anthropic.com/v1/messages",
                headers={"Content-Type": "application/json", "anthropic-version": "2023-06-01"},
                json=payload,
                timeout=aiohttp.ClientTimeout(total=4.0)
            ) as resp:
                if resp.status == 200:
                    data = await resp.json()
                    text = data.get("content", [{}])[0].get("text", "").strip()
                    if text:
                        return text
    except Exception as e:
        logger.debug(f"AI commentary API call failed ({event_type}/{style}): {e}")
    
    # Fallback to static commentary
    return get_commentary(event_type, group_id=None, user_id=None)

async def prefetch_ai_commentary(event_type: str, style: str = "english", count: int = 3):
    """Pre-warm the AI commentary cache in background."""
    cache_key = f"{style}:{event_type}"
    if len(_ai_commentary_cache[cache_key]) >= count:
        return
    for _ in range(count - len(_ai_commentary_cache[cache_key])):
        line = await get_ai_commentary_async(event_type, style)
        if line:
            _ai_commentary_cache[cache_key].append(line)

def get_commentary_with_ai_fallback(event_type: str, group_id: int = None, user_id: int = None) -> str:
    """Synchronous wrapper: returns static commentary immediately (AI is async, used in async contexts)."""
    return get_commentary(event_type, group_id=group_id, user_id=user_id)

def save_match_stats(match, winner_team, loser_team):
    """Save match statistics - ENHANCED WITH COMPLETE TRACKING"""
    try:
        # Save winner team stats
        for player in winner_team.players:
            user_id = player.user_id
            init_player_stats(user_id)
            
            stats = player_stats[user_id]
            team_stats = stats.get("team", {})
            
            # Complete stat tracking
            team_stats["matches"] = team_stats.get("matches", 0) + 1
            team_stats["matches_played"] = team_stats.get("matches_played", 0) + 1
            team_stats["wins"] = team_stats.get("wins", 0) + 1
            team_stats["runs"] = team_stats.get("runs", 0) + player.runs
            team_stats["balls"] = team_stats.get("balls", 0) + player.balls_faced
            team_stats["wickets"] = team_stats.get("wickets", 0) + player.wickets
            team_stats["fours"] = team_stats.get("fours", 0) + player.boundaries
            team_stats["sixes"] = team_stats.get("sixes", 0) + player.sixes
            team_stats["dots"] = team_stats.get("dots", 0) + getattr(player, 'dots', 0)
            
            # Update highest score
            if player.runs > team_stats.get("highest", 0):
                team_stats["highest"] = player.runs
            
            # Milestone tracking
            if player.runs >= 100:
                team_stats["centuries"] = team_stats.get("centuries", 0) + 1
            elif player.runs >= 50:
                team_stats["fifties"] = team_stats.get("fifties", 0) + 1
            elif player.runs == 0 and player.balls_faced > 0:
                team_stats["ducks"] = team_stats.get("ducks", 0) + 1
            
            stats["team"] = team_stats
            player_stats[user_id] = stats
        
        # Save loser team stats (everything except wins)
        for player in loser_team.players:
            user_id = player.user_id
            init_player_stats(user_id)
            
            stats = player_stats[user_id]
            team_stats = stats.get("team", {})
            
            team_stats["matches"] = team_stats.get("matches", 0) + 1
            team_stats["matches_played"] = team_stats.get("matches_played", 0) + 1
            team_stats["runs"] = team_stats.get("runs", 0) + player.runs
            team_stats["balls"] = team_stats.get("balls", 0) + player.balls_faced
            team_stats["wickets"] = team_stats.get("wickets", 0) + player.wickets
            team_stats["fours"] = team_stats.get("fours", 0) + player.boundaries
            team_stats["sixes"] = team_stats.get("sixes", 0) + player.sixes
            team_stats["dots"] = team_stats.get("dots", 0) + getattr(player, 'dots', 0)
            
            # Update highest score
            if player.runs > team_stats.get("highest", 0):
                team_stats["highest"] = player.runs
            
            # Milestone tracking
            if player.runs >= 100:
                team_stats["centuries"] = team_stats.get("centuries", 0) + 1
            elif player.runs >= 50:
                team_stats["fifties"] = team_stats.get("fifties", 0) + 1
            elif player.runs == 0 and player.balls_faced > 0:
                team_stats["ducks"] = team_stats.get("ducks", 0) + 1
            
            stats["team"] = team_stats
            player_stats[user_id] = stats
        
        save_data()
        
        # Sync team stats to DB columns so mystats team view shows correct data
        _all_team_players = list(winner_team.players) + list(loser_team.players)
        try:
            conn_s = sqlite3.connect(DB_PATH)
            cs = conn_s.cursor()
            for player in _all_team_players:
                uid = player.user_id
                ts = player_stats.get(uid, {}).get("team", {})
                is_win = 1 if player in winner_team.players else 0
                cs.execute("""INSERT INTO user_stats 
                    (user_id, username, first_name,
                     team_matches_played, team_matches_won,
                     team_total_runs, team_total_balls_faced,
                     team_total_wickets, team_total_balls_bowled,
                     team_total_sixes, team_total_fours,
                     team_highest_score, team_total_hundreds,
                     team_total_fifties, team_total_ducks, team_total_dots)
                    VALUES (?, ?, ?,
                        ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                    ON CONFLICT(user_id) DO UPDATE SET
                        username = excluded.username,
                        first_name = excluded.first_name,
                        team_matches_played = team_matches_played + 1,
                        team_matches_won = team_matches_won + ?,
                        team_total_runs = team_total_runs + ?,
                        team_total_balls_faced = team_total_balls_faced + ?,
                        team_total_wickets = team_total_wickets + ?,
                        team_total_balls_bowled = team_total_balls_bowled + ?,
                        team_total_sixes = team_total_sixes + ?,
                        team_total_fours = team_total_fours + ?,
                        team_highest_score = MAX(team_highest_score, ?),
                        team_total_hundreds = team_total_hundreds + ?,
                        team_total_fifties = team_total_fifties + ?,
                        team_total_ducks = team_total_ducks + ?,
                        team_total_dots = team_total_dots + ?
                """, (
                    uid, player.username or "", player.first_name,
                    1, is_win,
                    player.runs, player.balls_faced,
                    player.wickets, player.balls_bowled,
                    getattr(player, 'sixes', 0), getattr(player, 'boundaries', 0),
                    player.runs, 
                    1 if player.runs >= 100 else 0,
                    1 if 50 <= player.runs < 100 else 0,
                    1 if player.runs == 0 and player.balls_faced > 0 else 0,
                    getattr(player, 'dots', 0),
                    # ON CONFLICT UPDATE values
                    is_win, player.runs, player.balls_faced,
                    player.wickets, player.balls_bowled,
                    getattr(player, 'sixes', 0), getattr(player, 'boundaries', 0),
                    player.runs,
                    1 if player.runs >= 100 else 0,
                    1 if 50 <= player.runs < 100 else 0,
                    1 if player.runs == 0 and player.balls_faced > 0 else 0,
                    getattr(player, 'dots', 0)
                ))
            conn_s.commit()
            conn_s.close()
        except Exception as db_err:
            logger.error(f"Team stats DB sync error: {db_err}")
        
        logger.info("รขลโฆ Match stats saved with complete tracking")
        
    except Exception as e:
        logger.error(f"รขยล Stats save error: {e}")
        import traceback
        traceback.print_exc()


async def update_joining_board(context: ContextTypes.DEFAULT_TYPE, chat_id: int, match: Match):
    """
    Updates the Joining Board safely (Handling Photo Caption vs Text)
    """
    if not match.main_message_id: return

    # Generate fresh text
    text = get_team_join_message(match)
    
    # Buttons
    keyboard = [
        [InlineKeyboardButton("รฐลธยงล  Join Team X", callback_data="join_team_x"),
         InlineKeyboardButton("รฐลธโยฅ Join Team Y", callback_data="join_team_y")],
        [InlineKeyboardButton("รฐลธลกยช Leave Team", callback_data="leave_team")]
    ]
    reply_markup = InlineKeyboardMarkup(keyboard)

    try:
        # Try editing as Photo Caption first (Since we are using Images)
        await context.bot.edit_message_caption(
            chat_id=chat_id,
            message_id=match.main_message_id,
            caption=text,
            reply_markup=reply_markup,
            parse_mode=ParseMode.HTML
        )
    except Exception as e:
        error_str = str(e).lower()
        
        # Agar "message is not modified" error hai, toh ignore karo (Sab same hai)
        if "message is not modified" in error_str:
            return
            
        # Agar error aaya ki "there is no caption" implies it's a TEXT message (Fallback)
        # Toh hum text edit karenge
        try:
            await context.bot.edit_message_text(
                chat_id=chat_id,
                message_id=match.main_message_id,
                text=text,
                reply_markup=reply_markup,
                parse_mode=ParseMode.HTML
            )
        except Exception as text_e:
            # Agar phir bhi fail hua, toh log karo par crash mat hone do
            pass

async def refresh_game_message(context: ContextTypes.DEFAULT_TYPE, chat_id: int, match: Match, caption: str, reply_markup: InlineKeyboardMarkup = None, media_key: str = None):
    """Delete old message, send new pinned message for every phase transition"""
    
    # Step 1: Delete old pinned message
    if match.main_message_id:
        try:
            await context.bot.unpin_chat_message(chat_id=chat_id, message_id=match.main_message_id)
        except Exception:
            pass
        try:
            await context.bot.delete_message(chat_id=chat_id, message_id=match.main_message_id)
        except Exception:
            pass
        match.main_message_id = None

    # Step 2: Send new message
    try:
        if media_key and media_key in MEDIA_ASSETS:
            msg = await context.bot.send_photo(
                chat_id=chat_id,
                photo=MEDIA_ASSETS[media_key],
                caption=caption,
                reply_markup=reply_markup,
                parse_mode=ParseMode.HTML
            )
        else:
            msg = await context.bot.send_message(
                chat_id=chat_id,
                text=caption,
                reply_markup=reply_markup,
                parse_mode=ParseMode.HTML
            )
        
        match.main_message_id = msg.message_id
        
        # Step 3: Pin new message
        try:
            await context.bot.pin_chat_message(
                chat_id=chat_id,
                message_id=msg.message_id,
                disable_notification=True
            )
        except Exception:
            pass
    except Exception as e:
        logger.error(f"refresh_game_message send failed: {e}")

