async def cheer_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Cheer for a player by tagging them!"""
    chat = update.effective_chat
    user = update.effective_user
    
    # 1. Detect Target User
    target_name = "everyone"
    if update.message.reply_to_message:
        target_name = update.message.reply_to_message.from_user.first_name
    elif context.args:
        # Handle mentions like @username or text
        target_name = " ".join(context.args)

    # 2. Cheer Message
    cheer_msg = f"รขโขยญรขโยรขโย รฐลธลฝโฐ CHEER SQUAD รขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรฐลธโยฃ\n"
    cheer_msg += f"รขโฦ รฐลธโยฃ {html.escape(user.first_name)} is screaming\n"
    cheer_msg += f"รขโฦ    for {html.escape(target_name)}!\n"
    cheer_msg += "รขโฦ\n"
    cheer_msg += "รขโฦ \"COME ON! YOU GOT THIS! รฐลธยยรฐลธโยฅ\"\n"
