async def scorecard_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """รฐลธยย Enhanced scorecard รขโ โ auto-detects Team/Solo mode"""
    group_id = update.effective_chat.id
    match = active_matches.get(group_id)

    if not match:
        await update.message.reply_text("รฐลธยย No active match! Use /game to begin")
        return

    # รขโโฌรขโโฌ SOLO MODE: show solo leaderboard instead รขโโฌรขโโฌ
    if getattr(match, 'game_mode', None) in ["SOLO", "MAGICBALL"] or match.phase in [GamePhase.SOLO_JOINING, GamePhase.SOLO_MATCH]:
        sorted_players = sorted(match.solo_players, key=lambda x: x.runs, reverse=True)
        medals = ["รฐลธยฅโก", "รฐลธยฅห", "รฐลธยฅโฐ"]
        msg = "รฐลธยโ  <b>SOLO BATTLE LEADERBOARD</b>\n"
        msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
        for i, p in enumerate(sorted_players, 1):
            rank = medals[i-1] if i <= 3 else f"<b>{i}.</b>"
            status = ""
            if p.is_out: status = " รขยล"
            elif (i-1) == match.current_solo_bat_idx: status = " รฐลธยย"
