# Callback query handler for mode selection
async def mode_selection_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    chat = query.message.chat
    user = query.from_user

    if chat.id in active_matches:
        await query.message.reply_text("รขลกย รฏยธย Match already active!")
        return

    if query.data == "mode_team":
        await start_team_mode(query, context, chat, user)

    elif query.data == "mode_solo":
        # ... (Same code as before) ...
        match = Match(chat.id, chat.title)
        match.game_mode = "SOLO"
        match.phase = GamePhase.SOLO_JOINING
        match.host_id = user.id
        match.host_name = user.first_name
        match.solo_join_end_time = time.time() + get_gc_setting(match.group_id, "lobby_time", 120)

        active_matches[chat.id] = match

        if user.id not in player_stats:
            init_player_stats(user.id)

        p = Player(user.id, user.username or "", user.first_name)
        match.solo_players.append(p)

        await update_solo_board(context, chat.id, match)
        match.solo_timer_task = asyncio.create_task(
            solo_join_countdown(context, chat.id, match)
        )

    elif query.data == "mode_tournament":
        # Check approval
        if chat.id not in TOURNAMENT_APPROVED_GROUPS:
            await query.answer(
                "รฐลธลกยซ Tournament not approved! Contact bot owner.",
                show_alert=True
            )
            return
        
        # Only group admins can use tournament mode
        member = await context.bot.get_chat_member(chat.id, user.id)
        if member.status not in ["administrator", "creator"]:
            await query.answer("รฐลธลกยซ Only group admins can access Tournament Mode!", show_alert=True)
            return

        # Show tournament 5-button menu
        keyboard = [
            [InlineKeyboardButton("รฐลธยย Start Match", callback_data="tour_start_match")],
            [InlineKeyboardButton("รฐลธโล  Points Table", callback_data="tour_points_table"),
             InlineKeyboardButton("รฐลธโโน Fixtures", callback_data="tour_fixtures")],
            [InlineKeyboardButton("รขลยรฏยธย Edit Team", callback_data="tour_edit_team"),
             InlineKeyboardButton("รฐลธโโข Back", callback_data="back_to_modes")]
        ]

        caption = (
            "รขโขยญรขโยรขโย รฐลธยโ  TOURNAMENT CONTROL CENTER รขโยรขโยรฐลธยโฆ\n"
            "รขโฦ รฐลธลฝยฏ Manage your championship league!\n"
            "รขโฦ\n"
            "รขโฦ รฐลธโโน MANAGEMENT COMMANDS\n"
            "รขโฦ รขโล /teamcreate [name]         รขลพโ Create franchise\n"
            "รขโฦ รขโล /teamadd [name] @user      รขลพโ Add squad member\n"
            "รขโฦ รขโล /teamremove [name] @user   รขลพโ Bench squad member\n"
            "รขโฦ รขโโ /teamdelete [name]         รขลพโ Dissolve franchise\n"
            "รขโฦ\n"
            "รขโฦ รฐลธโโก Use the controls below to navigate!\n"
            "รขโขยฐรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโย"
        )


        try:
            await query.message.edit_caption(
                caption=caption,
                reply_markup=InlineKeyboardMarkup(keyboard),
                parse_mode=ParseMode.HTML
            )
        except Exception:
            try:
                photo = MEDIA_ASSETS.get("tournament_mode")
                await context.bot.send_photo(
                    chat_id=chat.id,
                    photo=photo,
                    caption=caption,
                    reply_markup=InlineKeyboardMarkup(keyboard),
                    parse_mode=ParseMode.HTML
                )
            except:
                await query.message.reply_text(
                    caption,
                    reply_markup=InlineKeyboardMarkup(keyboard),
                    parse_mode=ParseMode.HTML
                )
    
    elif query.data == "mode_ai":
        # AI Mode - Play vs Bot in DM
        await query.answer("รฐลธยคโ Opening AI Mode in your DM...", show_alert=True)
        
        # Send DM to user
        try:
            await context.bot.send_message(
                chat_id=user.id,
                text=(
                    "รขโขยญรขโยรขโย รฐลธยคโ AI MODE รขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรฐลธลฝยฎ\n"
                    "รขโฦ รขลกโข Play vs Computer รขโฌโ single player!\n"
                    "รขโฦ\n"
                    "รขโฦ Welcome to AI mode!\n"
                    "รขโฦ You'll face an intelligent bot opponent.\n"
                    "รขโฦ\n"
                    "รขโฦ รขลกโข Use: /aistart to begin a match!\n"
                    "รขโขยฐรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโย"
                ),
                parse_mode=ParseMode.HTML
            )
        except Forbidden:
            await query.message.reply_text(
                "รขลกย รฏยธย Please start the bot in DM first!\n"
                f"Click here: @{(await context.bot.get_me()).username}"
            )

    elif query.data == "mode_magicball":
        # Magic Ball Mode - Solo match with special power-up balls
        match = Match(chat.id, chat.title)
        match.game_mode = "MAGICBALL"
        match.magic_ball_mode = True
        match.phase = GamePhase.SOLO_JOINING
        match.host_id = user.id
        match.host_name = user.first_name
        match.solo_join_end_time = time.time() + get_gc_setting(match.group_id, "lobby_time", 120)

        active_matches[chat.id] = match

        if user.id not in player_stats:
            init_player_stats(user.id)

        p = Player(user.id, user.username or "", user.first_name)
        match.solo_players.append(p)

        await update_solo_board(context, chat.id, match)
        match.solo_timer_task = asyncio.create_task(
            solo_join_countdown(context, chat.id, match)
        )

async def auction_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle auction related callbacks"""
    query = update.callback_query
    await query.answer()
    
    if query.data == "start_auction":
        # ... (Check active auctions code) ...
        chat = query.message.chat
        user = query.from_user
        
        if chat.id in active_auctions:
            await query.answer("Auction already active!", show_alert=True)
            return
        
        auction = Auction(chat.id, chat.title, user.id, user.first_name)
        active_auctions[chat.id] = auction
        
        msg = (
            "รขโขยญรขโยรขโย รฐลธยยฆ AUCTION SETUP รขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรฐลธโยฐ\n"
            "รขโฦ รขลกโข Follow these steps to begin!\n"
            "รขโฦ\n"
            "รขโฦ รฐลธโโน NEXT STEPS\n"
            "รขโฦ รขโล 1รฏยธยรขฦยฃ /bidder [team]      รขลพโ Assign bidders\n"
            "รขโฦ รขโล 2รฏยธยรขฦยฃ /aucplayer          รขลพโ Add players\n"
            "รขโฦ รขโล 3รฏยธยรขฦยฃ Select auctioneer below\n"
            "รขโฦ รขโโ 4รฏยธยรขฦยฃ /startauction       รขลพโ Go live!\n"
            "รขโฦ\n"
            "รขโฦ รฐลธโยฐ Default Purse: 1000\n"
            "รขโขยฐรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโย"
        )
        
        keyboard = [[InlineKeyboardButton("รฐลธลฝยค Be Auctioneer", callback_data="become_auctioneer")]]
        
        # รขลโฆ FIX: Use edit_caption
        await query.message.edit_caption(
            caption=msg,
            reply_markup=InlineKeyboardMarkup(keyboard),
            parse_mode=ParseMode.HTML
        )
    
    elif query.data == "become_auctioneer":
        chat = query.message.chat
        user = query.from_user
        
        if chat.id not in active_auctions:
            return
        
        auction = active_auctions[chat.id]
        auction.auctioneer_id = user.id
        auction.auctioneer_name = user.first_name
        
        # รขลโฆ FIX: Use edit_caption
        await query.message.edit_caption(
            caption=f"รขลโฆ <b>Auctioneer Set!</b>\n\nรฐลธลฝยค {get_user_tag(user)}\n\nNext: Assign bidders with <code>/bidder</code>",
            parse_mode=ParseMode.HTML
        )
    
    elif query.data == "back_to_modes":
        keyboard = [
            [InlineKeyboardButton("รฐลธโยฅ Team Mode", callback_data="mode_team"),
            InlineKeyboardButton("รขลกโรฏยธย Solo Mode", callback_data="mode_solo")],
            [InlineKeyboardButton("รฐลธยโ  Tournament", callback_data="mode_tournament")]
        ]
        
        # รขลโฆ FIX: Use edit_caption
        await query.message.edit_caption(
            caption="รขโขยญรขโยรขโย รฐลธลฝยฎ SELECT GAME MODE รขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรฐลธยย\nรขโฦ รขลกโข Choose your battle style below!\nรขโขยฐรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโย",
            reply_markup=InlineKeyboardMarkup(keyboard),
            parse_mode=ParseMode.HTML
        )

