async def teamcreate_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Create a tournament team: /teamcreate [team name]"""
    chat = update.effective_chat
    user = update.effective_user

    if chat.type == "private":
        await update.message.reply_text("Use this command in a group!")
        return

    group_id = chat.id

    # Check approval รขโ โ silently ignore unapproved groups
    if group_id not in TOURNAMENT_APPROVED_GROUPS:
        return

    # Admin check
    member = await context.bot.get_chat_member(group_id, user.id)
    if member.status not in ["administrator", "creator"]:
        await update.message.reply_text("รฐลธลกยซ Only group admins can create teams!")
        return
    
    if not context.args:
        await update.message.reply_text(
            "รฐลธโโน Usage: <code>/teamcreate [team name]</code>\nExample: <code>/teamcreate Team Alpha</code>",
            parse_mode=ParseMode.HTML
        )
        return
    
    team_name = " ".join(context.args).strip()
    
    if team_name in tournament_teams[group_id]:
        await update.message.reply_text(f"รขลกย รฏยธย Team '<b>{team_name}</b>' already exists!", parse_mode=ParseMode.HTML)
        return
    
    tournament_teams[group_id][team_name] = {"players": [], "captain": None}
    
    await update.message.reply_text(
        f"รขลโฆ <b>Team Created!</b>\n"
        f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        f"รฐลธยย <b>Team:</b> {team_name}\n\n"
        f"Now add players:\n"
        f"<code>/teamadd {team_name} @username @username2...</code>",
        parse_mode=ParseMode.HTML
    )


async def teamadd_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Add players to tournament team: /teamadd [team] @user @user2...
    Also supports reply to add single user, or user IDs."""
    chat = update.effective_chat
    user = update.effective_user
    
    if chat.type == "private":
        await update.message.reply_text("Use this command in a group!")
        return
    
    group_id = chat.id
    
    if group_id not in TOURNAMENT_APPROVED_GROUPS:
        return
    
    member = await context.bot.get_chat_member(group_id, user.id)
    if member.status not in ["administrator", "creator"]:
        await update.message.reply_text("รฐลธลกยซ Only admins can add players!")
        return
    
    if not context.args:
        await update.message.reply_text(
            "รฐลธโโน Usage: <code>/teamadd [team name] @user @user2...</code>",
            parse_mode=ParseMode.HTML
        )
        return
    
    # Parse: first arg(s) might be multi-word team name, then @mentions
    args = context.args
    teams = tournament_teams.get(group_id, {})
    
    # Find team name (try progressively longer phrases)
    team_name = None
    player_args_start = 0
    for i in range(len(args), 0, -1):
        potential = " ".join(args[:i])
        if potential in teams:
            team_name = potential
            player_args_start = i
            break
    
    if not team_name:
        team_list = ", ".join(teams.keys()) if teams else "None"
        await update.message.reply_text(
            f"รขลกย รฏยธย Team not found!\nAvailable teams: {team_list}",
            parse_mode=ParseMode.HTML
        )
        return
    
    player_args = args[player_args_start:]
    added = []
    failed = []
    
    # Parse mentions and user IDs
    entities = update.message.entities or []
    mentioned_users = []
    for entity in entities:
        if entity.type == "mention":
            username = update.message.text[entity.offset+1:entity.offset+entity.length]
            try:
                chat_member = await context.bot.get_chat_member(group_id, f"@{username}")
                mentioned_users.append({
                    "user_id": chat_member.user.id,
                    "username": chat_member.user.username or "",
                    "first_name": chat_member.user.first_name
                })
            except:
                failed.append(f"@{username}")
        elif entity.type == "text_mention" and entity.user:
            mentioned_users.append({
                "user_id": entity.user.id,
                "username": entity.user.username or "",
                "first_name": entity.user.first_name
            })
    
    # Also check numeric user IDs in args
    for arg in player_args:
        if arg.isdigit():
            try:
                cm = await context.bot.get_chat_member(group_id, int(arg))
                mentioned_users.append({
                    "user_id": cm.user.id,
                    "username": cm.user.username or "",
                    "first_name": cm.user.first_name
                })
            except:
                failed.append(arg)
    
    team_data = tournament_teams[group_id][team_name]
    existing_ids = {p["user_id"] for p in team_data["players"]}
    
    not_started = []  # Users who haven't started the bot
    for p in mentioned_users:
        if p["user_id"] not in existing_ids:
            # รขลโฆ Check if player has started the bot before adding
            started = await check_user_started_bot(context.bot, p["user_id"])
            if not started:
                not_started.append(p["first_name"])
                # Still add them รขโฌโ but warn the admin
            team_data["players"].append(p)
            existing_ids.add(p["user_id"])
            added.append(p["first_name"])
    
    bot_username = context.bot.username
    msg = f"รขลโฆ <b>Players Added to {team_name}</b>\nรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
    if added:
        msg += f"รขลโฆ Added: {', '.join(added)}\n"
    if failed:
        msg += f"รขลกย รฏยธย Not found in group: {', '.join(failed)}\n"
    if not_started:
        msg += (
            f"\nรขลกย รฏยธย <b>Hasn't started bot:</b> {', '.join(not_started)}\n"
            f"รฐลธโโฐ Ask them to start: <a href='https://t.me/{bot_username}'>@{bot_username}</a>\n"
            f"<i>They won't receive bowl/bat DMs until they do!</i>\n"
        )
    msg += f"\nรฐลธโล  <b>Team size:</b> {len(team_data['players'])} players"
    
    await update.message.reply_text(msg, parse_mode=ParseMode.HTML, disable_web_page_preview=True)


async def teamremove_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Remove player(s) from tournament team: /teamremove [team] @user @user2..."""
    chat = update.effective_chat
    user = update.effective_user
    
    if chat.type == "private":
        return
    
    group_id = chat.id
    
    if group_id not in TOURNAMENT_APPROVED_GROUPS:
        return
    
    member = await context.bot.get_chat_member(group_id, user.id)
    if member.status not in ["administrator", "creator"]:
        await update.message.reply_text("รฐลธลกยซ Only admins can remove players!")
        return
    
    if not context.args:
        await update.message.reply_text(
            "รฐลธโโน Usage: <code>/teamremove [team name] @user @user2...</code>",
            parse_mode=ParseMode.HTML
        )
        return
    
    args = context.args
    teams = tournament_teams.get(group_id, {})
    
    team_name = None
    player_args_start = 0
    for i in range(len(args), 0, -1):
        potential = " ".join(args[:i])
        if potential in teams:
            team_name = potential
            player_args_start = i
            break
    
    if not team_name:
        await update.message.reply_text("รขลกย รฏยธย Team not found!")
        return
    
    # Collect IDs to remove
    ids_to_remove = set()
    entities = update.message.entities or []
    for entity in entities:
        if entity.type == "mention":
            username = update.message.text[entity.offset+1:entity.offset+entity.length]
            try:
                cm = await context.bot.get_chat_member(group_id, f"@{username}")
                ids_to_remove.add(cm.user.id)
            except:
                pass
        elif entity.type == "text_mention" and entity.user:
            ids_to_remove.add(entity.user.id)
    
    for arg in context.args[player_args_start:]:
        if arg.isdigit():
            ids_to_remove.add(int(arg))
    
    team_data = tournament_teams[group_id][team_name]
    before = len(team_data["players"])
    team_data["players"] = [p for p in team_data["players"] if p["user_id"] not in ids_to_remove]
    after = len(team_data["players"])
    removed = before - after
    
    await update.message.reply_text(
        f"รขลโฆ <b>Removed {removed} player(s) from {team_name}</b>\n"
        f"รฐลธโล  <b>Team size:</b> {after} players",
        parse_mode=ParseMode.HTML
    )


async def tourresult_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Record tournament match result: /tourresult [winning_team]"""
    chat = update.effective_chat
    user = update.effective_user
    group_id = chat.id
    
    if chat.type == "private":
        return
    
    if group_id not in TOURNAMENT_APPROVED_GROUPS:
        return
    
    member = await context.bot.get_chat_member(group_id, user.id)
    if member.status not in ["administrator", "creator"]:
        await update.message.reply_text("รฐลธลกยซ Only admins can record results!")
        return
    
    if group_id not in pending_tour_match:
        await update.message.reply_text("รขลกย รฏยธย No active tournament match found!")
        return
    
    if not context.args:
        await update.message.reply_text(
            "รฐลธโโน Usage: <code>/tourresult [winning team name]</code>\nOr <code>/tourresult tie</code>",
            parse_mode=ParseMode.HTML
        )
        return
    
    tm = pending_tour_match[group_id]
    t1 = tm["team1"]
    t2 = tm["team2"]
    match_id = tm["match_id"]
    winner_arg = " ".join(context.args).strip().lower()
    
    pts = tournament_points[group_id]
    for tn in [t1, t2]:
        if tn not in pts:
            pts[tn] = {"played": 0, "won": 0, "lost": 0, "tied": 0, "pts": 0, "nrr": 0.0}
    
    if winner_arg == "tie":
        pts[t1]["played"] += 1
        pts[t2]["played"] += 1
        pts[t1]["tied"] += 1
        pts[t2]["tied"] += 1
        pts[t1]["pts"] += 1
        pts[t2]["pts"] += 1
        result_str = "Tie"
    else:
        # Match team name
        winner = None
        for tn in [t1, t2]:
            if tn.lower() == winner_arg or winner_arg in tn.lower():
                winner = tn
                break
        
        if not winner:
            await update.message.reply_text(f"รขลกย รฏยธย Team not found! Valid teams: {t1}, {t2}")
            return
        
        loser = t2 if winner == t1 else t1
        pts[winner]["played"] += 1
        pts[loser]["played"] += 1
        pts[winner]["won"] += 1
        pts[loser]["lost"] += 1
        pts[winner]["pts"] += 2
        result_str = f"{winner} won"
    
    # Update fixture
    for fix in tournament_fixtures[group_id]:
        if fix["match_id"] == match_id:
            fix["result"] = result_str
            break
    
    del pending_tour_match[group_id]
    
    await update.message.reply_text(
        f"รขลโฆ <b>RESULT RECORDED!</b>\n"
        f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        f"รขลกโรฏยธย <b>{t1}</b> vs <b>{t2}</b>\n"
        f"รฐลธยโ  <b>Result:</b> {result_str}\n\n"
        f"Points table has been updated!",
        parse_mode=ParseMode.HTML
    )


async def tourlb_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Tournament leaderboard: /tourlb รขโ โ attractive paginated image version"""
    chat = update.effective_chat
    user = update.effective_user
    group_id = chat.id

    if chat.type == "private":
        await update.message.reply_text("Use in a group!")
        return

    if group_id not in TOURNAMENT_APPROVED_GROUPS:
        return

    # Build category text
    def _tourlb_text(group_id: int, metric: str = "runs") -> str:
        all_runs = {}
        all_wickets = {}
        all_sixes = {}
        all_fours = {}

        for match_id, stats in tour_match_stats.get(group_id, {}).items():
            for pid, val in stats.get("player_runs", {}).items():
                all_runs.setdefault(pid, {"name": str(pid), "total": 0})["total"] += val
            for pid, val in stats.get("player_wickets", {}).items():
                all_wickets.setdefault(pid, {"name": str(pid), "total": 0})["total"] += val
            for pid, val in stats.get("player_sixes", {}).items():
                all_sixes.setdefault(pid, {"name": str(pid), "total": 0})["total"] += val
            for pid, val in stats.get("player_fours", {}).items():
                all_fours.setdefault(pid, {"name": str(pid), "total": 0})["total"] += val

        medals = ["รฐลธยฅโก", "รฐลธยฅห", "รฐลธยฅโฐ", "4รฏยธยรขฦยฃ", "5รฏยธยรขฦยฃ", "6รฏยธยรขฦยฃ", "7รฏยธยรขฦยฃ", "8รฏยธยรขฦยฃ", "9รฏยธยรขฦยฃ", "รฐลธโลธ"]

        if metric == "runs":
            title = "รฐลธยฦ TOP RUN SCORERS"
            data = sorted(all_runs.values(), key=lambda x: -x["total"])
            lines = [f"{medals[i]} <b>{d['name'][:18]}</b>  รขโ โ  {d['total']} runs" for i, d in enumerate(data[:10])]
        elif metric == "wickets":
            title = "รขลกยพ TOP WICKET TAKERS"
            data = sorted(all_wickets.values(), key=lambda x: -x["total"])
            lines = [f"{medals[i]} <b>{d['name'][:18]}</b>  รขโ โ  {d['total']} wkts" for i, d in enumerate(data[:10])]
        elif metric == "sixes":
            title = "รฐลธลกโฌ MOST SIXES"
            data = sorted(all_sixes.values(), key=lambda x: -x["total"])
            lines = [f"{medals[i]} <b>{d['name'][:18]}</b>  รขโ โ  {d['total']} รฐลธลกโฌ" for i, d in enumerate(data[:10])]
        elif metric == "fours":
            title = "4รฏยธยรขฦยฃ MOST FOURS"
            data = sorted(all_fours.values(), key=lambda x: -x["total"])
            lines = [f"{medals[i]} <b>{d['name'][:18]}</b>  รขโ โ  {d['total']} fours" for i, d in enumerate(data[:10])]
        else:
            title = "รฐลธยฦ TOP RUN SCORERS"
            lines = []

        total_matches = len(tour_match_stats.get(group_id, {}))
        text = f"รฐลธยโ  <b>TOURNAMENT LEADERBOARD</b>\n"
        text += f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        text += f"รฐลธโล  {total_matches} match(es) played\n"
        text += f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        text += f"<b>{title}</b>\n\n"
        if lines:
            text += "\n".join(lines)
        else:
            text += "<i>No data yet รขโ โ complete some matches!</i>"
        text += "\nรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ"
        return text

    metric = "runs"
    text = _tourlb_text(group_id, metric)
    kb = InlineKeyboardMarkup([
        [InlineKeyboardButton("รฐลธยฦ Runs",    callback_data=f"tourlb_{group_id}_runs"),
         InlineKeyboardButton("รขลกยพ Wickets", callback_data=f"tourlb_{group_id}_wickets")],
        [InlineKeyboardButton("รฐลธลกโฌ Sixes",   callback_data=f"tourlb_{group_id}_sixes"),
         InlineKeyboardButton("4รฏยธยรขฦยฃ Fours",   callback_data=f"tourlb_{group_id}_fours")],
    ])

    # Try generate image
    try:
        img_bio = await asyncio.to_thread(generate_tour_leaderboard_image, group_id)
    except Exception:
        img_bio = None

    try:
        if img_bio:
            await update.message.reply_photo(photo=img_bio, caption=text, parse_mode=ParseMode.HTML, reply_markup=kb)
        else:
            photo = MEDIA_ASSETS.get("tournament_mode")
            await update.message.reply_photo(photo=photo, caption=text, parse_mode=ParseMode.HTML, reply_markup=kb)
    except:
        await update.message.reply_text(text, parse_mode=ParseMode.HTML, reply_markup=kb)


async def update_solo_board(context, chat_id, match):
    """Updates the Solo Joining List with Host Tag"""
    count = len(match.solo_players)
    
    # Time Calc
    remaining = int(match.solo_join_end_time - time.time())
    if remaining < 0: remaining = 0
    mins, secs = divmod(remaining, 60)
    
    # Generate Host Tag
    if match.host_id and match.host_name:
        host_tag = f'<a href=\"tg://user?id={match.host_id}\">{match.host_name}</a>'
    else:
        host_tag = "Unknown"
    
    msg = "รขลกโรฏยธย <b>SOLO BATTLE ROYALE</b> รขลกโรฏยธย\n"
    msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
    msg += f"รฐลธลฝโข <b>Host:</b> {host_tag}\n"
    msg += f"รขยยณ <b>Time Left:</b> <code>{mins:02d}:{secs:02d}</code>\n"
    msg += f"รฐลธโยฅ <b>Players Joined:</b> {count}\n\n"
    
    msg += "<b>PLAYER LIST:</b>\n"
    if match.solo_players:
        for i, p in enumerate(match.solo_players, 1):
            ptag = f'<a href=\"tg://user?id={p.user_id}\">{p.first_name}</a>'
            msg += f"  {i}. {ptag}\n"
    else:
        msg += "  <i>Waiting for players...</i>\n"
        
    msg += "\nรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
    msg += "รฐลธโโก <i>Click Join to Enter the Ground!</i>"
    
    # Buttons
    keyboard = [
        [InlineKeyboardButton("รขลโฆ Join Battle", callback_data="solo_join"),
         InlineKeyboardButton("รฐลธลกยช Leave", callback_data="solo_leave")]
    ]
    
    # Show START button if enough players
    if count >= 2:
        keyboard.append([InlineKeyboardButton("รฐลธลกโฌ START MATCH", callback_data="solo_start_game")])
        
    await refresh_game_message(context, chat_id, match, msg, InlineKeyboardMarkup(keyboard), media_key="joining")

async def start_team_mode(query, context: ContextTypes.DEFAULT_TYPE, chat, user):
    """Initialize team mode with Fancy Image"""
    # Create new match
    match = Match(chat.id, chat.title)
    active_matches[chat.id] = match
    
    # Set time (2 minutes)
    match.team_join_end_time = time.time() + get_gc_setting(match.group_id, "lobby_time", 120)
    
    # Buttons
    keyboard = [
        [InlineKeyboardButton("รฐลธยงล  Join Team X", callback_data="join_team_x"),
         InlineKeyboardButton("รฐลธโยฅ Join Team Y", callback_data="join_team_y")],
        [InlineKeyboardButton("รฐลธลกยช Leave Team", callback_data="leave_team")]
    ]
    reply_markup = InlineKeyboardMarkup(keyboard)
    
    # Fancy Text
    text = get_team_join_message(match)
    
    # Send using Master Function (With Image)
    await refresh_game_message(context, chat.id, match, text, reply_markup, media_key="joining")
    
    # Start Timer
    match.join_phase_task = asyncio.create_task(
        team_join_countdown(context, chat.id, match)
    )

def get_team_join_message(match: Match) -> str:
    """Generate Professional Joining List"""
    remaining = max(0, int(match.team_join_end_time - time.time()))
    minutes = remaining // 60
    seconds = remaining % 60
    
    total_p = len(match.team_x.players) + len(match.team_y.players)
    
