# Toss callback
async def toss_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle toss selection safely"""
    query = update.callback_query
    await query.answer()
    
    chat = query.message.chat
    user = query.from_user
    
    if chat.id not in active_matches:
        await query.answer("No active match found.", show_alert=True)
        return
    
    match = active_matches[chat.id]
    
    if match.phase != GamePhase.TOSS:
        await query.answer("Toss phase has ended.", show_alert=True)
        return
    
    # Only Team X captain can call toss
    if user.id != match.team_x.captain_id:
        await query.answer("Only Team X Captain can call the toss.", show_alert=True)
        return
    
    # Determine toss result
    toss_result = random.choice(["heads", "tails"])
    captain_call = "heads" if query.data == "toss_heads" else "tails"
    
    if toss_result == captain_call:
        match.toss_winner = match.team_x
        winner_captain = match.team_x.get_player(match.team_x.captain_id)
    else:
        match.toss_winner = match.team_y
        winner_captain = match.team_y.get_player(match.team_y.captain_id)
    
    # Ask winner to choose bat or bowl
    keyboard = [
        [InlineKeyboardButton("รฐลธยย Bat First", callback_data="toss_decision_bat")],
        [InlineKeyboardButton("รขลกยพ Bowl First", callback_data="toss_decision_bowl")]
    ]
    reply_markup = InlineKeyboardMarkup(keyboard)
    
    decision_text = f"รขโขยญรขโยรขโย รฐลธยชโข TOSS OUTCOME รขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรฐลธยโ \n"
    decision_text += f"รขโฦ รฐลธลฝโฐ {match.toss_winner.name} won the toss!\n"
    decision_text += f"รขโฦ รฐลธลธยก Landed on: {toss_result.upper()}\n"
    decision_text += f"รขโฦ\n"
    decision_text += f"รขโฦ รฐลธโโ Captain {winner_captain.first_name}, choose!\n"
    decision_text += f"รขโฦ รขยยฑ Decision Time: 30 seconds\n"
    decision_text += f"รขโขยฐรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโย"

    
    # รขลโฆ FIX: Use refresh_game_message instead of edit_message_text
    await refresh_game_message(context, chat.id, match, decision_text, reply_markup, media_key="toss")
    
    # Set timeout for decision
    asyncio.create_task(toss_decision_timeout(context, chat.id, match))

async def toss_decision_timeout(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """Handle toss decision timeout"""
    await asyncio.sleep(30)
    
    if match.phase != GamePhase.TOSS:
        return
    
    # Auto select bat if no decision made
    match.batting_first = match.toss_winner
    match.bowling_first = match.get_other_team(match.toss_winner)
    
    await start_match(context, group_id, match, auto_decision=True)

# Toss decision callback
async def toss_decision_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle bat/bowl decision"""
    query = update.callback_query
    await query.answer()
    
    chat = query.message.chat
    user = query.from_user
    
    if chat.id not in active_matches:
        await query.answer("No active match found.", show_alert=True)
        return
    
    match = active_matches[chat.id]
    
    if match.phase != GamePhase.TOSS:
        await query.answer("Toss phase has ended.", show_alert=True)
        return
    
    # Only toss winner captain can decide
    winner_captain = match.get_captain(match.toss_winner)
    if user.id != winner_captain.user_id:
        await query.answer("Only the toss winner captain can decide.", show_alert=True)
        return
    
    if query.data == "toss_decision_bat":
        match.batting_first = match.toss_winner
        match.bowling_first = match.get_other_team(match.toss_winner)
    else:
        match.bowling_first = match.toss_winner
        match.batting_first = match.get_other_team(match.toss_winner)
    
    await start_match(context, chat.id, match, auto_decision=False)

async def start_match(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match, auto_decision: bool):
    """Start the actual match with prediction poll - FIXED WORKFLOW"""
    match.phase = GamePhase.MATCH_IN_PROGRESS
    match.current_batting_team = match.batting_first
    match.current_bowling_team = match.bowling_first
    match.innings = 1
    
    # รขลโฆ CRITICAL: Reset Batsmen & Bowler indices to None (Fresh Start)
    match.current_batting_team.current_batsman_idx = None
    match.current_batting_team.current_non_striker_idx = None
    match.current_bowling_team.current_bowler_idx = None
    
    # รขลโฆ Enable Waiting Flags
    match.waiting_for_batsman = True
    match.waiting_for_bowler = False 

    # Cleanup the Toss Board
    if match.main_message_id:
        try:
            await context.bot.unpin_chat_message(chat_id=group_id, message_id=match.main_message_id)
        except: pass

    # Send toss summary
    decision_method = "chose to" if not auto_decision else "will"
    toss_summary = "รฐลธยลธรฏยธย <b>MATCH HAS BEGUN!</b>\n"
    toss_summary += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
    toss_summary += f"รฐลธยชโข <b>Toss Winner:</b> {match.toss_winner.name}\n"
    toss_summary += f"รฐลธยย <b>Decision:</b> {match.batting_first.name} {decision_method} bat first\n"
    toss_summary += f"รฐลธโย <b>Format:</b> <code>{match.total_overs} Overs</code> per innings\n"
    
    await context.bot.send_message(chat_id=group_id, text=toss_summary, parse_mode=ParseMode.HTML)
    
    # รขลโฆ CREATE PREDICTION POLL
    await create_prediction_poll(context, group_id, match)
    
    # Wait 3 seconds for effect
    await asyncio.sleep(3)
    
    # รขลโฆ REQUEST STRIKER ONLY (Step 1)
    captain = match.get_captain(match.current_batting_team)
    if not captain:
        await context.bot.send_message(group_id, "รขลกย รฏยธย No captain found!", parse_mode=ParseMode.HTML)
        return
    
    captain_tag = get_user_tag(captain)
    
    opener_lines = [
        f"รฐลธโโ {captain_tag}, select your opening batsman:",
        f"รขลยจรฏยธย Use <code>/batting [number]</code> to select.",
        f"รฐลธโยฅ <b>Squad Pool:</b> {len(match.current_batting_team.players)} players available",
    ]
    msg = themed("รฐลธยย SELECT OPENING BATSMAN", opener_lines, "รฐลธยย")

    
    await context.bot.send_message(group_id, msg, parse_mode=ParseMode.HTML)
    
    # Start selection timer
    match.batsman_selection_time = time.time()
    match.batsman_selection_task = asyncio.create_task(
        batsman_selection_timeout(context, group_id, match)
    )

async def request_batsman_selection(context: ContextTypes.DEFAULT_TYPE, chat_id: int, match: Match):
    """Prompt captain for new batsman after wicket"""
    # รขโโฌรขโโฌ Check batting queue first รขโโฌรขโโฌ
    bat_team = match.current_batting_team
    queued_idx = _pop_next_batsman(chat_id, bat_team)
    if queued_idx is not None:
        bat_team.current_batsman_idx = queued_idx
        match.waiting_for_batsman = False
        queued_player = bat_team.players[queued_idx]
        player_tag = get_user_tag(queued_player)
        await context.bot.send_message(
            chat_id,
            f"รฐลธยย <b>NEXT BATSMAN (from queue):</b> {player_tag} walks in!",
            parse_mode=ParseMode.HTML
        )
        logger.info(f"รขลโฆ Auto-selected queued batsman: {queued_player.first_name}")
        await asyncio.sleep(1)
        if match.current_bowling_team.current_bowler_idx is not None:
            await execute_ball(context, chat_id, match)
        return

    captain = match.get_captain(bat_team)
    if not captain:
        await context.bot.send_message(chat_id, "รขลกย รฏยธย No captain selected! Use /captain to set one.")
        return

    captain_tag = get_user_tag(captain)
    
    # Count available batsmen for display
    available_batsmen_count = len([
        p for i, p in enumerate(bat_team.players)
        if i not in bat_team.out_players_indices
        and i != bat_team.current_non_striker_idx
        and i != bat_team.current_batsman_idx
    ])
    
    bat_msg_lines = [
        f"รฐลธยย {captain_tag} รขลพโ Send in your next batsman!",
        f"รขลกโข Use: <code>/batting [number]</code>",
        f"รขยยณ Hint: Use <code>/qbatting</code> to pre-queue a batsman",
    ]
    msg = themed("SELECT BATSMAN", bat_msg_lines, "รฐลธยย")
    
    await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML)
    
    # Start 30s timer for selection
    match.batsman_selection_time = time.time() + 30
    match.batsman_selection_task = asyncio.create_task(
        selection_timer(context, chat_id, match, "batsman", captain.first_name)
    )

async def selection_timer(context: ContextTypes.DEFAULT_TYPE, chat_id: int, match: Match, selection_type: str, name: str):
    """Timeout for batsman/bowler selection (30s)"""
    await asyncio.sleep(30)
    if (selection_type == "batsman" and match.waiting_for_batsman and 
        time.time() >= match.batsman_selection_time) or \
       (selection_type == "bowler" and match.waiting_for_bowler and 
        time.time() >= match.bowler_selection_time):
        msg = f"รขยยฐ <b>{name}</b> timed out on {selection_type} selection! Random selected."
        await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML)
        await auto_select_player(context, chat_id, match, selection_type)

async def auto_select_player(context: ContextTypes.DEFAULT_TYPE, chat_id: int, match: Match, selection_type: str):
    """Randomly select player on timeout"""
    if selection_type == "batsman":
        team = match.current_batting_team
        available = [p for idx, p in enumerate(team.players) if idx not in team.out_players_indices and 
                     idx != team.current_batsman_idx and idx != team.current_non_striker_idx]
        if available:
            random_idx = random.choice([i for i in range(len(team.players)) if i not in team.out_players_indices and 
                                        i != team.current_batsman_idx and i != team.current_non_striker_idx])
            team.current_batsman_idx = random_idx  # New striker
            match.waiting_for_batsman = False
            await resume_after_selection(context, chat_id, match)
    elif selection_type == "bowler":
        team = match.current_bowling_team
        available = team.get_available_bowlers()
        if available:
            new_bowler = random.choice(available)
            team.current_bowler_idx = team.players.index(new_bowler)
            team.bowler_history.append(team.current_bowler_idx)
            match.waiting_for_bowler = False
            await request_bowler_number(context, chat_id, match)  # Resume next ball

async def resume_after_selection(context: ContextTypes.DEFAULT_TYPE, chat_id: int, match: Match):
    """Resume game after batsman selection (e.g., next ball)"""
    # Cancel timer
    if match.batsman_selection_task:
        match.batsman_selection_task.cancel()
    match.waiting_for_batsman = False
    
    # If mid-over, prompt bowler for next ball
    if match.current_bowling_team.current_bowler_idx is not None:
        await request_bowler_number(context, chat_id, match)
    else:
        # Edge: Start over or somethingรขโ โlog
        logger.warning("Resume called without bowler")

async def batting_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    รขลโฆ COMPLETE BATTING COMMAND - FIXED: Proper flow after selection
    """
    chat = update.effective_chat
    user = update.effective_user
    
    logger.info(f"รฐลธยย /batting command from {user.first_name} (ID: {user.id})")
    
    if chat.id not in active_matches:
        logger.warning(f"รขลกย รฏยธย No active match in chat {chat.id}")
        return
    
    match = active_matches[chat.id]
    
    if match.phase != GamePhase.MATCH_IN_PROGRESS:
        logger.warning(f"รขลกย รฏยธย Match not in progress, phase={match.phase}")
        await update.message.reply_text("รขลกย รฏยธย Match is not in progress!")
        return

    bat_team = match.current_batting_team
    
    # Only captain can select รขโ โ silently reject & delete non-captain messages
    if user.id != bat_team.captain_id:
        logger.warning(f"รฐลธโยฎรขโฌยรขโขโรฏยธย User {user.first_name} is not captain")
        try:
            await update.message.delete()
        except Exception:
            pass
        return

    if not context.args:
        await update.message.reply_text("รขโยนรฏยธย <b>Usage:</b> <code>/batting [serial_number]</code>", parse_mode=ParseMode.HTML)
        return
    
    try:
        serial = int(context.args[0])
        logger.info(f"รฐลธโยข Serial number: {serial}")
    except:
        await update.message.reply_text("รขยล Invalid number.")
        return

    player = bat_team.get_player_by_serial(serial)
    if not player:
        logger.warning(f"รฐลธลกยซ Player #{serial} not found")
        await update.message.reply_text(f"รฐลธลกยซ Player #{serial} not found.")
        return
    
    logger.info(f"รฐลธโยค Player selected: {player.first_name} (ID: {player.user_id})")
    
    if player.is_out:
        logger.warning(f"รฐลธโโฌ Player {player.first_name} is already OUT")
        await update.message.reply_text(f"รฐลธโโฌ {player.first_name} is already OUT!")
        return
    
    player_idx = serial - 1
    
    # Check duplicates
    if player_idx == bat_team.current_batsman_idx or player_idx == bat_team.current_non_striker_idx:
        logger.warning(f"รฐลธโบโ Player {player.first_name} already on crease")
        await update.message.reply_text(f"รฐลธโบโ {player.first_name} is already on the crease!")
        return

    # ========================================
    # รฐลธลฝยฏ CASE 1: SELECTING STRIKER (Opening)
    # ========================================
    if bat_team.current_batsman_idx is None and bat_team.current_non_striker_idx is None:
        logger.info("รฐลธลฝยฏ CASE 1: Selecting STRIKER (Opening)")
        bat_team.current_batsman_idx = player_idx
        
        await update.message.reply_text(
            f"รขลโฆ <b>Hey here is our Striker:</b> {player.first_name}", 
            parse_mode=ParseMode.HTML
        )
        logger.info(f"รขลโฆ Here is our Striker set: {player.first_name} (Index: {player_idx})")
        await asyncio.sleep(1)

        # Request Non-Striker
        captain_tag = get_user_tag(match.get_captain(bat_team))
        msg += f"รฐลธยงยข <b>{captain_tag}</b>, now select the <b>NON-STRIKER</b>:\n"
        msg += f"รฐลธโโฐ <b>Command:</b> <code>/batting [serial_number]</code>"
        
        await context.bot.send_message(chat.id, msg, parse_mode=ParseMode.HTML)
        logger.info("รขลโฆ Here our Non-striker request sent")
        return

    # ========================================
    # รฐลธลฝยฏ CASE 2: SELECTING NON-STRIKER (Opening)
    # ========================================
    elif bat_team.current_non_striker_idx is None:
        logger.info("รฐลธลฝยฏ CASE 2: Selecting NON-STRIKER (Opening)")
        bat_team.current_non_striker_idx = player_idx
        
        await update.message.reply_text(f"รฐลธฦย <b>Non-Striker Selected:</b> {player.first_name}", parse_mode=ParseMode.HTML)
        logger.info(f"รขลโฆ Non-striker set: {player.first_name} (Index: {player_idx})")
        await asyncio.sleep(1)
        
        # รขลโฆ Opening Pair Complete
        match.waiting_for_batsman = False
        if match.batsman_selection_task:
            match.batsman_selection_task.cancel()
            logger.info("รขลโฆ Batsman selection timer cancelled")
        
        striker = bat_team.players[bat_team.current_batsman_idx]
        non_striker = bat_team.players[bat_team.current_non_striker_idx]
        
        confirm_msg = f"รขลโฆ <b>Today's Match Opener </b>\n"
        confirm_msg += f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        confirm_msg += f"รฐลธยย <b>Striker:</b> {striker.first_name}\n"
        confirm_msg += f"รฐลธฦย <b>Non-Striker:</b> {non_striker.first_name}\n\n"
        
        # Send with photo
        try:
            await context.bot.send_photo(
                chat.id,
                photo=OPENING_PAIR_PHOTO,
                caption=confirm_msg,
                parse_mode=ParseMode.HTML
            )
        except Exception as e:
            logger.error(f"Error sending opening pair photo: {e}")
            # Fallback to text
            await context.bot.send_message(chat.id, confirm_msg, parse_mode=ParseMode.HTML)
        
        logger.info("รขลโฆ Opening pair confirmed")
        await asyncio.sleep(2)
        
        # รขลโฆ Request Bowler (Step 3) - THIS IS THE CRITICAL FIX
        match.waiting_for_bowler = True
        match.waiting_for_batsman = False  # Ensure this is false
        logger.info("รฐลธโยฃ Calling request_bowler_selection...")
        await request_bowler_selection(context, chat.id, match)
        logger.info("รขลโฆ Bowler selection initiated")
        return

    # ========================================
    # รฐลธลฝยฏ CASE 3: NEW BATSMAN (After Wicket)
    # ========================================
    else:
        logger.info("รฐลธลฝยฏ CASE 3: Selecting NEW BATSMAN after wicket")
        
        if not match.waiting_for_batsman:
            logger.warning("รขลกย รฏยธย Not waiting for batsman")
            await update.message.reply_text("รขลกย รฏยธย Batsmen are already set. Use /impact for substitution.")
            return

        # รขลโฆ SET NEW STRIKER (NON-STRIKER STAYS SAME)
        bat_team.current_batsman_idx = player_idx
        match.waiting_for_batsman = False
        
        if match.batsman_selection_task:
            match.batsman_selection_task.cancel()
            logger.info("รขลโฆ Batsman selection timer cancelled")
    
        player_tag = get_user_tag(player)
        await update.message.reply_text(
            f"รฐลธลกยถรขโฌยรขโขโรฏยธย <b>NEW BATSMAN:</b> {player_tag} walks in!", 
            parse_mode=ParseMode.HTML
        )
        logger.info(f"รขลโฆ New batsman set: {player.first_name} (Index: {player_idx})")
    
        await asyncio.sleep(2)
        
        # รขลโฆ CRITICAL: Check pending over complete status FIRST
        if hasattr(match, 'pending_over_complete') and match.pending_over_complete:
            logger.info("รฐลธยย Pending over complete detected, calling check_over_complete")
            match.pending_over_complete = False  # Reset flag
            await check_over_complete(context, chat.id, match)
            return
        
        # รขลโฆ If no pending over complete, resume normal play
        bowl_team = match.current_bowling_team
        
        # รขลโฆ If bowler exists, resume
        if bowl_team.current_bowler_idx is not None:
            logger.info("รขโยถรฏยธย Bowler exists, resuming ball execution")
            await context.bot.send_message(chat.id, "รขโยถรฏยธย <b>Game Resumed!</b>", parse_mode=ParseMode.HTML)
            await asyncio.sleep(1)
            await execute_ball(context, chat.id, match)
            
        # รขลโฆ Edge case: No bowler (shouldn't happen in normal flow)
        else:
            logger.warning("รขลกย รฏยธย No bowler found, requesting bowler selection")
            match.waiting_for_bowler = True
            await request_bowler_selection(context, chat.id, match)        
        return

async def players_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """รฐลธยย Show playing squads with player tags and live real-time status"""
    group_id = update.effective_chat.id
    match = active_matches.get(group_id)
    
    if not match:
        await update.message.reply_text("รฐลธยย No active match! Start with /game")
        return

    if getattr(match, 'game_mode', None) in ["SOLO", "MAGICBALL"] or match.phase in [GamePhase.SOLO_JOINING, GamePhase.SOLO_MATCH]:
        # Solo mode รขโ โ show player roster
        msg = "รฐลธโล <b>SOLO BATTLE ROSTER</b>\n"
        msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        for i, p in enumerate(match.solo_players, 1):
            status = "รขยยณ <i>Waiting</i>"
            if p.is_out: status = "รขยล <b>OUT</b>"
            elif match.phase == GamePhase.SOLO_MATCH:
                if i-1 == match.current_solo_bat_idx: status = "รฐลธยย <b>BATTING</b>"
                elif i-1 == match.current_solo_bowl_idx: status = "รขลกยพ <b>BOWLING</b>"
                elif p.is_bowling_banned: status = "รฐลธลกยซ <b>BANNED (Bowl)</b>"
            msg += f"<b>{i}. {p.first_name}</b>\n   รขโโ {status} รขโฌยข {p.runs} Runs\n"
        msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ"
        await update.message.reply_text(msg, parse_mode=ParseMode.HTML)
        return
    
    # รขโโฌรขโโฌรขโโฌ Determine toss winner รขโโฌรขโโฌรขโโฌ
    toss_winner_team = getattr(match, 'toss_winner', None)
    
    NUM_EMOJI = ["1รฏยธยรขฦยฃ","2รฏยธยรขฦยฃ","3รฏยธยรขฦยฃ","4รฏยธยรขฦยฃ","5รฏยธยรขฦยฃ","6รฏยธยรขฦยฃ","7รฏยธยรขฦยฃ","8รฏยธยรขฦยฃ","9รฏยธยรขฦยฃ","รฐลธโลธ",
                 "1รฏยธยรขฦยฃ1รฏยธยรขฦยฃ","1รฏยธยรขฦยฃ2รฏยธยรขฦยฃ","1รฏยธยรขฦยฃ3รฏยธยรขฦยฃ","1รฏยธยรขฦยฃ4รฏยธยรขฦยฃ","1รฏยธยรขฦยฃ5รฏยธยรขฦยฃ"]

    def _get_player_status_icons(player, team):
        """Return status icons for a player (emoji only, no text labels)"""
        if player.is_out:
            return "รขยล"
        icons = []
        # Captain
        if player.user_id == team.captain_id:
            icons.append("รฐลธโโ")
        # Batting / Non-Striker
        if match.current_batting_team == team:
            bat_idx = team.current_batsman_idx
            ns_idx = team.current_non_striker_idx
            if bat_idx is not None and bat_idx < len(team.players) and team.players[bat_idx].user_id == player.user_id:
                icons.append("รฐลธยย")
            elif ns_idx is not None and ns_idx < len(team.players) and team.players[ns_idx].user_id == player.user_id:
                icons.append("รฐลธยฦรขโฌยรขโขโรฏยธย")
        # Bowling
        if match.current_bowling_team == team:
            bowl_idx = team.current_bowler_idx
            if bowl_idx is not None and bowl_idx < len(team.players) and team.players[bowl_idx].user_id == player.user_id:
                icons.append("รขโฌยผรฏยธย")
        return " ".join(icons) if icons else ""

    def _build_player_row(player, team, num):
        """Build a player row in new UI format"""
        tag = f'<a href="tg://user?id={player.user_id}">{html.escape(player.first_name)}</a>'
        status = _get_player_status_icons(player, team)
        num_icon = NUM_EMOJI[num-1] if num <= len(NUM_EMOJI) else f"{num}."
        row = f"รขโล {num_icon} {tag}"
        if status:
            row += f" {status}"
        row += "\n"
        return row

    def _build_team_block(team, color, num_players):
        toss_icon = " รฐลธยชโข" if toss_winner_team == team else ""
        batting_icon = ""
        if match.current_batting_team == team:
            batting_icon = " รฐลธยย"
        elif match.current_bowling_team == team:
            batting_icon = " รฐลธโยฅ"

        score_str = ""
        if match.phase == GamePhase.MATCH_IN_PROGRESS or match.innings >= 1:
            score_str = f" รขลพโ {team.score}/{team.wickets} ({format_overs(team.balls)} ov)"

        color_icon = "รฐลธยงล " if team == match.team_x else "รฐลธโยฅ"
        block = f"{color_icon} <b>รฐยโยงรฐยโหรฐยโโรฐยโย  {html.escape(team.name)}</b>{toss_icon}{score_str}\n"
        block += "รขโลรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        for i, player in enumerate(team.players, 1):
            block += _build_player_row(player, team, i)
        block += "รขโโรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        return block

    # Header
    host_tag = f'<a href="tg://user?id={match.host_id}">{html.escape(match.host_name or "Host")}</a>'
    overs_info = getattr(match, 'total_overs', 0)
    text = f"รฐลธโโ รฐยโโบรฐยโยผรฐยหโฌรฐยหย: {host_tag}\n"
    text += f"รขยยณ รฐยโยขรฐยหฦรฐยโยฒรฐยโยฟรฐยหโฌ: {overs_info}\n"
    text += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"

    x_players = len(match.team_x.players)
    y_players = len(match.team_y.players)

    text += _build_team_block(match.team_x, "รขยโรฏยธย", x_players)
    text += _build_team_block(match.team_y, "รฐลธโยฅ", y_players)
    
    
    # 30-second cooldown for players command during active match
    if match.phase == GamePhase.MATCH_IN_PROGRESS:
        remaining = check_players_cooldown(group_id)
        if remaining is not None:
            secs = math.ceil(remaining)
            cool_msg = await update.message.reply_text(
                f"รขยยณ <b>Players command cooldown:</b> Wait <b>{secs}s</b> more!",
                parse_mode=ParseMode.HTML
            )
            asyncio.get_event_loop().call_later(
                remaining + 1,
                lambda: asyncio.ensure_future(cool_msg.delete())
            )
            return
        set_players_cooldown(group_id)

    try:
        avatar_ids = [
            getattr(match, "host_id", None),
            getattr(match.team_x.get_player(match.team_x.captain_id), "user_id", None),
            getattr(match.team_y.get_player(match.team_y.captain_id), "user_id", None),
        ]
        avatar_bytes_map = {}
        for uid in [uid for uid in avatar_ids if uid]:
            avatar_bytes_map[uid] = await fetch_user_avatar_bytes(context, uid)
        players_img = await asyncio.to_thread(generate_players_squad_image, match, avatar_bytes_map)
        if players_img:
            sent = await update.message.reply_photo(
                photo=players_img, caption=text, parse_mode=ParseMode.HTML
            )
        else:
            sent = await update.message.reply_text(text, parse_mode=ParseMode.HTML)
    except Exception:
        try:
            sent = await update.message.reply_text(text, parse_mode=ParseMode.HTML)
        except Exception:
            await update.message.reply_text("รฐลธยย Players list unavailable right now.")
            return
    # Pin the players message
    try:
        await context.bot.pin_chat_message(
            chat_id=group_id,
            message_id=sent.message_id,
            disable_notification=True
        )
    except Exception:
        pass



async def batsman_selection_timeout(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """Handle batsman selection timeout"""
    try:
        await asyncio.sleep(120)  # 2 minutes - send reminder
        
        if not match.waiting_for_batsman:
            return
        
        # 2-minute reminder
        reminder_msg = (
            f"รขลกย รฏยธย {match.current_batting_team.name} รขโ โ pick your next batter!\n"
            f"รขลยจรฏยธย <code>/batting [number]</code>  รยท  รขยยณ <b>2 min</b> left!"
        )
        await context.bot.send_message(
            chat_id=group_id,
            text=reminder_msg,
            parse_mode=ParseMode.HTML
        )
        
        await asyncio.sleep(120)  # Another 2 minutes (total 4 min)
        
        if not match.waiting_for_batsman:
            return
        
        # Timeout occurred - penalty
        penalty = 6
        match.current_batting_team.score -= penalty
        match.current_batting_team.score = max(0, match.current_batting_team.score)
        match.current_batting_team.penalty_runs += penalty
        
        penalty_msg = (
            f"รฐลธโยธ <b>{match.current_batting_team.name}</b> penalized <b>-{penalty} runs</b> for delay!\n"
            f"รฐลธโล  Score: <b>{match.current_batting_team.score}/{match.current_batting_team.wickets}</b>\n"
            f"รขลยจรฏยธย Select NOW: <code>/batting [number]</code>"
        )
        
        await context.bot.send_message(
            chat_id=group_id,
            text=penalty_msg,
            parse_mode=ParseMode.HTML
        )
        
        # Reset timer
        match.batsman_selection_time = time.time()
        match.batsman_selection_task = asyncio.create_task(
            batsman_selection_timeout(context, group_id, match)
        )
    
    except asyncio.CancelledError:
        pass

async def request_bowler_selection(context: ContextTypes.DEFAULT_TYPE, chat_id: int, match: Match):
    """Prompt captain for bowler - GUARANTEED DELIVERY WITH FULL LOGGING"""
    
    logger.info(f"รฐลธลฝยฌ === BOWLER SELECTION START === Chat: {chat_id}")
    
    # Validate bowling team exists
    if not match.current_bowling_team:
        logger.error("รขยล CRITICAL: No bowling team set!")
        await context.bot.send_message(chat_id, "รขลกย รฏยธย Error: No bowling team found!", parse_mode=ParseMode.HTML)
        return
    
    logger.info(f"รขลโฆ Bowling team: {match.current_bowling_team.name}")

    # รขโโฌรขโโฌ Check bowling queue first รขโโฌรขโโฌ
    bowl_team = match.current_bowling_team
    queued_idx = _pop_next_bowler(chat_id, bowl_team)
    if queued_idx is not None:
        bowl_team.current_bowler_idx = queued_idx
        match.waiting_for_bowler = False
        match.current_ball_data = {}
        queued_bowler = bowl_team.players[queued_idx]
        bowler_tag = get_user_tag(queued_bowler)
        await context.bot.send_message(
            chat_id,
            f"รขลกยพ <b>NEXT BOWLER (from queue):</b> {bowler_tag} takes the ball!",
            parse_mode=ParseMode.HTML
        )
        logger.info(f"รขลโฆ Auto-selected queued bowler: {queued_bowler.first_name}")
        await asyncio.sleep(1)
        await execute_ball(context, chat_id, match)
        return
    
    # Get captain
    captain = match.get_captain(match.current_bowling_team)
    if not captain:
        logger.error("รขยล CRITICAL: No bowling captain found!")
        await context.bot.send_message(
            chat_id, 
            "รขลกย รฏยธย <b>Error:</b> No bowling captain found! Use /changecap to set one.", 
            parse_mode=ParseMode.HTML
        )
        return

    captain_tag = get_user_tag(captain)
    logger.info(f"รฐลธโโ Captain: {captain.first_name} (ID: {captain.user_id})")
    
    # Get available bowlers
    available = match.current_bowling_team.get_available_bowlers()
    logger.info(f"รฐลธโล  Available bowlers: {len(available)}")
    
    if len(available) == 0:
        logger.error("รขยล CRITICAL: No available bowlers!")
        await context.bot.send_message(
            chat_id,
            "รขลกย รฏยธย <b>Error:</b> No bowlers available! All players may be banned from bowling.",
            parse_mode=ParseMode.HTML
        )
        return
    
    # Log available bowlers
    for i, p in enumerate(available):
        logger.info(f"  Bowler #{i+1}: {p.first_name} (ID: {p.user_id})")
    
    # Build message รขโ โ properly initialized
    over_num = len(match.team_x_over_runs if match.current_batting_team == match.team_x else match.team_y_over_runs) + 1
    bowler_lines = [
        f"รฐลธยฅลฝ {captain_tag} รขลพโ Send in your strike bowler!",
        f"รขลกโข Use: <code>/bowling [number]</code>",
        f"Use <code>/qbowling</code> to pre-queue a bowler.",
    ]
    msg = themed("SELECT BOWLER", bowler_lines, "รฐลธยฅลฝ")
    
    # Group URL for "Go to Group" button
    try:
        _cid_str = str(abs(chat_id))
        _tme_gid = _cid_str[3:] if _cid_str.startswith("100") else _cid_str
        _group_url = f"https://t.me/c/{_tme_gid}/1"
    except Exception:
        _group_url = f"https://t.me/{context.bot.username}"
    
    bowler_select_markup = InlineKeyboardMarkup([[
        InlineKeyboardButton("รฐลธยลธรฏยธย Go to Group", url=_group_url)
    ]])
    
    # Send message to group
    try:
        sent_msg = await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML, reply_markup=bowler_select_markup)
        logger.info(f"รขลโฆ Group message sent successfully (msg_id: {sent_msg.message_id})")
    except Exception as e:
        logger.error(f"รขยล Failed to send group message: {e}")
        return
    
    # SET WAITING STATE BEFORE ANYTHING ELSE
    match.waiting_for_bowler = True
    match.waiting_for_batsman = False
    match.current_ball_data = {}
    logger.info(f"รขลโฆ State set: waiting_for_bowler=True, waiting_for_batsman=False")
    
    # Start timeout timer
    match.bowler_selection_time = time.time()
    match.bowler_selection_task = asyncio.create_task(
        bowler_selection_timeout(context, chat_id, match)
    )
    logger.info(f"รขลโฆ Timeout timer started (120 seconds)")
    
    logger.info(f"รฐลธลฝยฌ === BOWLER SELECTION END ===")

async def bowler_selection_timeout(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """Handle bowler selection timeout"""
    try:
        await asyncio.sleep(120)  # 2 minutes - send reminder
        
        if not match.waiting_for_bowler:
            return
        
        # 2-minute reminder
        captain = match.get_captain(match.current_bowling_team)
        captain_tag = get_user_tag(captain) if captain else match.current_bowling_team.name
        reminder_msg = (
            f"รขลกยพ {captain_tag} รขโ โ pick your bowler now!\n"
            f"รขลยจรฏยธย <code>/bowling [number]</code>  รยท  รขยยณ <b>2 min</b> left!"
        )
        await context.bot.send_message(
            chat_id=group_id,
            text=reminder_msg,
            parse_mode=ParseMode.HTML
        )
        
        await asyncio.sleep(120)  # Another 2 minutes (total 4 min)
        
        if not match.waiting_for_bowler:
            return
        
        # Get current bowler if any
        if match.current_bowling_team.current_bowler_idx is not None:
            bowler = match.current_bowling_team.players[match.current_bowling_team.current_bowler_idx]
            bowler.bowling_timeouts += 1
            
            timeout_count = bowler.bowling_timeouts
            
            if timeout_count >= PLAYER_TIMEOUT_LIMIT:
                # Ban from bowling
                
                penalty_msg = (
                    f"รฐลธลกยจ <b>BOWLER BANNED รขโ โ TIMEOUT!</b>\n"
                    f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
                    f"รขโบโ <b>{bowler.first_name}</b> timed out {PLAYER_TIMEOUT_LIMIT}รโ. They can bowl again later.\n"
                    f"รฐลธโล NO BALL  รยท  รขลพโข +1 Run  รยท  รขลกยก FREE HIT next!\n"
                    f"รขลยจรฏยธย Select another: <code>/bowling [number]</code>"
                )
                
                # Add no ball
                match.current_batting_team.score += 1
                match.current_batting_team.extras += 1
                match.is_free_hit = True
                
                await context.bot.send_message(
                    chat_id=group_id,
                    text=penalty_msg,
                    parse_mode=ParseMode.HTML
                )
            else:
                penalty_msg = (
                    f"รขยยฑรฏยธย <b>BOWLER TIMEOUT!</b>  <code>{timeout_count}/{PLAYER_TIMEOUT_LIMIT}</code>\n"
                    f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
                    f"รขลกย รฏยธย <b>{bowler.first_name}</b> didn't bowl in time!\n"
                    f"รฐลธโล NO BALL  รยท  รขลพโข +1 Run  รยท  รขลกยก FREE HIT!\n"
                    f"รขลยจรฏยธย <code>/bowling [number]</code> รขโ โ select bowler!"
                )
                
                # Add no ball
                match.current_batting_team.score += 1
                match.current_batting_team.extras += 1
                match.is_free_hit = True
                
                await context.bot.send_message(
                    chat_id=group_id,
                    text=penalty_msg,
                    parse_mode=ParseMode.HTML
                )
        else:
            # First ball, no specific bowler to penalize
            penalty_msg = (
                f"รขลกย รฏยธย <b>{match.current_bowling_team.name}</b> delayed bowler selection!\n"
                f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
                f"รฐลธโยธ -6 Run Penalty applied.\n"
                f"รขลยจรฏยธย <code>/bowling [number]</code> รขโ โ select NOW!"
            )
            
            await context.bot.send_message(
                chat_id=group_id,
                text=penalty_msg,
                parse_mode=ParseMode.HTML
            )
        
        # Reset timer
        match.bowler_selection_time = time.time()
        match.bowler_selection_task = asyncio.create_task(
            bowler_selection_timeout(context, group_id, match)
        )
    
    except asyncio.CancelledError:
        pass

async def bowling_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle Bowling Selection - FIXED VERSION"""
    chat = update.effective_chat
    user = update.effective_user
    
    logger.info(f"รขลกยพ === BOWLING COMMAND START === From: {user.first_name} (ID: {user.id})")
    
    if chat.id not in active_matches: 
        logger.warning(f"รขยล No active match in chat {chat.id}")
        await update.message.reply_text("รขยล No active match")
        return
    
    match = active_matches[chat.id]
    logger.info(f"รขลโฆ Match found - Phase: {match.phase}")
    
    # Check if we are waiting for bowler
    if not match.waiting_for_bowler:
        logger.warning(f"รขลกย รฏยธย Not waiting for bowler (waiting_for_bowler=False)")
        await update.message.reply_text("รขลกย รฏยธย Not waiting for bowler selection right now.")
        return
    
    logger.info(f"รขลโฆ Waiting for bowler confirmed")
    
    bowling_captain = match.get_captain(match.current_bowling_team)
    if not bowling_captain:
        logger.error(f"รขยล No bowling captain found!")
        await update.message.reply_text("รขลกย รฏยธย No bowling captain found!")
        return
    
    logger.info(f"รฐลธโโ Bowling captain: {bowling_captain.first_name} (ID: {bowling_captain.user_id})")
        
    if user.id != bowling_captain.user_id:
        logger.warning(f"รฐลธลกยซ User {user.first_name} is not the bowling captain")
        try:
            await update.message.delete()
        except Exception:
            pass
        return
    
    logger.info(f"รขลโฆ Captain verification passed")
    
    if not context.args:
        logger.warning(f"รขลกย รฏยธย No serial number provided")
        await update.message.reply_text("รขลกย รฏยธย Usage: <code>/bowling [serial]</code>", parse_mode=ParseMode.HTML)
        return
    
    try:
        serial = int(context.args[0])
        logger.info(f"รฐลธโยข Serial number: {serial}")
    except: 
        logger.error(f"รขยล Invalid serial number: {context.args[0]}")
        await update.message.reply_text("รขยล Invalid number.")
        return
    
    bowler = match.current_bowling_team.get_player_by_serial(serial)
    if not bowler:
        logger.error(f"รขยล Player #{serial} not found in bowling team")
        await update.message.reply_text(f"รขยล Player #{serial} not found.")
        return
    
    logger.info(f"รฐลธโยค Bowler selected: {bowler.first_name} (ID: {bowler.user_id})")
        
    if bowler.is_bowling_banned:
        logger.warning(f"รฐลธลกยซ {bowler.first_name} is banned from bowling")
        await update.message.reply_text("รฐลธลกยซ Player is BANNED from bowling.")
        return
    
    logger.info(f"รขลโฆ Bowler validation passed")
    
    # รขลโฆ NO CONSECUTIVE OVERS CHECK
    bowler_idx = serial - 1
    if match.current_bowling_team.bowler_history:
        if bowler_idx == match.current_bowling_team.bowler_history[-1]:
            logger.warning(f"รฐลธลกยซ Consecutive over attempt by {bowler.first_name}")
            await update.message.reply_text("รฐลธลกยซ <b>Rule:</b> Bowler cannot bowl 2 consecutive overs!", parse_mode=ParseMode.HTML)
            return
    
    logger.info(f"รขลโฆ Consecutive over check passed")

    # รขลโฆ SET BOWLER
    match.current_bowling_team.current_bowler_idx = bowler_idx
    match.waiting_for_bowler = False
    match.waiting_for_batsman = False 
    
    logger.info(f"รขลโฆ Bowler set: Index={bowler_idx}, waiting_for_bowler=False")
    
    if match.bowler_selection_task: 
        match.bowler_selection_task.cancel()
        logger.info(f"รขลโฆ Bowler selection timer cancelled")
    
    # Confirmation
    try: 
        bowler_tag = get_user_tag(bowler)
    except: 
        bowler_tag = bowler.first_name
    
    conf_lines = [
        f"รฐลธยฅลฝ {bowler_tag} has the ball!",
        f"รฐลธโล  Over: {format_overs(bowler.balls_bowled)} | รฐลธลธยข {bowler.wickets}W / {bowler.runs_conceded}R",
    ]
    confirm_msg = themed("รฐลธโโ BOWLER LOCKED", conf_lines, "รฐลธยฅลฝ")
    
    # Add Go to Group button for non-AI modes
    try:
        _cid_str = str(abs(chat.id))
        _tme_gid = _cid_str[3:] if _cid_str.startswith("100") else _cid_str
        _group_url = f"https://t.me/c/{_tme_gid}/1"
        _confirm_markup = InlineKeyboardMarkup([[InlineKeyboardButton("รฐลธยลธรฏยธย Go to Group", url=_group_url)]])
    except Exception:
        _confirm_markup = None
    
    await update.message.reply_text(confirm_msg, parse_mode=ParseMode.HTML, reply_markup=_confirm_markup)
    logger.info(f"รขลโฆ Confirmation message sent")
    
    await asyncio.sleep(2)
    
    # รขลโฆ RESUME GAME (Trigger first ball of over) - THIS IS THE CRITICAL FIX
    logger.info(f"รฐลธลฝยฎ Calling execute_ball to start bowling...")
    await execute_ball(context, chat.id, match)
    logger.info(f"รขลกยพ === BOWLING COMMAND END ===")


