# รฐลธยยณรฏยธย DECLARE COMMAND  (batting captain only)
# รขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขย
async def declare_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Batting captain can declare the innings early. Host accepts / denies."""
    chat = update.effective_chat
    user = update.effective_user

    if chat.id not in active_matches:
        await update.message.reply_text(
            themed("รขลกย รฏยธย NO MATCH", ["No active match found. Use /game to start."], "รขยล"),
            parse_mode=ParseMode.HTML
        )
        return

    match = active_matches[chat.id]

    if match.phase != GamePhase.MATCH_IN_PROGRESS:
        await update.message.reply_text(
            themed("รขลกย รฏยธย NOT IN PROGRESS", ["Match is not currently in progress."], "รขยล"),
            parse_mode=ParseMode.HTML
        )
        return

    if match.declare_pending:
        await update.message.reply_text(
            themed("รขยยณ DECLARE PENDING", ["A declare request is already pending. Wait for the host to respond."], "รขยยณ"),
            parse_mode=ParseMode.HTML
        )
        return

    bat_team = match.current_batting_team
    bat_captain = match.get_captain(bat_team)

    if not bat_captain or bat_captain.user_id != user.id:
        await update.message.reply_text(
            themed("รฐลธลกยซ CAPTAIN ONLY", ["Only the <b>batting captain</b> can declare the innings!", ""], "รฐลธลกยซ"),
            parse_mode=ParseMode.HTML
        )
        return

    # Can only declare in 1st innings
    if match.innings != 1:
        await update.message.reply_text(
            themed("รขลกย รฏยธย DECLARE UNAVAILABLE", ["Declare is only allowed during the 1st innings."], "รขลกย รฏยธย"),
            parse_mode=ParseMode.HTML
        )
        return

    match.declare_pending = True
    cap_tag = get_user_tag(bat_captain)
    crr = round(bat_team.score / max(bat_team.balls / 6, 0.1), 2)

    declare_lines = [
        f"รฐลธยยณรฏยธย {cap_tag} wants to <b>DECLARE</b> the innings!",
        f"รฐลธยย <b>{bat_team.name}:</b> {bat_team.score}/{bat_team.wickets} ({format_overs(bat_team.balls)} ov) | RR: {crr}",
        f"รฐลธลฝยฏ Host รขโฌโ do you accept the declaration?",
        f"รขยยณ Decide within 60 seconds or it is auto-denied.",
    ]
    msg_text = themed("รฐลธยยณรฏยธย INNINGS DECLARATION", declare_lines, "รฐลธยยณรฏยธย")

    keyboard = InlineKeyboardMarkup([[
        InlineKeyboardButton("รขลโฆ Accept Declaration", callback_data=f"declare_accept_{chat.id}"),
        InlineKeyboardButton("รขยล Deny", callback_data=f"declare_deny_{chat.id}"),
    ]])

    sent = await context.bot.send_message(chat.id, msg_text, parse_mode=ParseMode.HTML, reply_markup=keyboard)
    match.declare_message_id = sent.message_id

    # Auto-deny after 60s
    async def _auto_deny():
        await asyncio.sleep(60)
        if match.declare_pending:
            match.declare_pending = False
            try:
                await context.bot.edit_message_text(
                    chat_id=chat.id,
                    message_id=match.declare_message_id,
                    text=themed("รฐลธยยณรฏยธย DECLARATION AUTO-DENIED", ["No response from host รขโฌโ game continues normally."], "รขยล"),
                    parse_mode=ParseMode.HTML,
                )
            except Exception:
                pass

    asyncio.create_task(_auto_deny())


async def declare_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle host accept/deny of a declaration."""
    query = update.callback_query
    await query.answer()

    data = query.data
    user = query.from_user

    try:
        parts = data.split("_")
        action = parts[1]  # accept or deny
        group_id = int(parts[2])
    except Exception:
        return

    if group_id not in active_matches:
        await query.answer("No active match!", show_alert=True)
        return

    match = active_matches[group_id]

    if user.id != match.host_id:
        await query.answer("รขลกย รฏยธย Only the Host can accept or deny a declaration!", show_alert=True)
        return

    if not match.declare_pending:
        await query.answer("Declaration is no longer pending.", show_alert=True)
        return

    match.declare_pending = False

    if action == "accept":
        try:
            await query.edit_message_text(
                themed("รขลโฆ DECLARATION ACCEPTED", [
                    "The batting team has declared their innings!",
                    "Innings ending now... รฐลธยยณรฏยธย",
                ], "รขลโฆ"),
                parse_mode=ParseMode.HTML,
            )
        except Exception:
            pass
        await asyncio.sleep(1)
        await end_innings(context, group_id, match)
    else:
        try:
            await query.edit_message_text(
                themed("รขยล DECLARATION DENIED", [
                    "Host denied the declaration. Game continues as normal. รฐลธยย",
                ], "รขยล"),
                parse_mode=ParseMode.HTML,
            )
        except Exception:
            pass


