# รขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขย
async def retirehurt_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Active striker can request to retire hurt. Captain accepts / denies."""
    chat = update.effective_chat
    user = update.effective_user

    if chat.id not in active_matches:
        await update.message.reply_text(
            themed("รขลกย รฏยธย NO MATCH", ["No active match found."], "รขยล"),
            parse_mode=ParseMode.HTML
        )
        return

    match = active_matches[chat.id]

    if match.phase != GamePhase.MATCH_IN_PROGRESS:
        await update.message.reply_text(
            themed("รขลกย รฏยธย NOT IN PROGRESS", ["Match is not currently in progress."], "รขยล"),
            parse_mode=ParseMode.HTML
        )
        return

    if match.retire_hurt_pending:
        await update.message.reply_text(
            themed("รขยยณ REQUEST PENDING", ["A retire-hurt request is already pending."], "รขยยณ"),
            parse_mode=ParseMode.HTML
        )
        return

    bat_team = match.current_batting_team
    # Only the current striker can request retire hurt
    if bat_team.current_batsman_idx is None:
        await update.message.reply_text("รขลกย รฏยธย No active batsman found.", parse_mode=ParseMode.HTML)
        return

    striker = bat_team.players[bat_team.current_batsman_idx]
    if striker.user_id != user.id:
        await update.message.reply_text(
            themed("รฐลธลกยซ STRIKER ONLY", ["Only the <b>current striker</b> can request to retire hurt."], "รฐลธลกยซ"),
            parse_mode=ParseMode.HTML
        )
        return

    match.retire_hurt_pending = True
    match.retire_hurt_batsman_id = user.id

    cap = match.get_captain(bat_team)
    cap_tag = get_user_tag(cap) if cap else bat_team.name
    player_tag = get_user_tag(striker)

    rh_lines = [
        f"รฐลธยคโข {player_tag} wants to <b>RETIRE HURT</b>!",
        f"รฐลธโล  Scores: {striker.runs} ({striker.balls_faced})",
        f"รฐลธยงยข Captain {cap_tag} รขโฌโ do you accept?",
        f"รขยยณ Respond within 60 seconds or it is auto-denied.",
    ]
    msg_text = themed("รฐลธยคโข RETIRE HURT REQUEST", rh_lines, "รฐลธยคโข")

    keyboard = InlineKeyboardMarkup([[
        InlineKeyboardButton("รขลโฆ Accept", callback_data=f"retirehurt_accept_{chat.id}"),
        InlineKeyboardButton("รขยล Deny", callback_data=f"retirehurt_deny_{chat.id}"),
    ]])

    sent = await context.bot.send_message(chat.id, msg_text, parse_mode=ParseMode.HTML, reply_markup=keyboard)
    match.retire_hurt_message_id = sent.message_id

    # Auto-deny after 60s
    async def _auto_deny_rh():
        await asyncio.sleep(60)
        if match.retire_hurt_pending:
            match.retire_hurt_pending = False
            match.retire_hurt_batsman_id = None
            try:
                await context.bot.edit_message_text(
                    chat_id=chat.id,
                    message_id=match.retire_hurt_message_id,
                    text=themed("รฐลธยคโข RETIRE HURT AUTO-DENIED", ["No response from captain รขโฌโ game continues normally."], "รขยล"),
                    parse_mode=ParseMode.HTML,
                )
            except Exception:
                pass

    asyncio.create_task(_auto_deny_rh())


async def retirehurt_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle captain accept/deny of retire hurt."""
    query = update.callback_query
    await query.answer()

    data = query.data
    user = query.from_user

    try:
        parts = data.split("_")
        action = parts[1]  # accept or deny
        group_id = int(parts[2])
    except Exception:
        return

    if group_id not in active_matches:
        await query.answer("No active match!", show_alert=True)
        return

    match = active_matches[group_id]
    bat_team = match.current_batting_team

    # Only batting captain can accept/deny
    cap = match.get_captain(bat_team)
    if not cap or cap.user_id != user.id:
        await query.answer("รขลกย รฏยธย Only the batting captain can respond!", show_alert=True)
        return

    if not match.retire_hurt_pending:
        await query.answer("Request is no longer pending.", show_alert=True)
        return

    match.retire_hurt_pending = False
    batsman_id = match.retire_hurt_batsman_id
    match.retire_hurt_batsman_id = None

    if action == "accept":
        # Mark batsman as retired hurt รขโฌโ NOT a wicket, just removes from crease
        if bat_team.current_batsman_idx is not None:
            retired = bat_team.players[bat_team.current_batsman_idx]
            retired.is_out = True
            retired.dismissal_type = "Retired Hurt"
            bat_team.out_players_indices.add(bat_team.current_batsman_idx)
            # รขยล Do NOT increment bat_team.wickets รขโฌโ retire hurt is NOT a dismissal

        try:
            await query.edit_message_text(
                themed("รขลโฆ RETIRE HURT ACCEPTED", [
                    f"รฐลธยคโข Batsman has retired hurt.",
                    f"รฐลธยย Captain รขโฌโ send in the next batsman.",
                    f"รขลกโข Use: <code>/batting [number]</code>",
                ], "รขลโฆ"),
                parse_mode=ParseMode.HTML,
            )
        except Exception:
            pass

        # Request next batsman
        match.waiting_for_batsman = True
        match.current_ball_data = {}
        await request_batsman_selection(context, group_id, match)

    else:
        try:
            await query.edit_message_text(
                themed("รขยล RETIRE HURT DENIED", [
                    "Captain denied the request. Batsman continues at the crease. รฐลธยย",
                ], "รขยล"),
                parse_mode=ParseMode.HTML,
            )
        except Exception:
            pass


# รขลโฆ FIX 3: Enhanced execute_ball with logging
async def execute_ball(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """
    Premium TV Broadcast Style - WITH CORRECT CHASE INFO
    """
    
    logger.info(f"รฐลธลฝยฎ === EXECUTE_BALL START === Group: {group_id}")
    
    bat_team = match.current_batting_team
    bowl_team = match.current_bowling_team
    
    # รขลโฆ SAFETY CHECK: Verify indices exist
    if bat_team.current_batsman_idx is None:
        logger.error("รขยล CRITICAL: No striker selected!")
        await context.bot.send_message(group_id, "รขลกย รฏยธย Error: No striker found!")
        return
    
    if bat_team.current_non_striker_idx is None:
        logger.error("รขยล CRITICAL: No non-striker selected!")
        await context.bot.send_message(group_id, "รขลกย รฏยธย Error: No non-striker found!")
        return
    
    if bowl_team.current_bowler_idx is None:
        logger.error("รขยล CRITICAL: No bowler selected!")
        await context.bot.send_message(group_id, "รขลกย รฏยธย Error: No bowler found!")
        return
    
    striker = bat_team.players[bat_team.current_batsman_idx]
    non_striker = bat_team.players[bat_team.current_non_striker_idx]
    bowler = bowl_team.players[bowl_team.current_bowler_idx]
    
    logger.info(f"รขลโฆ Players verified:")
    logger.info(f"  รฐลธยย Striker: {striker.first_name} (Index: {bat_team.current_batsman_idx})")
    logger.info(f"  รฐลธยฦ Non-Striker: {non_striker.first_name} (Index: {bat_team.current_non_striker_idx})")
    logger.info(f"  รขลกยพ Bowler: {bowler.first_name} (Index: {bowl_team.current_bowler_idx})")
    
    # Clickable Names
    striker_tag = f'<a href=\"tg://user?id={striker.user_id}\">{striker.first_name}</a>'
    bowler_tag = f'<a href=\"tg://user?id={bowler.user_id}\">{bowler.first_name}</a>'

    # --- รฐลธยงยฎ CALCULATE STATS ---
    total_overs_bowled = bat_team.balls / 6 if bat_team.balls > 0 else 0.1
    crr = round(bat_team.score / total_overs_bowled, 2)
    
    # รขลโฆ FIXED: Match Equation (For 2nd Innings) - use bat_team balls for consistency
    equation = ""
    if match.innings == 2:
        runs_needed = match.target - bat_team.score
        balls_left = (match.total_overs * 6) - bat_team.balls  # รขลโฆ USE BATTING TEAM'S BALLS
        rrr = round((runs_needed / balls_left) * 6, 2) if balls_left > 0 else 0
        equation = f"\nรฐลธลฝยฏ Need <b>{runs_needed}</b> off <b>{balls_left}</b> balls (RRR {rrr})"

    # --- รฐลธยลธรฏยธย GROUP DISPLAY ---
    overs_str = format_overs(bat_team.balls)
    crr_str = f"{crr:.2f}"

    text = (
        f"รขโขยญรขโยรขโย รฐลธโยด LIVE รขโยรขโยรขโยรขโยรขโยรขโย\n"
        f"รขโฦ รฐลธโยน Over: {overs_str}  |  รฐลธโยน RR: {crr_str}\n"
        f"รขโฦ รฐลธยฅลฝ {bowler_tag} is charging in to bowl...\n"
        f"รขโขยฐรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโย"
    )
    if equation:
        text += f"\n{equation.strip()}"
    if match.is_free_hit:
        text += "\nรขลกยก <b>FREE HIT!</b> รขโ โ Batsman cannot be dismissed!"
    
    # Button รขโ โ "Deliver Bowl" deep-links bowler straight into their DM with the bot
    bot_username = context.bot.username
    # deep link: t.me/botname?start=bowl_{group_id} รขโ โ opens DM directly
    dm_deep_url = f"https://t.me/{bot_username}"
    keyboard = [[InlineKeyboardButton("รขลกยพ Deliver Bowl", url=dm_deep_url)]]
    reply_markup = InlineKeyboardMarkup(keyboard)
    
    # GIF
    ball_gif = "https://t.me/kyanaamrkhe/6"
    
    try:
        await context.bot.send_animation(
            group_id, 
            animation=ball_gif,
            caption=text,
            reply_markup=reply_markup,
            parse_mode=ParseMode.HTML
        )
        logger.info("รขลโฆ Ball animation sent to group")
    except Exception as e:
        logger.error(f"รขยล Failed to send animation: {e}")
        await context.bot.send_message(group_id, text, reply_markup=reply_markup, parse_mode=ParseMode.HTML)
    
    # --- รฐลธโยฉ DM TO BOWLER ---
    dm_lines = [
        f"รฐลธยย <b>Batsman:</b> {striker.first_name}",
        f"รฐลธโล  <b>Score:</b> {bat_team.score}/{bat_team.wickets}",
    ]
    if match.innings == 2:
        runs_needed = match.target - bat_team.score
        balls_left = (match.total_overs * 6) - bat_team.balls
        dm_lines.append(f"รฐลธลฝยฏ <b>Defend:</b> {runs_needed} runs in {balls_left} balls")
    dm_lines.append("รฐลธโยฉ Send a number (0รขโฌโ6) to bowl!")
    dm_lines.append("รขยยฑ <i>45 seconds remaining</i>")
    dm_text = themed("รขลกยพ YOUR TURN TO BOWL", dm_lines, "รฐลธยฅลฝ")
    
    # Build inline button to jump back to the group game
    try:
        chat_id_str = str(abs(group_id))
        if chat_id_str.startswith("100"):
            tme_gid = chat_id_str[3:]
        else:
            tme_gid = chat_id_str
        game_msg_id = match.main_message_id or 1
        game_url = f"https://t.me/c/{tme_gid}/{game_msg_id}"
        dm_bowl_markup = InlineKeyboardMarkup([[
            InlineKeyboardButton("รฐลธยลธรฏยธย Go to Game", url=game_url)
        ]])
    except Exception:
        dm_bowl_markup = None

    # Always initialize ball data and start timer regardless of DM success
    match.current_ball_data = {
        "bowler_id": bowler.user_id, 
        "bowler_number": None, 
        "batsman_number": None,
        "group_id": group_id
    }
    logger.info(f"รขลโฆ Ball data initialized: {match.current_ball_data}")
    
    if match.ball_timeout_task:
        match.ball_timeout_task.cancel()
    match.ball_timeout_task = asyncio.create_task(
        game_timer(context, group_id, match, "bowler", bowler.first_name)
    )
    logger.info(f"รขลโฆ Game timer started for bowler")

    try:
        await context.bot.send_message(bowler.user_id, dm_text, parse_mode=ParseMode.HTML, reply_markup=dm_bowl_markup)
        logger.info(f"รขลโฆ DM sent to bowler {bowler.first_name} (ID: {bowler.user_id})")
        
    except Forbidden:
        logger.warning(f"รขลกย รฏยธย Cannot DM bowler {bowler.first_name} - User hasn't started bot")
        await context.bot.send_message(
            group_id, 
            f"รขลกย รฏยธย <b>{bowler_tag}</b> hasn't started the bot in DM!\n"
            f"รขยยณ They have <b>45 seconds</b> to bowl or a penalty will be applied automatically.", 
            parse_mode=ParseMode.HTML
        )
    except Exception as e:
        logger.error(f"รขยล DM error: {e}")
    
    logger.info(f"รฐลธลฝยฎ === EXECUTE_BALL END ===")

async def wait_for_bowler_number(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """Wait for bowler to send number with reminders"""
    bowler = match.current_bowling_team.players[match.current_bowling_team.current_bowler_idx]
    
    try:
        # Wait 30 seconds
        await asyncio.sleep(30)
        
        if match.current_ball_data.get("bowler_number") is None:
            # Send reminder at 30s
            try:
                await context.bot.send_message(
                    chat_id=bowler.user_id,
                    text="รขยยฐ <b>30 seconds left!</b>\nรขลกยพ Send your number (0รขโฌโ6) to bowl!",
                    parse_mode=ParseMode.HTML
                )
                match.current_ball_data["bowler_reminded"] = True
            except Exception as e:
                logger.error(f"Error sending reminder to bowler: {e}")
        
        # Wait 15 more seconds
        await asyncio.sleep(15)
        
        if match.current_ball_data.get("bowler_number") is None:
            # Send reminder at 15s
            try:
                await context.bot.send_message(
                    chat_id=bowler.user_id,
                    text="รฐลธลกยจ <b>15 SECONDS!</b> Bowl NOW or it's a NO BALL!",
                    parse_mode=ParseMode.HTML
                )
            except Exception as e:
                logger.error(f"Error sending reminder to bowler: {e}")
        
        # Wait 10 more seconds
        await asyncio.sleep(10)
        
        if match.current_ball_data.get("bowler_number") is None:
            # Send reminder at 5s
            try:
                await context.bot.send_message(
                    chat_id=bowler.user_id,
                    text="รฐลธโยด <b>5 SECONDS!</b> BOWL NOW!",
                    parse_mode=ParseMode.HTML
                )
            except Exception as e:
                logger.error(f"Error sending reminder to bowler: {e}")
        
        # Wait final 5 seconds
        await asyncio.sleep(5)
        
        if match.current_ball_data.get("bowler_number") is None:
            # Timeout - handle penalty
            await handle_bowler_timeout(context, group_id, match)
    
    except asyncio.CancelledError:
        pass

async def handle_bowler_timeout(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """Handle bowler timeout penalty"""
    bowler = match.current_bowling_team.players[match.current_bowling_team.current_bowler_idx]
    bowler.bowling_timeouts += 1
    bowler.no_balls += 1
    
    timeout_count = bowler.bowling_timeouts
    
    # Add no ball
    match.current_batting_team.score += 1
    match.current_batting_team.extras += 1
    match.is_free_hit = True
    
    gif_url = get_random_gif(MatchEvent.NO_BALL)
    commentary = get_random_commentary("noball")
    
    if timeout_count >= PLAYER_TIMEOUT_LIMIT:
        # Ban from bowling
        
        penalty_text = f"รฐลธลกยจ <b>BOWLER TIMEOUT รขโ โ BANNED!</b>\n"
        penalty_text += f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        penalty_text += f"รขโบโ <b>{bowler.first_name}</b> timed out {PLAYER_TIMEOUT_LIMIT} times. They can bowl again later.\n"
        penalty_text += f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        penalty_text += f"รฐลธโล NO BALL  รยท  รขลพโข +1 Run  รยท  รขลกยก FREE HIT next ball!\n"
        penalty_text += f"รฐลธโยฌ <i>{commentary}</i>\n"
        penalty_text += f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        penalty_text += f"รฐลธโล  Score: <b>{match.current_batting_team.score}/{match.current_batting_team.wickets}</b>"
    else:
        penalty_text = f"รขยยฑรฏยธย <b>BOWLER TIMEOUT!</b>  <code>{timeout_count}/{PLAYER_TIMEOUT_LIMIT}</code>\n"
        penalty_text += f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        penalty_text += f"รขลกย รฏยธย <b>{bowler.first_name}</b> didn't bowl in time!\n"
        penalty_text += f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        penalty_text += f"รฐลธโล NO BALL  รยท  รขลพโข +1 Run  รยท  รขลกยก FREE HIT!\n"
        penalty_text += f"รฐลธโยฌ <i>{commentary}</i>\n"
        penalty_text += f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        penalty_text += f"รฐลธโล  Score: <b>{match.current_batting_team.score}/{match.current_batting_team.wickets}</b>"
    
    try:
        if gif_url:
            await context.bot.send_animation(
                chat_id=group_id,
                animation=gif_url,
                caption=penalty_text
            )
        else:
            await context.bot.send_message(
                chat_id=group_id,
                text=penalty_text
            )
    except Exception as e:
        logger.error(f"Error sending timeout message: {e}")
        await context.bot.send_message(
            chat_id=group_id,
            text=penalty_text
        )
    
    # Continue with next ball
    await asyncio.sleep(2)
    
    if bowler.is_bowling_banned:
        # Need new bowler รขโ โ request selection, don't call execute_ball here
        match.waiting_for_bowler = True
        match.current_ball_data = {}
        await request_bowler_selection(context, group_id, match)
    else:
        # รขลโฆ FIX 7: No ball รขโ โ same bowler bowls again (ball doesn't count)
        match.current_ball_data = {}
        await execute_ball(context, group_id, match)

# Handle DM messages from players

async def bannedgroups_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    Show list of all banned groups (Owner Only)
    """
    user = update.effective_user
    
    if user.id != OWNER_ID:
        return
    
    if not banned_groups:
        await update.message.reply_text(
            "รขลโฆ <b>NO BANNED GROUPS</b>\n\n"
            "Currently, no groups are banned from using the bot.",
            parse_mode=ParseMode.HTML
        )
        return
    
    msg = f"รฐลธลกยซ <b>BANNED GROUPS LIST</b>\n"
    msg += f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
    msg += f"รฐลธโล  <b>Total:</b> {len(banned_groups)} groups\n\n"
    
    for i, chat_id in enumerate(banned_groups, 1):
        # Try to get group name
        try:
            chat_info = await context.bot.get_chat(chat_id)
            group_name = chat_info.title
        except:
            group_name = "Unknown/Left Group"
        
        msg += f"{i}. <b>{group_name}</b>\n"
        msg += f"   รฐลธโ โ <code>{chat_id}</code>\n\n"
        
        # Telegram message limit protection
        if len(msg) > 3500:
            await update.message.reply_text(msg, parse_mode=ParseMode.HTML)
            msg = "<b>...continued</b>\n\n"
    
    msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
    msg += "<i>Use /unbangroup [id] to unban</i>"
    
    await update.message.reply_text(msg, parse_mode=ParseMode.HTML)

async def unbangroup_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    Unban a group (Owner Only)
    Usage: 
      - In group: /unbangroup
      - Via DM: /unbangroup -1001234567890
    """
    user = update.effective_user
    
    # Owner check
    if user.id != OWNER_ID:
        return
    
    chat = update.effective_chat
    
    # Method 1: Command used in the group itself
    if chat.type in ["group", "supergroup"]:
        target_chat_id = chat.id
        target_chat_name = chat.title
    
    # Method 2: Command used in DM with group ID
    elif context.args:
        try:
            target_chat_id = int(context.args[0])
            
            # Try to get group info
            try:
                chat_info = await context.bot.get_chat(target_chat_id)
                target_chat_name = chat_info.title
            except:
                target_chat_name = "Unknown Group"
        except ValueError:
            await update.message.reply_text(
                "รขลกย รฏยธย <b>Invalid Group ID</b>\n\n"
                "<b>Usage:</b>\n"
                "In Group: <code>/unbangroup</code>\n"
                "In DM: <code>/unbangroup -1001234567890</code>",
                parse_mode=ParseMode.HTML
            )
            return
    else:
        await update.message.reply_text(
            "รขลกย รฏยธย <b>Usage:</b>\n"
            "In Group: <code>/unbangroup</code>\n"
            "In DM: <code>/unbangroup [group_id]</code>\n\n"
            "<b>Example:</b> <code>/unbangroup -1001234567890</code>",
            parse_mode=ParseMode.HTML
        )
        return
    
    # Check if actually banned
    if target_chat_id not in banned_groups:
        await update.message.reply_text(
            f"รขลกย รฏยธย <b>{target_chat_name}</b> (<code>{target_chat_id}</code>) is not banned!",
            parse_mode=ParseMode.HTML
        )
        return
    
    # รขลโฆ UNBAN THE GROUP
    banned_groups.discard(target_chat_id)
    save_data()
    
    # Notify the group
    await notify_ban_status(context, target_chat_id, is_ban=False)
    
    # Confirm to owner
    await update.message.reply_text(
        f"รขลโฆ <b>GROUP UNBANNED</b>\n\n"
        f"รฐลธโโบ <b>Name:</b> {target_chat_name}\n"
        f"รฐลธโ โ <b>ID:</b> <code>{target_chat_id}</code>\n\n"
        f"รขลโฆ This group can now use the bot again.",
        parse_mode=ParseMode.HTML
    )
    
    # Log to support group
    try:
        await context.bot.send_message(
            chat_id=SUPPORT_GROUP_ID,
            text=(
                f"รขลโฆ <b>GROUP UNBANNED</b>\n"
                f"รฐลธโโบ {target_chat_name}\n"
                f"รฐลธโ โ <code>{target_chat_id}</code>\n"
                f"รฐลธโยค By: {user.first_name}"
            ),
            parse_mode=ParseMode.HTML
        )
    except:
        pass

