async def check_wide_condition(match: Match, current_number: int) -> bool:
    """
    รขลโฆ FIXED: Wide only if bowler sends same number 3 CONSECUTIVE times
    รฐลธโล Example: 4, 4, 4 = WIDE
    รฐลธลกยซ But: 4, 2, 4 = NOT WIDE (not consecutive)
    รฐลธลกยซ And: 4, 4, 3, 4 = NOT WIDE (sequence broken)
    """
    # Check if wides are disabled for this group
    group_id = getattr(match, 'group_id', None)
    if group_id and not get_gc_setting(group_id, "wide_enabled", True):
        return False
    
    # รฐลธโล Initialize history if not exists
    bowl_team = getattr(match, "current_bowling_team", None)
    bowler = None
    if bowl_team and getattr(bowl_team, "current_bowler_idx", None) is not None:
        try:
            bowler = bowl_team.players[bowl_team.current_bowler_idx]
        except Exception:
            bowler = None
    if not bowler:
        return False

    if not hasattr(bowler, "bowling_number_counts"):
        bowler.bowling_number_counts = defaultdict(int)
    bowler.bowling_number_counts[current_number] += 1
    if bowler.bowling_number_counts[current_number] >= 3:
        logger.info(f"Wide detected for bowler {bowler.user_id}: number {current_number}")
        bowler.bowling_number_counts[current_number] = 0
        return True
    
    return False

