async def drs_timeout_handler(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """รขยยณ Auto-reject DRS after 10 seconds"""
    try:
        await asyncio.sleep(10)
        
        if not match.drs_in_progress:
            return
        
        match.drs_in_progress = False
        
        await context.bot.send_message(
            group_id,
            "รขลโบ <b>DRS TIMEOUT!</b>\n"
            "10 seconds are up รขโ โ no review taken.\n"
            "รขลกโรฏยธย <b>Umpire's decision stands!</b>\n"
            "รฐลธโยด <b>WICKET CONFIRMED.</b>",
            parse_mode=ParseMode.HTML
        )
        
        await asyncio.sleep(2)
        
        # รขลโฆ CRITICAL FIX: Confirm wicket properly
        calculate_momentum_change(match, 0, True, False)
        await confirm_wicket_and_continue(context, group_id, match)
        
    except asyncio.CancelledError:
        pass

# รขลโฆ DRS Callback Handler
async def drs_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """รฐลธโยฑรฏยธย Handle DRS button clicks"""
    query = update.callback_query
    await query.answer()
    
    chat = query.message.chat
    user = query.from_user
    
    if chat.id not in active_matches:
        return
    
    match = active_matches[chat.id]
    
    if not match.drs_in_progress:
        await query.answer("รขลโบ DRS window closed!", show_alert=True)
        return
    
    # Check if captain
    batting_captain = match.get_captain(match.current_batting_team)
    if user.id != batting_captain.user_id:
        await query.answer("รฐลธยงยข Only Captain can decide DRS!", show_alert=True)
        return
    
    match.drs_in_progress = False
    
    if query.data == "drs_take":
        # รฐลธโยบ Use DRS
        match.current_batting_team.drs_remaining -= 1
        await query.message.edit_text(
            f"รฐลธโยบ <b>DRS รขโ โ REVIEW CALLED!</b>\n"
            f"รฐลธโย Sending to Third Umpire...\n"
            f"รขยยณ <i>Awaiting ball-tracking data...</i>",
            parse_mode=ParseMode.HTML
        )
        await process_drs_review(context, chat.id, match)
        
    elif query.data == "drs_reject":
        # รขยล Don't use DRS
        await query.message.edit_text(
            f"รขลโน <b>DRS DECLINED</b>\n"
            f"รฐลธยคย {batting_captain.first_name} accepts the umpire's call. Decision stands.",
            parse_mode=ParseMode.HTML
        )
        await asyncio.sleep(2)
        
        # รขลโฆ CRITICAL FIX: Continue game after rejection
        calculate_momentum_change(match, 0, True, False)
        await confirm_wicket_and_continue(context, chat.id, match)

async def drs_decision_timeout(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """Handle DRS decision timeout"""
    await asyncio.sleep(30)
    
    if not match.drs_in_progress:
        return
    
    # No DRS taken, confirm wicket
    match.drs_in_progress = False
    await confirm_wicket(context, group_id, match, drs_used=False, drs_successful=False)

# DRS command
async def drs_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    รขลโฆ UPDATED: DRS command with 10 second check
    """
    chat = update.effective_chat
    user = update.effective_user
    
    if chat.type == "private":
        await update.message.reply_text("This command only works in groups.")
        return
    
    if chat.id not in active_matches:
        await update.message.reply_text("No active match found.")
        return
    
    match = active_matches[chat.id]
    
    if not match.drs_in_progress:
        await update.message.reply_text("No DRS review available at this moment.")
        return
    
    # Check if 10 seconds have passed
    current_time = time.time()
    if current_time - match.drs_offer_time > 10:
        await update.message.reply_text("รขลกย รฏยธย DRS time expired! 10 seconds over.")
        match.drs_in_progress = False
        calculate_momentum_change(match, 0, True, False)
        await confirm_wicket_and_continue(context, chat.id, match)
        return
    
    # Check if user is batting captain
    batting_captain = match.get_captain(match.current_batting_team)
    if not batting_captain:
        await update.message.reply_text("รขลกย รฏยธย No batting captain found!")
        return
    
    if user.id != batting_captain.user_id:
        await update.message.reply_text(
            f"รขลกย รฏยธย Only {match.current_batting_team.name} Captain can request DRS."
        )
        return
    
    # Process DRS
    match.drs_in_progress = False
    match.current_batting_team.drs_remaining -= 1
    
    await process_drs_review(context, chat.id, match)


async def process_drs_review(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """
    รขลโฆ FIXED: DRS successful doesn't reduce wickets below original count
    """
    batsman = match.last_wicket_ball["batsman"]
    
    drs_text = "รฐลธโยบ <b>DRS รขโ โ IN REVIEW...</b>\n"
    drs_text += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
    drs_text += "รฐลธโย Ball-tracking analysis underway...\n"
    drs_text += "รฐลธโยก Consulting Third Umpire...\n"
    drs_text += "รขยยณ <i>Please hold...</i>"
    
    gif_url = get_random_gif(MatchEvent.DRS_REVIEW)
    
    try:
        if gif_url:
            msg = await context.bot.send_animation(group_id, animation=gif_url, caption=drs_text, parse_mode=ParseMode.HTML)
        else:
            msg = await context.bot.send_message(group_id, drs_text, parse_mode=ParseMode.HTML)
    except:
        msg = await context.bot.send_message(group_id, drs_text, parse_mode=ParseMode.HTML)
    
    await asyncio.sleep(3)
    
    is_overturned = random.random() < 0.40
    
    if is_overturned:
        # รขลโฆ NOT OUT - Don't touch wickets (they were never incremented)
        batsman.is_out = False
        match.current_batting_team.out_players_indices.discard(match.current_batting_team.current_batsman_idx)
        
        gif = "https://tenor.com/bOVyJ.gif"
        
        result_text = "รฐลธโยบ <b>DRS RESULT รขโ โ NOT OUT!</b>\n"
        result_text += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        result_text += f"รขลโฆ <b>{batsman.first_name}</b> survives! Decision OVERTURNED!\n"
        result_text += f"รฐลธโยก DRS left: {match.current_batting_team.drs_remaining}"
        
        try:
            await context.bot.send_animation(group_id, animation=gif, caption=result_text, parse_mode=ParseMode.HTML)
        except:
            await context.bot.send_message(group_id, result_text, parse_mode=ParseMode.HTML)
        
        await asyncio.sleep(2)
        
        if match.current_bowling_team.get_current_over_balls() == 0:
            await check_over_complete(context, group_id, match)
        else:
            await execute_ball(context, group_id, match)
    else:
        # OUT confirmed
        result_text = "รฐลธโยบ <b>DRS RESULT รขโ โ OUT!</b>\n"
        result_text += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        result_text += f"รฐลธโยด <b>{batsman.first_name}</b> is OUT! Decision UPHELD!\n"
        result_text += f"รฐลธยฦ Score: {batsman.runs}({batsman.balls_faced})  รยท  รฐลธโยก DRS left: {match.current_batting_team.drs_remaining}"
        
        try:
            await context.bot.send_animation(group_id, animation=gif_url, caption=result_text, parse_mode=ParseMode.HTML)
        except:
            await context.bot.send_message(group_id, result_text, parse_mode=ParseMode.HTML)
        
        await asyncio.sleep(2)
        calculate_momentum_change(match, 0, True, False)
        await confirm_wicket_and_continue(context, group_id, match)

async def confirm_wicket_and_continue(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """
    รขลโฆ FIXED: Wicket handler WITH proper wicket increment
    """
    
    logger.info(f"รฐลธโยดรฐลธยย === WICKET HANDLER START === Group: {group_id}")
    
    if match.phase == GamePhase.MATCH_ENDED:
        logger.warning("รฐลธโบโ Match already ended, aborting wicket handling")
        return

    bat_team = match.current_batting_team
    bowl_team = match.current_bowling_team
    
    # Get the OUT player
    if bat_team.current_batsman_idx is None:
        logger.error("รฐลธลกยซรฐลธโยค CRITICAL: No batsman index set!")
        await context.bot.send_message(group_id, "รขลกย รฏยธย Error: No batsman found!", parse_mode=ParseMode.HTML)
        return
    
    out_player = bat_team.players[bat_team.current_batsman_idx]
    bowler = bowl_team.players[bowl_team.current_bowler_idx]
    
    logger.info(f"รขหย รฏยธย OUT Player: {out_player.first_name} (Index: {bat_team.current_batsman_idx})")
    
    await asyncio.sleep(1)
    
    # รขลโฆ CRITICAL FIX: INCREMENT WICKETS HERE
    out_player.is_out = True
    bat_team.wickets += 1  # รขลโฆ INCREMENT TEAM WICKET COUNT
    bowler.wickets += 1    # รขลโฆ INCREMENT BOWLER WICKET COUNT
    # Save & reset partnership on wicket
    if match.current_partnership_runs > 0:
        _batsman_name = match.current_batting_team.players[match.current_batting_team.current_batsman_idx].first_name if match.current_batting_team.current_batsman_idx is not None else '?'
        _ns_name = match.current_batting_team.players[match.current_batting_team.current_non_striker_idx].first_name if match.current_batting_team.current_non_striker_idx is not None else '?'
        match.partnership_history.append({'p1': _batsman_name, 'p2': _ns_name, 'runs': match.current_partnership_runs, 'balls': match.current_partnership_balls})
    match.current_partnership_runs = 0
    match.current_partnership_balls = 0
    # Increment over wickets counter
    match.current_over_wickets += 1
    bowler.consecutive_wickets += 1  # รฐลธลฝยฏ Increment consecutive wickets for hat-trick
    
    # รขลโฆ LOG WICKET BALL
    match.ball_by_ball_log.append({
        "over": format_overs(bat_team.balls),
        "batsman": out_player.first_name,
        "bowler": bowler.first_name,
        "batting_team": bat_team.name,
        "runs": 0,
        "wicket": True,
        "is_wicket": True,
        "wide": False,
        "noball": False,
    })

    logger.info(f"รขลโฆ Wickets updated: Team={bat_team.wickets}, Bowler={bowler.wickets}, Consecutive={bowler.consecutive_wickets}")
    
    # รฐลธลฝโฐ CHECK BOWLING MILESTONE
    await check_and_celebrate_milestones(context, group_id, match, bowler, 'bowling')
    
    # รฐลธโโ Send Mini Scorecard with dynamic over-by-over bar chart
    try:
        mini_card = generate_mini_scorecard(match)
        # Try dynamic bar chart first
        chart_sent = False
        try:
            chart_bio = await asyncio.to_thread(generate_over_bar_chart, match)
            if chart_bio:
                await context.bot.send_photo(
                    group_id,
                    photo=chart_bio,
                    caption=mini_card,
                    parse_mode=ParseMode.HTML
                )
                chart_sent = True
        except Exception as chart_err:
            logger.warning(f"Bar chart (wicket) failed: {chart_err}")
        if not chart_sent:
            # Fallback: static photo
            try:
                await context.bot.send_photo(
                    group_id,
                    photo=MINI_SCORECARD_PHOTO,
                    caption=mini_card,
                    parse_mode=ParseMode.HTML
                )
            except Exception as photo_error:
                logger.error(f"Error sending mini scorecard photo: {photo_error}")
                await context.bot.send_message(group_id, mini_card, parse_mode=ParseMode.HTML)
        logger.info("รฐลธโยจ Mini scorecard sent")
    except Exception as e:
        logger.error(f"รฐลธลกยซ Failed to send mini scorecard: {e}")
    
    await asyncio.sleep(2)
    
    # รขลกยฐรฏยธย Mark player as OUT
    bat_team.out_players_indices.add(bat_team.current_batsman_idx)
    logger.info(f"รขลโฆ Marked {out_player.first_name} as OUT (Total Out: {len(bat_team.out_players_indices)})")
    
    # รฐลธยงยน Clear striker position
    bat_team.current_batsman_idx = None
    logger.info("รฐลธยงยน Striker position cleared, non-striker remains same")
    
    # รฐลธยงยฎ Check innings end conditions
    remaining_players = len(bat_team.players) - len(bat_team.out_players_indices)
    logger.info(f"รฐลธโยฅ Remaining Players: {remaining_players}")
    
    # รขลโฆ CRITICAL: Check if this wicket fell on the LAST ball of the over
    current_over_balls_after_wicket = bat_team.get_current_over_balls()
    is_last_ball_of_over = (current_over_balls_after_wicket == 0 and bat_team.balls > 0)
    
    if bat_team.is_all_out():
        logger.info("รขยลรฐลธโบโ ALL OUT - Ending Innings")
        await context.bot.send_message(
            group_id,
            themed("รฐลธโโฌ ALL OUT!", ["Last wicket falls! The innings has ended.", f"รฐลธโล  Final: {match.current_batting_team.score}/{match.current_batting_team.wickets}"], "รฐลธโโฌ"),
            parse_mode=ParseMode.HTML
        )
        await asyncio.sleep(2)
        await end_innings(context, group_id, match)
        return
    
    if bat_team.balls >= match.total_overs * 6:
        logger.info("รขยยฑ Overs complete - Ending Innings")
        await end_innings(context, group_id, match)
        return
    
    if match.innings == 2 and bat_team.score >= match.target:
        logger.info("รฐลธลฝโฐรฐลธยโ  Target chased - Match Won")
        await end_innings(context, group_id, match)
        return
    
    # รฐลธโโ PRIORITY #1: Request new batsman FIRST (ALWAYS)
    match.waiting_for_batsman = True
    match.waiting_for_bowler = False
    match.current_ball_data = {}
    logger.info("รขยยธรฏยธยรขลโน Game PAUSED - waiting_for_batsman=True")
    
    # รฐลธโล STORE OVER STATUS - Will be checked AFTER batsman is selected
    match.pending_over_complete = is_last_ball_of_over
    logger.info(f"รฐลธโล  Over status stored: pending_over_complete={match.pending_over_complete}")
    
    batting_captain = match.get_captain(bat_team)
    if not batting_captain:
        logger.error("รฐลธลกยซรฐลธโยฎ CRITICAL: No batting captain found!")
        await context.bot.send_message(group_id, "รขลกย รฏยธย Error: No captain found!", parse_mode=ParseMode.HTML)
        return
    
    captain_tag = get_user_tag(batting_captain)
    available_batsmen = [
        p for i, p in enumerate(bat_team.players) 
        if i not in bat_team.out_players_indices 
        and i != bat_team.current_non_striker_idx
    ]
    available_count = len(available_batsmen)
    
    if available_count == 0:
        logger.error("รฐลธโยญ No available batsmen!")
        await end_innings(context, group_id, match)
        return
    
    msg += f"รฐลธโโ {captain_tag} รขโ โ send in your next batter!\n"
    msg += f"รขลยจรฏยธย <code>/batting [number]</code>  รขยยณ <i>4 min window</i>"
    
    await context.bot.send_message(group_id, msg, parse_mode=ParseMode.HTML)
    logger.info("รฐลธโยจ New batsman request sent to group")
    
    # รขยยฑรฏยธย Start selection timer
    match.batsman_selection_time = time.time()
    match.batsman_selection_task = asyncio.create_task(
        batsman_selection_timeout(context, group_id, match)
    )
    logger.info("รขยยฑรฏยธยรฐลธลกโฌ Batsman selection timer started")
    logger.info(f"รฐลธโยดรฐลธยย === WICKET HANDLER END ===\n")

async def handle_noball_and_continue(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """
    รขลโฆ FIX 7: After No Ball รขโ โ send bowling message again so bowler re-bowls
    """
    bat_team = match.current_batting_team
    bowl_team = match.current_bowling_team
    
    match.is_free_hit = True
    bat_team.score += 1
    bat_team.extras += 1
    
    bowler = bowl_team.players[bowl_team.current_bowler_idx] if bowl_team.current_bowler_idx is not None else None
    bowler_tag = get_user_tag(bowler) if bowler else "Bowler"
    
    nb_gif = get_random_gif(MatchEvent.NO_BALL)
    nb_msg = (
        f"รฐลธลกยซ <b>NO BALL!</b> รฐลธลกยซ\n"
        f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        f"รขลกยพ {bowler_tag} oversteps!\n"
        f"รขลพโข <b>+1 Extra</b>  รยท  รขลกยก <b>FREE HIT</b> next ball!\n"
        f"รฐลธโล  Score: <b>{bat_team.score}/{bat_team.wickets}</b>\n"
        f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        f"รฐลธโย <i>Ball does NOT count รขโ โ bowling again!</i>"
    )
    
    try:
        if nb_gif:
            await context.bot.send_animation(group_id, animation=nb_gif, caption=nb_msg, parse_mode=ParseMode.HTML)
        else:
            await context.bot.send_message(group_id, nb_msg, parse_mode=ParseMode.HTML)
    except Exception:
        await context.bot.send_message(group_id, nb_msg, parse_mode=ParseMode.HTML)
    
    # Log no ball (does NOT count as legal delivery)
    striker = bat_team.players[bat_team.current_batsman_idx] if bat_team.current_batsman_idx is not None else None
    match.ball_by_ball_log.append({
        "over": format_overs(bat_team.balls),
        "batsman": striker.first_name if striker else "?",
        "bowler": bowler.first_name if bowler else "?",
        "batting_team": bat_team.name,
        "runs": 1,
        "wicket": False,
        "is_wicket": False,
        "wide": False,
        "noball": True,
    })
    
    await asyncio.sleep(2)
    
    # Reset ball data and re-send bowling prompt (ball NOT counted)
    match.current_ball_data = {}
    await execute_ball(context, group_id, match)


    """
    รฐลธยฅยค DRINKS BREAK - Triggers at 10th over (60 balls)
    """
    bat_team = match.current_batting_team
    
    # รฐลธโขยตรฏยธย Check if 10 overs completed (60 balls)
    if bat_team.balls == 60:
        drinks_gif = "https://media.giphy.com/media/l0HlBO7eyXzSZkJri/giphy.gif"
        
        msg = f"รฐลธยฅยค <b>DRINKS BREAK!</b> รฐลธยฅยค\n"
        msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        msg += f"รฐลธโล  <b>Score:</b> {bat_team.score}/{bat_team.wickets} ({format_overs(bat_team.balls)})\n\n"
        
        # รฐลธยงยฎ Calculate stats
        overs_played = max(bat_team.balls / 6, 0.1)
        crr = round(bat_team.score / overs_played, 2)
        msg += f"รฐลธโห <b>Current RR:</b> {crr}\n"
        
        if match.innings == 2:
            runs_needed = match.target - bat_team.score
            balls_left = (match.total_overs * 6) - bat_team.balls
            rrr = round((runs_needed / balls_left) * 6, 2) if balls_left > 0 else 0
            msg += f"รฐลธลฝยฏ <b>Required RR:</b> {rrr}\n"
            msg += f"รฐลธยย <b>Need:</b> {runs_needed} runs in {balls_left} balls\n"
        
        msg += "\nรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        msg += "รขยยณ <i>Resuming in 30 seconds...</i>"
        
        try:
            await context.bot.send_animation(group_id, animation=drinks_gif, caption=msg, parse_mode=ParseMode.HTML)
        except:
            await context.bot.send_message(group_id, msg, parse_mode=ParseMode.HTML)
        
        # รขยยฑรฏยธย 30 second pause
        await asyncio.sleep(30)
        
        await context.bot.send_message(
            group_id,
            text="รขโยถรฏยธย <b>DRINKS BREAK OVER!</b> รขโ โ Play resumes now! รฐลธยย",
            parse_mode=ParseMode.HTML
        )
        await asyncio.sleep(2)

async def check_over_complete(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """
    รฐลธยย End of Over: Show Mini Scorecard, Swap Batsmen, Request New Bowler
    """
    
    logger.info(f"รฐลธลธยข check_over_complete called for group {group_id}")
    
    if match.phase == GamePhase.MATCH_ENDED:
        logger.warning("รฐลธโบโ Match already ended, skipping over complete")
        return

    bat_team = match.current_batting_team
    bowl_team = match.current_bowling_team
    
    # Get current bowler info BEFORE clearing
    if bowl_team.current_bowler_idx is not None:
        bowler = bowl_team.players[bowl_team.current_bowler_idx]
        bowl_team.bowler_history.append(bowl_team.current_bowler_idx)
        logger.info(f"รขลโฆ Bowler {bowler.first_name} added to history")
    else:
        bowler = type("obj", (object,), {"first_name": "Unknown", "wickets": 0, "runs_conceded": 0})
        logger.error("รฐลธลกยซ No bowler found at over complete!")
    
    # Save over wickets
    if bat_team == match.team_x:
        match.team_x_over_wickets.append(match.current_over_wickets)
    else:
        match.team_y_over_wickets.append(match.current_over_wickets)
    match.current_over_wickets = 0

    # รขลโฆ Save over runs for this completed over
    if bat_team == match.team_x:
        already_accounted = sum(match.team_x_over_runs)
        runs_in_this_over = bat_team.score - already_accounted
        match.team_x_over_runs.append(max(0, runs_in_this_over))
    else:
        already_accounted = sum(match.team_y_over_runs)
        runs_in_this_over = bat_team.score - already_accounted
        match.team_y_over_runs.append(max(0, runs_in_this_over))
    match.current_over_runs = 0  # Reset for the next over

    # รขโโฌรขโโฌ Compute best ball of the over from ball_by_ball_log รขโโฌรขโโฌ
    over_num_done = bat_team.balls // 6
    over_balls_log = [
        b for b in match.ball_by_ball_log
        if b.get("batting_team") == bat_team.name
    ]
    this_over_balls = over_balls_log[-(over_num_done * 6 - (over_num_done - 1) * 6):]  # last 6 legal
    # Simpler: just last min(6, len) entries for this batting team
    this_over_balls = [
        b for b in match.ball_by_ball_log
        if b.get("batting_team") == bat_team.name
    ][-6:]
    best_ball_runs = max((b.get("runs", 0) for b in this_over_balls), default=0)
    wicket_in_over = any(b.get("is_wicket") or b.get("wicket") for b in this_over_balls)
    dot_balls_over = sum(1 for b in this_over_balls if b.get("runs", 0) == 0 and not (b.get("is_wicket") or b.get("wicket")))

    # รขลโฆ STEP 1: SWAP BATSMEN (Strike Rotation) รขโฌโ do BEFORE building summary
    logger.info(f"รฐลธโโ Swapping batsmen - Before: Striker={bat_team.current_batsman_idx}, Non-Striker={bat_team.current_non_striker_idx}")
    bat_team.swap_batsmen()
    logger.info(f"รฐลธโโ After swap: Striker={bat_team.current_batsman_idx}, Non-Striker={bat_team.current_non_striker_idx}")
    
    # Re-fetch players after swap
    new_striker = bat_team.players[bat_team.current_batsman_idx] if bat_team.current_batsman_idx is not None else None
    new_non_striker = bat_team.players[bat_team.current_non_striker_idx] if bat_team.current_non_striker_idx is not None else None

    # รขโโฌรขโโฌ Build END OF OVER summary รขโโฌรขโโฌ
    _over_runs_list = match.team_x_over_runs if bat_team == match.team_x else match.team_y_over_runs
    _over_wkts_list = match.team_x_over_wickets if bat_team == match.team_x else match.team_y_over_wickets
    _last_runs = _over_runs_list[-1] if _over_runs_list else 0
    _last_wkts = _over_wkts_list[-1] if _over_wkts_list else 0
    # Run history bar (last 5 overs)
    _hist = ""
    for _r in (_over_runs_list[-5:] if _over_runs_list else []):
        if _r >= 12: _hist += "รฐลธลธยฃ"
        elif _r >= 9: _hist += "รฐลธโยด"
        elif _r >= 6: _hist += "รฐลธลธย "
        elif _r >= 3: _hist += "รฐลธลธยก"
        else: _hist += "รขลกยซ"
    _rr = round(bat_team.score / (bat_team.balls / 6), 2) if bat_team.balls > 0 else 0.0
    _part_txt = f"  รขโล   รฐลธยคย Partnership: {match.current_partnership_runs}({match.current_partnership_balls})" if match.current_partnership_runs > 0 else ""

    # Bowler economy this over
    _over_econ = round(_last_runs / 1, 2)  # runs per over (this was 1 over)
    # Best ball label
    if best_ball_runs == 6:
        _best_ball_txt = "รฐลธลกโฌ Best ball: SIX!"
    elif best_ball_runs == 4:
        _best_ball_txt = "รฐลธโยฅ Best ball: FOUR!"
    elif wicket_in_over:
        _best_ball_txt = "รฐลธโโฌ Wicket taken this over!"
    elif dot_balls_over >= 3:
        _best_ball_txt = f"รฐลธโโ {dot_balls_over} dot balls รขโ โ tight bowling!"
    else:
        _best_ball_txt = f"รฐลธโล  {dot_balls_over} dot ball{'s' if dot_balls_over != 1 else ''}"

    # รขโโฌรขโโฌ Build END OF OVER summary using new styled format รขโโฌรขโโฌ
    mini_card = generate_mini_scorecard(match)
    combined_caption = mini_card

    # รขลโฆ Send combined over-summary + mini scorecard with chart
    chart_sent2 = False
    try:
        chart_bio2 = await asyncio.to_thread(generate_over_bar_chart, match)
        if chart_bio2:
            await context.bot.send_photo(
                group_id,
                photo=chart_bio2,
                caption=combined_caption,
                parse_mode=ParseMode.HTML
            )
            chart_sent2 = True
    except Exception as chart_err2:
        logger.warning(f"Bar chart (over complete) failed: {chart_err2}")
    if not chart_sent2:
        try:
            await context.bot.send_photo(
                group_id,
                photo=MINI_SCORECARD_PHOTO,
                caption=combined_caption,
                parse_mode=ParseMode.HTML
            )
        except Exception as photo_error:
            logger.error(f"Error sending mini scorecard photo: {photo_error}")
            await context.bot.send_message(group_id, combined_caption, parse_mode=ParseMode.HTML)
    logger.info("รฐลธโยจ Combined over-summary + mini scorecard sent")

    # รขโโฌรขโโฌ Mid-match random image every 2 overs (after over 2+ and randomly chosen)
    try:
        overs_done = len(match.team_x_over_runs) + len(match.team_y_over_runs)
        last_img_over = mid_match_image_tracker.get(group_id, 0)
        # Trigger if at least 2 overs since last image, with 50% random chance
        if (overs_done - last_img_over) >= 2 and random.random() < 0.5:
            mid_bio = await asyncio.to_thread(generate_mid_match_image, match)
            if mid_bio:
                caption = _build_mid_match_caption(match)
                await context.bot.send_photo(
                    chat_id=group_id,
                    photo=mid_bio,
                    caption=caption,
                    parse_mode=ParseMode.HTML
                )
                mid_match_image_tracker[group_id] = overs_done
    except Exception as mid_e:
        logger.error(f"Mid-match image error: {mid_e}")
    
    # รขลโฆ DRINKS BREAK CHECK (10th over = 60 balls)
    if bat_team.balls == 60:
        await check_drinks_break(context, group_id, match)
    
    # รขลโฆ STEP 3: CHECK INNINGS/MATCH END
    if bat_team.balls >= match.total_overs * 6:
        logger.info("รขลโบ Innings complete - Overs finished")
        await end_innings(context, group_id, match)
        return
    
    if match.innings == 2 and bat_team.score >= match.target:
        logger.info("รฐลธยโ  Match won - Target chased")
        await end_innings(context, group_id, match)
        return
    
    # รขลโฆ STEP 4: CLEAR OLD BOWLER & PAUSE GAME
    logger.info(f"รฐลธโบโ Clearing bowler - Old index: {bowl_team.current_bowler_idx}")
    bowl_team.current_bowler_idx = None  
    match.waiting_for_bowler = True
    match.waiting_for_batsman = False
    match.current_ball_data = {}
    logger.info("รขยยธรฏยธย Match state set to waiting_for_bowler=True")
    
    await asyncio.sleep(2)
    
    # รขลโฆ STEP 5: REQUEST NEW BOWLER (CRITICAL)
    logger.info("รฐลธโยข Calling request_bowler_selection...")
    await request_bowler_selection(context, group_id, match)
    logger.info("รขลโฆ request_bowler_selection completed")


# --- HELPER FUNCTIONS FOR GRAPHICS ENGINE ---


async def confirm_wicket(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match, drs_used: bool, drs_successful: bool):
    """Confirm wicket and update match state"""
    batsman = match.last_wicket_ball["batsman"]
    bowler = match.last_wicket_ball["bowler"]
    
    # Mark batsman as out
    batsman.is_out = True
    batsman.dismissal_type = "Bowled"
    match.current_batting_team.wickets += 1
    bowler.wickets += 1
    
    # รขลโฆ FIX: Update player_stats dismissal field
    if batsman.user_id in match.current_batting_team.player_stats:
        match.current_batting_team.player_stats[batsman.user_id]["dismissal"] = batsman.dismissal_type
    
    # รขลโฆ CHECK BOWLING MILESTONE
    await check_and_celebrate_milestones(context, group_id, match, bowler, 'bowling')

    # รขลโฆ CHECK BOWLING MILESTONE
    await check_and_celebrate_milestones(context, group_id, match, bowler, 'bowling')
    
    if drs_used and not drs_successful:
        gif_url = get_random_gif(MatchEvent.DRS_OUT)
        
        result_text = "รฐลธโยบรฃโฌโ <b>DRS RESULT</b> รฃโฌโขรฐลธโยบ\n\n"
        result_text += "รขลกโรฏยธย <b>Decision:</b> OUT รขโ โ Stands!\n\n"
        result_text += "Third umpire upholds the original call.\n\n"
        result_text += f"รฐลธโล  <b>{batsman.first_name}:</b> {batsman.runs} ({batsman.balls_faced})\n\n"
        result_text += f"รฐลธโยก DRS Remaining: {match.current_batting_team.drs_remaining}\n\n"
        result_text += f"รฐลธโล  <b>Score:</b> {match.current_batting_team.score}/{match.current_batting_team.wickets}"
        
        try:
            if gif_url:
                await context.bot.send_animation(
                    chat_id=group_id,
                    animation=gif_url,
                    caption=result_text
                )
            else:
                await context.bot.send_message(
                    chat_id=group_id,
                    text=result_text
                )
        except Exception as e:
            logger.error(f"Error sending DRS out message: {e}")
            await context.bot.send_message(
                chat_id=group_id,
                text=result_text
            )
    else:
        wicket_confirm_text = f"Wicket Confirmed\n\n"
        wicket_confirm_text += f"{batsman.first_name}: {batsman.runs} ({batsman.balls_faced})\n"
        wicket_confirm_text += f"Bowler: {bowler.first_name}\n\n"
        wicket_confirm_text += f"Score: {match.current_batting_team.score}/{match.current_batting_team.wickets}"
        
        await context.bot.send_message(
            chat_id=group_id,
            text=wicket_confirm_text
        )
    
    # Update stats
    batsman.balls_faced += 1
    bowler.balls_bowled += 1
    match.current_batting_team.update_overs()
    
    # Check for duck
    if batsman.runs == 0:
        batsman.ducks += 1
    
    # Log ball
    match.ball_by_ball_log.append({
        "over": format_overs(match.current_batting_team.balls - 1),
        "batsman": batsman.first_name,
        "bowler": bowler.first_name,
        "result": "Wicket",
        "runs": 0,
        "is_wicket": True
    })
    
    await asyncio.sleep(2)
    
    # Check if innings over
    if match.is_innings_complete():
        await end_innings(context, group_id, match)
    else:
        # Request new batsman
        match.waiting_for_batsman = True
        await request_batsman_selection(context, group_id, match)

# --- UPDATE handle_dm_message ---

async def addauctionplayer_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    รขลพโข Add player to auction pool (Mid-Auction)
    Usage: Reply to user with /addauctionplayer
    or /addauctionplayer @username
    """
    chat = update.effective_chat
    user = update.effective_user
    
    if chat.id not in active_auctions:
        await update.message.reply_text("รขยล No active auction!")
        return
    
    auction = active_auctions[chat.id]
    
    # Only host/auctioneer can add
    if user.id not in [auction.host_id, auction.auctioneer_id]:
        await update.message.reply_text("รฐลธลกยซ Only Host/Auctioneer can add players!")
        return
    
    # Get target user
    target_user = None
    
    if update.message.reply_to_message:
        target_user = update.message.reply_to_message.from_user
    elif context.args:
        arg = context.args[0]
        if arg.startswith("@"):
            username = arg[1:].lower()
            for uid, data in user_data.items():
                if data.get("username", "").lower() == username:
                    try:
                        target_user = await context.bot.get_chat(uid)
                    except:
                        pass
                    break
        elif arg.isdigit():
            try:
                target_user = await context.bot.get_chat(int(arg))
            except:
                pass
    
    if not target_user:
        await update.message.reply_text(
            "รขโยนรฏยธย <b>Usage:</b>\n"
            "Reply: <code>/addauctionplayer</code>\n"
            "Username: <code>/addauctionplayer @username</code>\n"
            "ID: <code>/addauctionplayer 123456789</code>",
            parse_mode=ParseMode.HTML
        )
        return
    
    # Check if already in pool or sold
    if any(p["player_id"] == target_user.id for p in auction.player_pool):
        await update.message.reply_text("รขลกย รฏยธย Player already in auction pool!")
        return
    
    if any(p["player_id"] == target_user.id for p in auction.sold_players):
        await update.message.reply_text("รขลกย รฏยธย Player already sold!")
        return
    
    # Initialize if new user
    if target_user.id not in user_data:
        user_data[target_user.id] = {
            "user_id": target_user.id,
            "username": target_user.username or "",
            "first_name": target_user.first_name,
            "started_at": datetime.now().isoformat(),
            "total_matches": 0
        }
        init_player_stats(target_user.id)
        save_data()
    
    # Base price selection
    keyboard = [
        [InlineKeyboardButton("รฐลธโยฐ 10", callback_data=f"midauc_base_10_{target_user.id}"),
         InlineKeyboardButton("รฐลธโยฐ 20", callback_data=f"midauc_base_20_{target_user.id}")],
        [InlineKeyboardButton("รฐลธโยฐ 30", callback_data=f"midauc_base_30_{target_user.id}"),
         InlineKeyboardButton("รฐลธโยฐ 50", callback_data=f"midauc_base_50_{target_user.id}")]
    ]
    
    target_tag = get_user_tag(target_user)
    
    await update.message.reply_text(
        f"รขลพโข <b>Adding Player to Auction</b>\n"
        f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
        f"รฐลธโยค {target_tag}\n\n"
        f"รฐลธโยฐ Select Base Price:",
        reply_markup=InlineKeyboardMarkup(keyboard),
        parse_mode=ParseMode.HTML
    )


async def midauc_base_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle mid-auction player base price"""
    query = update.callback_query
    await query.answer()
    
    chat = query.message.chat
    
    if chat.id not in active_auctions:
        return
    
    auction = active_auctions[chat.id]
    
    # Parse callback data
    try:
        parts = query.data.split("_")
        price = int(parts[2])
        player_id = int(parts[3])
    except:
        return
    
    # Get player info
    player_info = user_data.get(player_id)
    if not player_info:
        await query.message.edit_text("รขยล Player not found!")
        return
    
    # Add to pool
    auction.player_pool.append({
        "player_id": player_id,
        "player_name": player_info["first_name"],
        "base_price": price
    })
    
    player_tag = f'<a href=\"tg://user?id={player_id}\">{player_info['first_name']}</a>'
    
    await query.message.edit_text(
        f"รขลโฆ <b>Player Added to Pool!</b>\n"
        f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
        f"รฐลธโยค {player_tag}\n"
        f"รฐลธโยฐ Base Price: {price}\n\n"
        f"รฐลธโล  Total in Pool: {len(auction.player_pool)}",
        parse_mode=ParseMode.HTML
    )


# 2รฏยธยรขฦยฃ REMOVE PLAYER FROM AUCTION
async def removeauctionplayer_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    รขลพโ Remove player from auction pool
    Usage: Reply to user with /removeauctionplayer
    """
    chat = update.effective_chat
    user = update.effective_user
    
    if chat.id not in active_auctions:
        await update.message.reply_text("รขยล No active auction!")
        return
    
    auction = active_auctions[chat.id]
    
    # Only host/auctioneer
    if user.id not in [auction.host_id, auction.auctioneer_id]:
        await update.message.reply_text("รฐลธลกยซ Only Host/Auctioneer can remove players!")
        return
    
    # Cannot remove during live bidding
    if auction.phase == AuctionPhase.AUCTION_LIVE and auction.current_player_id:
        await update.message.reply_text("รขลกย รฏยธย Cannot remove player during active bidding!")
        return
    
    # Get target
    target_id = None
    
    if update.message.reply_to_message:
        target_id = update.message.reply_to_message.from_user.id
    elif context.args:
        arg = context.args[0]
        if arg.startswith("@"):
            username = arg[1:].lower()
            for uid, data in user_data.items():
                if data.get("username", "").lower() == username:
                    target_id = uid
                    break
        elif arg.isdigit():
            target_id = int(arg)
    
    if not target_id:
        await update.message.reply_text(
            "รขโยนรฏยธย <b>Usage:</b>\n"
            "Reply: <code>/removeauctionplayer</code>\n"
            "Username: <code>/removeauctionplayer @username</code>",
            parse_mode=ParseMode.HTML
        )
        return
    
    # Find and remove
    found = False
    for i, p in enumerate(auction.player_pool):
        if p["player_id"] == target_id:
            removed = auction.player_pool.pop(i)
            found = True
            
            await update.message.reply_text(
                f"รขลพโ <b>Player Removed!</b>\n"
                f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
                f"รฐลธโยค {removed['player_name']}\n"
                f"รฐลธโยฐ Base: {removed['base_price']}\n\n"
                f"รฐลธโล  Remaining in Pool: {len(auction.player_pool)}",
                parse_mode=ParseMode.HTML
            )
            break
    
    if not found:
        await update.message.reply_text("รขลกย รฏยธย Player not found in auction pool!")


# 3รฏยธยรขฦยฃ ADD/REMOVE PURSE
async def addpurse_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    รฐลธโยฐ Add money to team purse
    Usage: /addpurse [team_name] [amount]
    """
    chat = update.effective_chat
    user = update.effective_user
    
    if chat.id not in active_auctions:
        await update.message.reply_text("รขยล No active auction!")
        return
    
    auction = active_auctions[chat.id]
    
    # Only host
    if user.id != auction.host_id:
        await update.message.reply_text("รฐลธลกยซ Only Host can modify purse!")
        return
    
    if len(context.args) < 2:
        await update.message.reply_text(
            "รขโยนรฏยธย <b>Usage:</b>\n"
            "<code>/addpurse [TeamName] [Amount]</code>\n\n"
            "<b>Example:</b>\n"
            "<code>/addpurse Mumbai Indians 100</code>",
            parse_mode=ParseMode.HTML
        )
        return
    
    try:
        amount = int(context.args[-1])
        team_name = " ".join(context.args[:-1])
    except:
        await update.message.reply_text("รขยล Invalid amount!")
        return
    
    if team_name not in auction.teams:
        await update.message.reply_text(f"รขยล Team '{team_name}' not found!")
        return
    
    team = auction.teams[team_name]
    team.purse_remaining += amount
    
    await update.message.reply_text(
        f"รฐลธโยฐ <b>Purse Updated!</b>\n"
        f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
        f"รฐลธยย <b>Team:</b> {team_name}\n"
        f"รขลพโข <b>Added:</b> {amount}\n"
        f"รฐลธโยต <b>New Balance:</b> {team.purse_remaining}",
        parse_mode=ParseMode.HTML
    )


