async def process_solo_turn_result(context, chat_id, match):
    """Calculates Solo result with FIXED Next Batsman flow"""
    batter = match.solo_players[match.current_solo_bat_idx]
    bowler = match.solo_players[match.current_solo_bowl_idx]
    bat_num = match.current_ball_data["batsman_number"]
    bowl_num = match.current_ball_data["bowler_number"]
    
    bat_tag = f'<a href=\"tg://user?id={batter.user_id}\">{batter.first_name}</a>'
    bowl_tag = f'<a href=\"tg://user?id={bowler.user_id}\">{bowler.first_name}</a>'

    # --- MAGIC BALL MODE INTERCEPTION ---
    is_wicket = (bat_num == bowl_num)
    runs = bat_num
    magic_msg = None

    if getattr(match, "game_mode", None) == "MAGICBALL":
        match_context = {
            "match": match,
            "batter": batter,
            "bowler": bowler,
            "batsman_num": bat_num,
            "bowler_num": bowl_num
        }
        magic_ball_result = await process_magic_ball(bat_num, bowl_num, match_context)
        if magic_ball_result and magic_ball_result.get("magic_type"):
            # 1. Handle Rewind (ball doesn't count, re-bowl)
            if magic_ball_result.get("special_flag") == "rewind":
                msg = magic_ball_result.get("message", "รขยยฎรฏยธย Rewind triggered!")
                try:
                    await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML)
                except Exception:
                    pass
                match.current_ball_data = {}
                await trigger_solo_ball(context, chat_id, match)
                return

            # 2. Handle Ghost / Reveal Delay
            if magic_ball_result.get("reveal_delay", 0) > 0:
                msg = magic_ball_result.get("message", "")
                try:
                    await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML)
                except Exception:
                    pass
                await asyncio.sleep(magic_ball_result["reveal_delay"])
                
                rev_msg = magic_ball_result.get("reveal_message", "")
                if rev_msg:
                    try:
                        await context.bot.send_message(chat_id, rev_msg, parse_mode=ParseMode.HTML)
                    except Exception:
                        pass
            
            # Override outputs
            is_wicket = magic_ball_result.get("is_wicket", False)
            runs = magic_ball_result.get("runs", 0)
            magic_msg = magic_ball_result.get("message")

    # --- 1. WICKET LOGIC ---
    if is_wicket:
        batter.is_out = True
        match.solo_balls_this_spell = 0
        
        # Hat-trick tracking
        if not hasattr(match, 'solo_consecutive_wickets'):
            match.solo_consecutive_wickets = {}
        bowler_key = bowler.user_id
        match.solo_consecutive_wickets[bowler_key] = match.solo_consecutive_wickets.get(bowler_key, 0) + 1
        hat_trick = match.solo_consecutive_wickets[bowler_key] >= 3
        
        gif = get_random_gif(MatchEvent.WICKET)
        commentary = await get_ai_commentary_async("wicket", gc_settings.get(chat_id, {}).get("commentary_style", registered_groups.get(chat_id, {}).get("commentary_style", "english")))
        sr = round((batter.runs / max(batter.balls_faced, 1)) * 100, 1)
        
        msg = f"รขยล <b>OUT! {batter.first_name} is gone!</b>\n"
        msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        if magic_msg:
            msg += f"รฐลธโยฎ {magic_msg}\nรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        msg += f"รฐลธยย <b>Final Score:</b> {batter.runs} ({batter.balls_faced})\n"
        msg += f"รฐลธโยฌ <i>{commentary}</i>"

        try:
            if gif: await context.bot.send_animation(chat_id, gif, caption=msg, parse_mode=ParseMode.HTML)
            else: await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML)
        except:
            await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML)
        
        # รฐลธลฝยฉ Hat-trick celebration
        if hat_trick:
            ht_msg = (
                f"รฐลธลฝยฉรฃโฌโ <b>HAT-TRICK!</b> รฃโฌโขรฐลธลฝยฉ\n\n"
                f"รฐลธโยฅ <b>{bowler.first_name}</b> takes 3 consecutive wickets!\n"
                f"รฐลธยย <i>Unbelievable bowling display!</i>"
            )
            try:
                ht_gif = "https://media.tenor.com/HpTnkTq6h2IAAAAC/cricket-hattrick.gif"
                await context.bot.send_animation(chat_id, ht_gif, caption=ht_msg, parse_mode=ParseMode.HTML)
            except:
                await context.bot.send_message(chat_id, ht_msg, parse_mode=ParseMode.HTML)
            match.solo_consecutive_wickets[bowler_key] = 0  # Reset after hat-trick
        match.current_solo_bat_idx += 1
        
        # Check if ALL OUT
        if match.current_solo_bat_idx >= len(match.solo_players):
            await end_solo_game_logic(context, chat_id, match)
            return

        # Assign New Bowler (Batsman ke next wala)
        match.current_solo_bowl_idx = (match.current_solo_bat_idx + 1) % len(match.solo_players)
        new_batter = match.solo_players[match.current_solo_bat_idx]
        new_bat_tag = f'<a href=\"tg://user?id={new_batter.user_id}\">{new_batter.first_name}</a>'
        
        await asyncio.sleep(2)
        await context.bot.send_message(
            chat_id, 
            f"รขลกยก <b>NEXT BATSMAN:</b> {new_bat_tag} walks to the crease!\n<i>Game resuming...</i>", 
            parse_mode=ParseMode.HTML
        )
        
        # รขลโฆ CRITICAL FIX: Naya ball trigger karna zaroori hai
        await asyncio.sleep(2)
        await trigger_solo_ball(context, chat_id, match)
        return

    # --- 2. RUNS LOGIC ---
    else:
        batter.runs += runs
        batter.balls_faced += 1
        
        # Reset consecutive wickets for this bowler (scored off)
        if not hasattr(match, 'solo_consecutive_wickets'):
            match.solo_consecutive_wickets = {}
        match.solo_consecutive_wickets[bowler.user_id] = 0
        
        # Map Run Events to GIFs
        events = {0: MatchEvent.DOT_BALL, 1: MatchEvent.RUNS_1, 2: MatchEvent.RUNS_2, 
                  3: MatchEvent.RUNS_3, 4: MatchEvent.RUNS_4, 5: MatchEvent.RUNS_5, 6: MatchEvent.RUNS_6}
        comm_keys = {0: "dot", 1: "single", 2: "double", 3: "triple", 4: "boundary", 5: "five", 6: "six"}
        
        gif = get_random_gif(events.get(runs, MatchEvent.DOT_BALL))
        commentary = await get_ai_commentary_async(comm_keys.get(runs, "dot"), gc_settings.get(chat_id, {}).get("commentary_style", registered_groups.get(chat_id, {}).get("commentary_style", "english")))
        sr = round((batter.runs / batter.balls_faced) * 100, 1)

        msg = f"รฐลธโยด <b>LIVE</b>\n"
        msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        if magic_msg:
            msg += f"รฐลธโยฎ {magic_msg}\nรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        msg += f"รฐลธยย <b>{runs} RUN{'S' if runs != 1 else ''}!</b>\n"
        msg += f"รฐลธโยฌ <i>{commentary}</i>\n"
        msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        msg += f"รฐลธโล  <b>{batter.first_name}:</b> {batter.runs} ({batter.balls_faced})\n"
        msg += f"รขลกยก <b>Strike Rate:</b> {sr}"

        try:
            if gif: await context.bot.send_animation(chat_id, gif, caption=msg, parse_mode=ParseMode.HTML)
            else: await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML)
        except:
            await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML)

        # Over/Spell Rotation (Every 3 balls)
        match.solo_balls_this_spell += 1

        # รขโโฌรขโโฌ รฐลธลฝโฐ MILESTONE CELEBRATIONS รขโโฌรขโโฌ
        prev_runs = batter.runs - runs
        # Fifty celebration
        if prev_runs < 50 and batter.runs >= 50 and batter.runs < 100:
            fifty_gifs = [
                "https://media.tenor.com/UBE1qWoTtLAAAAAC/cricket-fifty.gif",
                "https://media.tenor.com/xtBFMdQjRwUAAAAC/cricket-celebration.gif"
            ]
            cel_msg = (
                f"รฐลธลลธรฃโฌโ <b>FIFTY!</b> รฃโฌโขรฐลธลลธ\n\n"
                f"รฐลธยย <b>{batter.first_name}</b> reaches <b>50 runs</b>!\n"
                f"รฐลธโล  {batter.runs} ({batter.balls_faced})  SR: {sr}\n"
                f"รฐลธลฝโฐ <i>Half-century milestone!</i>"
            )
            try:
                await context.bot.send_animation(chat_id, random.choice(fifty_gifs), caption=cel_msg, parse_mode=ParseMode.HTML)
            except:
                await context.bot.send_message(chat_id, cel_msg, parse_mode=ParseMode.HTML)
        # Hundred celebration
        elif prev_runs < 100 and batter.runs >= 100:
            hundred_gifs = [
                "https://media.tenor.com/BK2xfqEUiGoAAAAC/cricket-century.gif",
                "https://media.tenor.com/xtBFMdQjRwUAAAAC/cricket-celebration.gif"
            ]
            cel_msg = (
                f"รฐลธโยฏรฃโฌโ <b>CENTURY!</b> รฃโฌโขรฐลธโยฏ\n\n"
                f"รฐลธยย <b>{batter.first_name}</b> reaches <b>100 runs</b>!\n"
                f"รฐลธโล  {batter.runs} ({batter.balls_faced})  SR: {sr}\n"
                f"รฐลธลฝล  <i>What a magnificent hundred!</i>"
            )
            try:
                await context.bot.send_animation(chat_id, random.choice(hundred_gifs), caption=cel_msg, parse_mode=ParseMode.HTML)
            except:
                await context.bot.send_message(chat_id, cel_msg, parse_mode=ParseMode.HTML)
        if match.solo_balls_this_spell >= 3:
            match.solo_balls_this_spell = 0
            old_idx = match.current_solo_bowl_idx
            next_idx = (old_idx + 1) % len(match.solo_players)
            
            # Bowler cannot be the current Batsman
            if next_idx == match.current_solo_bat_idx:
                next_idx = (next_idx + 1) % len(match.solo_players)
            
            match.current_solo_bowl_idx = next_idx
            new_bowler = match.solo_players[next_idx]
            
            await asyncio.sleep(1)
            await context.bot.send_message(
                chat_id, 
                f"รฐลธโโ <b>CHANGE OF OVER!</b>\nNew Bowler: <b>{new_bowler.first_name}</b> takes the ball.", 
                parse_mode=ParseMode.HTML
            )
            await asyncio.sleep(2)

        # Trigger Next Ball
        await trigger_solo_ball(context, chat_id, match)

# --- NEW: Solo Callback Handler ---
async def solo_join_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle Solo Join/Leave AND Start Game - WITH TIMER"""
    query = update.callback_query
    await query.answer()
    chat = query.message.chat
    user = query.from_user
    
    if chat.id not in active_matches: return
    match = active_matches[chat.id]
    
    # --- ACTION: START GAME ---
    if query.data == "solo_start_game":
        # 1. Check Permissions (Host Only)
        if user.id != match.host_id:
            await query.answer("รขลกย รฏยธย Only the Host can start the match!", show_alert=True)
            return
            
        # 2. Check Player Count
        if len(match.solo_players) < 2:
            await query.answer("รขลกย รฏยธย Need at least 2 players to start!", show_alert=True)
            return

        # 3. Cancel Timer Task before starting
        if hasattr(match, 'solo_timer_task') and match.solo_timer_task:
            match.solo_timer_task.cancel()

        # 4. Start the Game Logic
        await start_solo_mechanics(context, chat.id, match)
        return

    # --- VALIDATION FOR JOIN/LEAVE ---
    if match.game_mode not in ["SOLO", "MAGICBALL"] or match.phase != GamePhase.SOLO_JOINING:
        await query.answer("Registration Closed!", show_alert=True)
        return

    user_tag = f'<a href=\"tg://user?id={user.id}\">{user.first_name}</a>'

    # --- ACTION: JOIN ---
    if query.data == "solo_join":
        # Check duplicate
        for p in match.solo_players:
            if p.user_id == user.id:
                await query.answer("Already joined!", show_alert=True)
                return
        
        # Init Stats if new user
        if user.id not in player_stats: init_player_stats(user.id)
        
        # Add Player
        p = Player(user.id, user.username or "", user.first_name)
        match.solo_players.append(p)
        
        # Update the Board Image
        await update_solo_board(context, chat.id, match)
        
        # Send Tagged Message
        msg = f"รขลโฆ <b>{user_tag}</b> has entered the Battleground! รฐลธโยฅ"
        await context.bot.send_message(chat.id, msg, parse_mode=ParseMode.HTML)

    # --- ACTION: LEAVE ---
    elif query.data == "solo_leave":
        for i, p in enumerate(match.solo_players):
            if p.user_id == user.id:
                match.solo_players.pop(i)
                
                # Update the Board Image
                await update_solo_board(context, chat.id, match)
                
                # Send Tagged Message
                msg = f"รฐลธโโน <b>{user_tag}</b> chickened out and left."
                await context.bot.send_message(chat.id, msg, parse_mode=ParseMode.HTML)
                return
        
        await query.answer("You are not in the list.", show_alert=True)

async def solo_join_countdown(context, chat_id, match):
    """Background Timer for Solo Joining Phase - Auto Updates Board"""
    try:
        warning_sent = False
        while True:
            # Check if phase changed
            if match.phase != GamePhase.SOLO_JOINING:
                break

            remaining = match.solo_join_end_time - time.time()
            
            # 30 Seconds Warning
            if remaining <= 30 and remaining > 20 and not warning_sent:
                await context.bot.send_message(
                    chat_id, 
                    "รขยยฐ <b>LAST CALL!</b> 30 seconds left to join!\nรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\nรฐลธโโก Tap below NOW รขโ โ hurry up! รฐลธยย", 
                    parse_mode=ParseMode.HTML
                )
                warning_sent = True

            # Time Up
            if remaining <= 0:
                # Check minimum players
                if len(match.solo_players) < 2:
                    await context.bot.send_message(
                        chat_id,
                        "รขยล <b>Match Cancelled!</b>\nNot enough players joined.",
                        parse_mode=ParseMode.HTML
                    )
                    del active_matches[chat_id]
                else:
                    # Auto-start the game
                    await context.bot.send_message(
                        chat_id,
                        "รขยยฐ <b>Time's Up!</b> Starting match now...",
                        parse_mode=ParseMode.HTML
                    )
                    await start_solo_mechanics(context, chat_id, match)
                break
            
            # Wait 10 seconds before next update
            await asyncio.sleep(10)
            
            # Update Board
            if match.phase == GamePhase.SOLO_JOINING:
                await update_solo_board(context, chat_id, match)
            
    except asyncio.CancelledError:
        pass
    except Exception as e:
        logger.error(f"Solo timer error: {e}")

async def end_solo_game_logic(context, chat_id, match):
    """รขลโฆ FIXED: Solo End with GC Notification"""
    match.phase = GamePhase.MATCH_ENDED
    
    # รขลโฆ GENERATE AND SEND FINAL IMAGE FIRST
    try:
        await generate_solo_end_image_v2(context, chat_id, match)
    except Exception as e:
        logger.error(f"Error generating solo end image: {e}")
    
    await asyncio.sleep(2)
    
    sorted_players = sorted(match.solo_players, key=lambda x: x.runs, reverse=True)
    winner = sorted_players[0]
    
    # Save Stats
    for p in match.solo_players:
        init_player_stats(p.user_id)
        
        if p.user_id in player_stats:
            s = player_stats[p.user_id]["solo"]
            s["matches"] += 1
            s["runs"] += p.runs
            s["balls"] += p.balls_faced
            s["wickets"] += p.wickets
            s["sixes"]   = s.get("sixes", 0) + getattr(p, "sixes", 0)
            s["fours"]   = s.get("fours", 0) + getattr(p, "boundaries", 0)
            if p.runs >= 100: s["centuries"] = s.get("centuries", 0) + 1
            elif p.runs >= 50: s["fifties"]  = s.get("fifties", 0) + 1
            if p.runs == 0 and p.is_out: s["ducks"] += 1
            if p.runs > s.get("highest", 0): s["highest"] = p.runs
            if p.runs > s.get("high_score", 0): s["high_score"] = p.runs
            
            if p.user_id == winner.user_id: 
                s["wins"] += 1
            if p in sorted_players[:3]:
                s["top_3_finishes"] += 1
                
    save_data()


    # รขลโฆ 2. VICTORY GIF WITH DETAILED CARD
    winner_sr = round((winner.runs / winner.balls_faced) * 100, 1) if winner.balls_faced > 0 else 0
    winner_tag = f'<a href=\"tg://user?id={winner.user_id}\">{html.escape(winner.first_name)}</a>'
    
    msg = f"รฐลธยโ  <b>SOLO BATTLE CHAMPION</b> รฐลธยโ \n"
    msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
    msg += f"รฐลธโโ <b>WINNER: {winner_tag}</b>\n"
    msg += f"รฐลธโยฅ <b>Score:</b> {winner.runs} ({winner.balls_faced})\n"
    msg += f"รฐลธโยฅ <b>Strike Rate:</b> {winner_sr}\n"
    msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
    
    msg += "รฐลธโล  <b>FINAL LEADERBOARD</b>\n"
    msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
    medals = ["รฐลธยฅโก", "รฐลธยฅห", "รฐลธยฅโฐ"]
    
    for i, p in enumerate(sorted_players):
        rank_icon = medals[i] if i < 3 else f"<b>{i+1}.</b>"
        status = " (Not Out)" if not p.is_out else ""
        sr = round((p.runs / p.balls_faced) * 100, 1) if p.balls_faced > 0 else 0
        msg += f"{rank_icon} <b>{p.first_name}</b>: {p.runs}({p.balls_faced}) SR: {sr}{status}\n"
        
    msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ"

    # Try sending with PIL-generated top3 image as champion card
    try:
        top3_avatar_map = {}
        for p in sorted_players[:3]:
            top3_avatar_map[p.user_id] = await fetch_user_avatar_bytes(context, p.user_id)
        top3_bio = generate_solo_top3_image(sorted_players, top3_avatar_map)
        if top3_bio:
            await context.bot.send_photo(chat_id, photo=top3_bio, caption=msg, parse_mode=ParseMode.HTML)
            return
    except Exception as e:
        logger.error(f"Error sending solo end PIL photo: {e}")

    # Fallback to SOLO_END_PHOTO file_id
    try:
        await context.bot.send_photo(chat_id, photo=SOLO_END_PHOTO, caption=msg, parse_mode=ParseMode.HTML)
        return
    except Exception as e:
        logger.error(f"Error sending solo end photo: {e}")
    
    # Fallback to GIF
    victory_gif = get_random_gif(MatchEvent.VICTORY)
    try:
        if victory_gif:
            await context.bot.send_animation(chat_id, victory_gif, caption=msg, parse_mode=ParseMode.HTML)
        else:
            await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML)
    except:
        await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML)

async def endsolo_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """End solo match - ADMIN ONLY"""
    chat_id = update.effective_chat.id
    user_id = update.effective_user.id
    
    match = active_matches.get(chat_id)
    if not match:
        await update.message.reply_text("รขยล No active match in this group!")
        return
    
    if match.phase not in [GamePhase.SOLO_JOINING, GamePhase.SOLO_MATCH]:
        await update.message.reply_text("รขยล No solo match is running!")
        return
    
    # Check if user is admin
    try:
        member = await context.bot.get_chat_member(chat_id, user_id)
        is_admin = member.status in ['creator', 'administrator']
    except:
        is_admin = False
    
    if not is_admin and user_id != match.host_id:
        await update.message.reply_text("รขยล Only admins or host can end the solo match!")
        return
    
    # Show confirmation buttons
    keyboard = InlineKeyboardMarkup([
        [
            InlineKeyboardButton("รขลโฆ Yes, End Solo", callback_data=f"confirm_endsolo_{chat_id}"),
            InlineKeyboardButton("รขยล Cancel", callback_data="cancel_endsolo")
        ]
    ])
    
    await update.message.reply_text(
        "รขลกย รฏยธย Are you sure you want to end this solo match?\n\n"
        "รฐลธโล  Final results will be generated and stats will be saved.",
        reply_markup=keyboard
    )

# /extendsolo
async def extendsolo_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat = update.effective_chat
    if chat.id not in active_matches: return
    match = active_matches[chat.id]
    
    if match.game_mode not in ["SOLO", "MAGICBALL"] or match.phase != GamePhase.SOLO_JOINING:
        await update.message.reply_text("Can only extend during joining phase.")
        return

    try:
        sec = int(context.args[0])
        match.solo_join_end_time += sec
        await update.message.reply_text(f"รขลโฆ Extended by {sec} seconds!")
    except:
        await update.message.reply_text("Usage: /extendsolo <seconds>")


