async def testwin_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """DEBUG: Force test winner determination"""
    user = update.effective_user
    if user.id != OWNER_ID: return
    
    chat = update.effective_chat
    if chat.id not in active_matches:
        await update.message.reply_text("No active match")
        return
    
    match = active_matches[chat.id]
    
    # Force set phase and call winner determination
    match.phase = GamePhase.MATCH_ENDED
    await determine_match_winner(context, chat.id, match)
    """
    รขลโฆ COMPLETE FIX: Proper winner determination and message delivery
    """
    logger.info(f"รฐลธยโ  === DETERMINE WINNER START === Group: {group_id}")
    
    # Get teams
    first = match.batting_first
    second = match.get_other_team(first)
    
    logger.info(f"รฐลธโล  First Innings: {first.name} - {first.score}/{first.wickets}")
    logger.info(f"รฐลธโล  Second Innings: {second.name} - {second.score}/{second.wickets}")
    logger.info(f"รฐลธลฝยฏ Target: {match.target}")
    
    winner = None
    loser = None
    margin = ""
    
    # ==========================================
    # รฐลธยงยฎ WINNER CALCULATION (FIXED LOGIC)
    # ==========================================
    
    # Case 1: Second team chased the target
    if second.score >= match.target:
        winner = second
        loser = first
        
        # Calculate wickets remaining
        wickets_lost = second.wickets
        wickets_remaining = len(second.players) - 1 - wickets_lost  # Total - 1 (for partner) - lost
        wickets_remaining = max(0, wickets_remaining)
        
        margin = f"{wickets_remaining} Wicket{'s' if wickets_remaining != 1 else ''}"
        logger.info(f"รขลโฆ Winner: {winner.name} (Chased target)")
        
    # Case 2: Second team failed to chase
    elif first.score > second.score:
        winner = first
        loser = second
        runs_diff = first.score - second.score
        margin = f"{runs_diff} Run{'s' if runs_diff != 1 else ''}"
        logger.info(f"รขลโฆ Winner: {winner.name} (Defended target)")
        
    # Case 3: Tied match
    elif first.score == second.score:
        logger.info("รฐลธยคย Match is TIED!")
        
        tie_msg = (
            f"รฐลธยคย <b>MATCH TIED!</b> รฐลธยคย\n"
            f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
            f"Both teams scored: <b>{first.score}/{first.wickets}</b>\n\n"
            f"รฐลธลฝยฒ What a thrilling finish!\n"
            f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ"
        )
        
        await context.bot.send_message(group_id, tie_msg, parse_mode=ParseMode.HTML)
        
        # Update stats for tie
        await update_player_stats_after_match(match, None, None)
        await save_match_to_history(match, "TIE")
        
        # Cleanup
        try:
            if match.main_message_id:
                await context.bot.unpin_chat_message(chat_id=group_id, message_id=match.main_message_id)
        except: pass
        
        if group_id in active_matches:
            del active_matches[group_id]
        
        logger.info("รขลโฆ Tie match handled successfully")
        return
    
    # ==========================================
    # รขลโฆ VALIDATE WINNER EXISTS
    # ==========================================
    if not winner or not loser:
        logger.error("รขยล CRITICAL: Winner/Loser not determined!")
        await context.bot.send_message(
            group_id,
            "รขลกย รฏยธย <b>Error determining match result.</b>\nPlease contact support.",
            parse_mode=ParseMode.HTML
        )
        
        # Force cleanup
        if group_id in active_matches:
            del active_matches[group_id]
        return
    
    logger.info(f"รฐลธยโ  FINAL: Winner={winner.name}, Loser={loser.name}, Margin={margin}")
    
    # ==========================================
    # รฐลธโล  UPDATE STATS & HISTORY
    # ==========================================
    try:
        logger.info("รฐลธโยพ Saving stats...")
        await update_player_stats_after_match(match, winner, loser)
        await save_match_to_history(match, winner.name)
        update_h2h_stats(match)
        logger.info("รขลโฆ Stats saved successfully")
    except Exception as e:
        logger.error(f"รขยล Stats save error: {e}")
    
    # ==========================================
    # รฐลธลฝโฐ SEND VICTORY MESSAGE (GUARANTEED)
    # ==========================================
    try:
        logger.info("รฐลธโยข Sending victory message...")
        await send_victory_message(context, group_id, match, winner, loser, margin)
        await asyncio.sleep(4)
        logger.info("รขลโฆ Victory message sent")
    except Exception as e:
        logger.error(f"รขยล Victory message error: {e}")
        # Fallback simple message
        fallback_msg = (
            f"รฐลธยโ  <b>{winner.name.upper()} WON!</b> รฐลธยโ \n"
            f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
            f"Won by: <b>{margin}</b>\n\n"
            f"รฐลธโล  {first.name}: {first.score}/{first.wickets}\n"
            f"รฐลธโล  {second.name}: {second.score}/{second.wickets}\n"
            f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ"
        )
        await context.bot.send_message(group_id, fallback_msg, parse_mode=ParseMode.HTML)
        await asyncio.sleep(3)
    
    # ==========================================
    # รฐลธโโน SEND SCORECARD
    # ==========================================
    try:
        logger.info("รฐลธโล  Sending scorecard...")
        await send_final_scorecard(context, group_id, match)
        await asyncio.sleep(3)
        logger.info("รขลโฆ Scorecard sent")
    except Exception as e:
        logger.error(f"รขยล Scorecard error: {e}")
    
    # ==========================================
    # รฐลธลลธ SEND POTM
    # ==========================================
    try:
        logger.info("รขยญย Sending POTM...")
        await send_potm_message(context, group_id, match)
        logger.info("รขลโฆ POTM sent")
    except Exception as e:
        logger.error(f"รขยล POTM error: {e}")
    
    # ==========================================
    # รฐลธยงยน CLEANUP
    # ==========================================
    try:
        if match.main_message_id:
            await context.bot.unpin_chat_message(chat_id=group_id, message_id=match.main_message_id)
    except: pass
    
    if group_id in active_matches:
        del active_matches[group_id]
    
    logger.info("รฐลธยย Match ended successfully")
    logger.info(f"รฐลธยโ  === DETERMINE WINNER END ===\n")

async def send_final_scorecard(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """
    รฐลธโล  PREMIUM MATCH SCORECARD - Professional Design
    """
    
    first_innings = match.batting_first
    second_innings = match.get_other_team(first_innings)
    
    # Helper function for batting card
    def format_batting_card(team, innings_num):
        inn_label = "1st" if innings_num == 1 else "2nd"
        rr = round(team.score / max(team.overs, 0.1), 2)
        extras = getattr(team, 'extras', 0)
        card = f"รขโขยญรขโยรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        card += f"รขโฦ รฐลธยโ  {inn_label} INNINGS รขลพโ {html.escape(team.name)}\n"
        card += f"รขโฦ รฐลธโล  {team.score}/{team.wickets} ({format_overs(team.balls)} ) | รฐลธโห RR: {rr}\n"
        card += f"รขโฦ รขลกโรฏยธย Extras: {extras}\n"
        card += f"รขโยฃรขโยรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        card += f"รขโฦ รฐลธยย BATTING\n"

        batters = sorted([p for p in team.players if p.balls_faced > 0 or p.is_out],
                        key=lambda x: x.runs, reverse=True)
        for p in batters:
            sr = round((p.runs / max(p.balls_faced, 1)) * 100, 1)
            not_out = "*" if not p.is_out and p.balls_faced > 0 else ""
            card += f"รขโฦ รฐลธโยค {html.escape(p.first_name[:16])}{not_out} รขลพโ {p.runs} ({p.balls_faced}b)  |  SR: {sr}\n"

        card += f"รขโขยฐรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโย\n"
        return card

    # Helper function for bowling card
    def format_bowling_card(bowling_team, batting_team_name):
        card = f"รขโขยญรขโยรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        card += f"รขโฦ รฐลธยฅลฝ BOWLING\n"

        bowlers = sorted([p for p in bowling_team.players if p.balls_bowled > 0],
                        key=lambda x: (x.wickets, -x.runs_conceded), reverse=True)
        for p in bowlers:
            ov = format_overs(p.balls_bowled)
            econ = round(p.runs_conceded / max(p.balls_bowled / 6, 0.1), 2)
            card += f"รขโฦ รฐลธโยค {html.escape(p.first_name[:16])} รขลพโ {p.wickets}/{p.runs_conceded} ({ov} ) | รฐลธโโฐ Eco: {econ}\n"

        card += f"รขโขยฐรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโย\n"
        return card

    # Build Complete Scorecard
    msg = "รฐลธโล  Cricoverse Scorecard\n"
    msg += format_batting_card(first_innings, 1)
    msg += format_bowling_card(second_innings, first_innings.name)
    
    msg += "\nรขโขย รขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยฃ\n"
    # Second Innings
    msg += "<b>รฐลธโยธ SECOND INNINGS</b>\n\n"
    msg += format_batting_card(second_innings, 2)
    msg += format_bowling_card(first_innings, second_innings.name)
    msg += "\nรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
    
    # Match Result
    winner = None
    if second_innings.score >= match.target:
        winner = second_innings
        wickets_remaining = len(winner.players) - 1 - winner.wickets
        margin = f"{wickets_remaining} wicket{'s' if wickets_remaining != 1 else ''}"
    else:
        winner = first_innings
        margin = f"{first_innings.score - second_innings.score} runs"
    
    msg += f"รฐลธยโ  <b>RESULT:</b> {winner.name} won by {margin}\n\n"
    
    # Key Performances
    all_players = first_innings.players + second_innings.players
    
    # Top Scorer
    top_scorer = max([p for p in all_players if p.balls_faced > 0], 
                    key=lambda x: x.runs, default=None)
    if top_scorer:
        msg += f"รขยญย <b>Top Score:</b> {top_scorer.first_name} - {top_scorer.runs}({top_scorer.balls_faced})\n"
    
    # Best Bowler
    best_bowler = max([p for p in all_players if p.balls_bowled > 0], 
                     key=lambda x: (x.wickets, -x.runs_conceded), default=None)
    if best_bowler:
        msg += f"รฐลธลฝยฏ <b>Best Bowling:</b> {best_bowler.first_name} - {best_bowler.wickets}/{best_bowler.runs_conceded}\n"
    
    # Bug 4 Fix: Use worm graph as the OFFICIAL MATCH SCORECARD image instead of static photo
    # Remove separate worm graph message รขโ โ worm is embedded in the scorecard
    try:
        worm_bio = await asyncio.to_thread(generate_worm_graph, match)
        if worm_bio:
            first_innings = match.batting_first
            keyboard = InlineKeyboardMarkup([[
                InlineKeyboardButton("รขลพยกรฏยธย 2nd Innings", callback_data=f"scorecard_worm_{group_id}_2")
            ]])
            await context.bot.send_photo(
                group_id,
                photo=worm_bio,
                caption=msg,
                parse_mode=ParseMode.HTML,
                reply_markup=keyboard
            )
        else:
            raise Exception("Worm graph returned None")
    except Exception as worm_e:
        logger.warning(f"Worm graph for scorecard failed, using fallback: {worm_e}")
        try:
            await context.bot.send_photo(
                group_id,
                photo=MEDIA_ASSETS.get("scorecard"),
                caption=msg,
                parse_mode=ParseMode.HTML
            )
        except:
            await context.bot.send_message(group_id, msg, parse_mode=ParseMode.HTML)


# รขโขโรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขยรขโขโ
