def _build_mid_match_caption(match) -> str:
    """Build caption text for mid-match live score image."""
    bat_team  = match.current_batting_team
    bowl_team = match.current_bowling_team
    if not bat_team or not bowl_team:
        return "รฐลธโยด <b>LIVE</b>"
    caption = (
        f"รฐลธโยด <b>LIVE SCORE</b>\n"
        f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        f"รฐลธยย <b>{bat_team.name}:</b>  {bat_team.score}/{bat_team.wickets}  ({format_overs(bat_team.balls)} ov)\n"
    )
    if match.innings == 2 and match.target > 0:
        needed = match.target - bat_team.score
        bl = (match.total_overs * 6) - bat_team.balls
        rrr = round(needed / max(bl / 6, 0.1), 2)
        caption += f"รฐลธลฝยฏ Need <b>{needed}</b> off <b>{bl}b</b>  RRR: {rrr}\n"
    # Current bowler
    if bowl_team.current_bowler_idx is not None and bowl_team.current_bowler_idx < len(bowl_team.players):
        bowler = bowl_team.players[bowl_team.current_bowler_idx]
        caption += f"รขลกยก <b>Current Bowler:</b> {bowler.first_name}  {bowler.wickets}/{bowler.runs_conceded}  ({format_overs(bowler.balls_bowled)})\n"
    # Current batsmen
    striker = bat_team.players[bat_team.current_batsman_idx] if bat_team.current_batsman_idx is not None else None
    nonstriker = bat_team.players[bat_team.current_non_striker_idx] if bat_team.current_non_striker_idx is not None else None
    if striker:
        sr_s = round((striker.runs / max(striker.balls_faced, 1)) * 100, 1)
        caption += f"รฐลธยย <b>{striker.first_name}:</b> {striker.runs} ({striker.balls_faced})  SR: {sr_s}\n"
    if nonstriker:
        sr_n = round((nonstriker.runs / max(nonstriker.balls_faced, 1)) * 100, 1)
        caption += f"รฐลธโโ <b>{nonstriker.first_name}:</b> {nonstriker.runs} ({nonstriker.balls_faced})  SR: {sr_n}\n"
    if match.current_partnership_runs > 0:
        caption += f"รฐลธยคย <b>Partnership:</b> {match.current_partnership_runs} runs off {match.current_partnership_balls} balls"
    return caption




def _clean_display_name(name: str, max_len: int = 20) -> str:
    """
    Clean a Telegram display name for image rendering.
    Removes emojis, special symbols, designer/role tags, and limits length.
    Handles names like 'รฐลธลฝยจ Designer | John' รขโ โ 'John'
    or 'รขลกยก John รขลกยก' รขโ โ 'John'
    """
    import unicodedata
    import re
    # Remove emoji characters using unicode category check
    cleaned = ''.join(
        ch for ch in name
        if not (unicodedata.category(ch).startswith('So') or  # Symbol, other (many emoji)
                unicodedata.category(ch).startswith('Sm') or  # Symbol, math
                unicodedata.category(ch).startswith('Sk') or  # Symbol, modifier
                ord(ch) > 0x1F000)  # Emoji range
    )
    # Remove common role/designer tag patterns like "Designer |", "| Owner"
    cleaned = re.sub(r'[|/\\#@*_~`<>]', ' ', cleaned)
    # Collapse multiple spaces
    cleaned = re.sub(r'\s+', ' ', cleaned).strip()
    # If nothing left, fall back to original truncated
    if not cleaned:
        cleaned = re.sub(r'\s+', ' ', name).strip()[:max_len]
    return cleaned[:max_len]


def _draw_text_centered(draw, text, cx, y, font, fill):
    bbox = draw.textbbox((0, 0), text, font=font)
    w = bbox[2] - bbox[0]
    draw.text((cx - w // 2, y), text, font=font, fill=fill)


def _draw_gradient_rect(img_draw_tuple, x1, y1, x2, y2, color_top, color_bot):
    """Vertical gradient fill on a rectangle."""
    img, draw = img_draw_tuple
    h = y2 - y1
    if h <= 0:
        return
    for i in range(h):
        t = i / h
        r = int(color_top[0] + t * (color_bot[0] - color_top[0]))
        g = int(color_top[1] + t * (color_bot[1] - color_top[1]))
        b = int(color_top[2] + t * (color_bot[2] - color_top[2]))
        draw.line([(x1, y1 + i), (x2, y1 + i)], fill=(r, g, b))


async def send_photo_generation_status(update: Update, title: str, detail: str = "Rendering a smoother visual card."):
    """Small progress message used while heavier PIL cards are being generated."""
    try:
        if update.effective_chat:
            await update.effective_chat.send_action("upload_photo")
        return await update.message.reply_text(
            f"รฐลธลฝยจ <b>{title}</b>\n"
            f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
            f"รขโฌยข Calibrating layout\n"
            f"รขโฌยข Smoothing edges\n"
            f"รขโฌยข Polishing the final card\n\n"
            f"<i>{detail}</i>",
            parse_mode=ParseMode.HTML
        )
    except Exception:
        return None


async def fetch_user_avatar_bytes(context: ContextTypes.DEFAULT_TYPE, user_id: int) -> Optional[bytes]:
    """Fetch the user's largest Telegram profile photo, if available."""
    try:
        photos = await context.bot.get_user_profile_photos(user_id=user_id, limit=1)
        if not photos.total_count or not photos.photos:
            return None
        file_id = photos.photos[0][-1].file_id
        tg_file = await context.bot.get_file(file_id)
        data = await tg_file.download_as_bytearray()
        return bytes(data)
    except Exception as e:
        logger.info(f"Could not fetch profile photo for {user_id}: {e}")
        return None


def _circle_avatar(avatar_bytes: Optional[bytes], size: int, initials: str = "CV") -> Image.Image:
    """Return a circular RGBA avatar; falls back to initials."""
    avatar = Image.new("RGBA", (size, size), (24, 31, 58, 255))
    draw = ImageDraw.Draw(avatar)
    if avatar_bytes:
        try:
            src = Image.open(BytesIO(avatar_bytes)).convert("RGBA")
            src = ImageOps.fit(src, (size, size), method=Image.Resampling.LANCZOS)
            avatar = src
        except Exception:
            avatar = Image.new("RGBA", (size, size), (24, 31, 58, 255))
            draw = ImageDraw.Draw(avatar)

    if not avatar_bytes:
        for y in range(size):
            t = y / max(size - 1, 1)
            color = (
                int(32 + 28 * t),
                int(45 + 35 * t),
                int(90 + 45 * t),
                255,
            )
            draw.line([(0, y), (size, y)], fill=color)
        text = (initials or "CV")[:2].upper()
        font = _get_font(True, max(22, size // 4))
        bbox = draw.textbbox((0, 0), text, font=font)
        draw.text(((size - (bbox[2] - bbox[0])) / 2, (size - (bbox[3] - bbox[1])) / 2 - size * 0.04), text, font=font, fill=(245, 249, 255, 255))

    mask = Image.new("L", (size, size), 0)
    ImageDraw.Draw(mask).ellipse((0, 0, size - 1, size - 1), fill=255)
    out = Image.new("RGBA", (size, size), (0, 0, 0, 0))
    out.paste(avatar, (0, 0), mask)
    ring = Image.new("RGBA", (size, size), (0, 0, 0, 0))
    rdraw = ImageDraw.Draw(ring)
    rdraw.ellipse((3, 3, size - 4, size - 4), outline=(255, 211, 80, 255), width=max(4, size // 28))
    out.alpha_composite(ring)
    return out


def _clean_display_name(name: str, max_len: int = 15) -> str:
    """Helper to keep player names from breaking the layout."""
    clean = name.strip()
    return clean[:max_len] + "..." if len(clean) > max_len else clean

def _create_avatar_image(avatar_bytes: bytes, size: int, initials: str) -> Image.Image:
    """Helper to process the DP into a perfect circle, or fallback to initials."""
    result = Image.new("RGBA", (size, size), (0, 0, 0, 0))
    mask = Image.new("L", (size, size), 0)
    draw_mask = ImageDraw.Draw(mask)
    draw_mask.ellipse((0, 0, size, size), fill=255)
    
    if avatar_bytes:
        try:
            av = Image.open(BytesIO(avatar_bytes)).convert("RGBA")
            # Crop to square first to avoid stretching
            w, h = av.size
            min_side = min(w, h)
            left = (w - min_side) / 2
            top = (h - min_side) / 2
            av = av.crop((left, top, left + min_side, top + min_side))
            av = av.resize((size, size), Image.Resampling.LANCZOS)
            result.paste(av, (0, 0), mask=mask)
            return result
        except Exception as e:
            pass
            
    # Fallback if no DP: Dark circle with neon initials
    draw_fallback = ImageDraw.Draw(result)
    draw_fallback.ellipse((0, 0, size, size), fill=(20, 30, 50, 255))
    try:
        font = ImageFont.truetype("Roboto-Bold.ttf", int(size * 0.4))
    except:
        font = ImageFont.load_default(size=int(size * 0.4))
    
    # Center text
    bbox = draw_fallback.textbbox((0, 0), initials, font=font)
    tw = bbox[2] - bbox[0]
    th = bbox[3] - bbox[1]
    draw_fallback.text(((size - tw) / 2, (size - th) / 2 - (size * 0.05)), initials, font=font, fill=(0, 229, 255, 255))
    result.putalpha(mask)
    return result

async def fetch_overall_stats_snapshot(user_id: int, name: str, stats: dict, avatar_bytes: bytes = None, mode: str = "overall") -> BytesIO:
    """
    ULTIMATE GOD-LEVEL CRICKET CARD
    Features: Deep night theme, stadium neon glows, player DP, frosted glass panels.
    """
    try:
        SC = 2  # Super-sampling scale for high resolution
        W, H = 1200 * SC, 740 * SC
        img = Image.new("RGBA", (W, H), (8, 12, 24, 255)) # Deepest Night Blue
        draw = ImageDraw.Draw(img, "RGBA")

        # รขโโฌรขโโฌ 1. STADIUM FLOODLIGHT GLOWS (Background Effects) รขโโฌรขโโฌ
        glow_layer = Image.new("RGBA", (W, H), (0, 0, 0, 0))
        glow_draw = ImageDraw.Draw(glow_layer)
        
        # Neon Cyan Glow (Top Left behind DP)
        glow_draw.ellipse((-300*SC, -300*SC, 600*SC, 600*SC), fill=(0, 229, 255, 30))
        # Neon Green/Purple Glow (Bottom Right)
        glow_draw.ellipse((W - 500*SC, H - 400*SC, W + 300*SC, H + 400*SC), fill=(57, 255, 20, 20))
        
        glow_layer = glow_layer.filter(ImageFilter.GaussianBlur(150))
        img.paste(glow_layer, (0, 0), glow_layer)

        # รขโโฌรขโโฌ COLORS & FONTS รขโโฌรขโโฌ
        WHITE = (255, 255, 255, 255)
        MUTED = (148, 163, 184, 255)
        CYAN  = (0, 229, 255, 255)
        GREEN = (57, 255, 20, 255)
        RED   = (255, 60, 90, 255)
        GLASS_PANEL = (20, 30, 45, 180) 
        GLASS_OUTLINE = (0, 229, 255, 60)

        # Attempt to use local fonts, fallback to default
        try:
            f_title = ImageFont.truetype("Roboto-Bold.ttf", 62 * SC)
            f_label = ImageFont.truetype("Roboto-Regular.ttf", 20 * SC)
            f_value = ImageFont.truetype("Roboto-Bold.ttf", 44 * SC)
            f_small = ImageFont.truetype("Roboto-Regular.ttf", 22 * SC)
            f_mode  = ImageFont.truetype("Roboto-Bold.ttf", 26 * SC)
        except:
            f_title = ImageFont.load_default(size=62 * SC)
            f_label = ImageFont.load_default(size=20 * SC)
            f_value = ImageFont.load_default(size=44 * SC)
            f_small = ImageFont.load_default(size=22 * SC)
            f_mode  = ImageFont.load_default(size=26 * SC)

        # รขโโฌรขโโฌ 2. WATERMARK (Crossed Bats) รขโโฌรขโโฌ
        def _draw_bats(cx, cy, size, alpha):
            w_color = (255, 255, 255, alpha)
            hw, bw = int(3 * SC), int(10 * SC)
            # Bat 1
            draw.line([(cx - size//2, cy - size//2), (cx - size//8, cy - size//8)], fill=w_color, width=hw)
            draw.line([(cx - size//8, cy - size//8), (cx + size//2, cy + size//2)], fill=w_color, width=bw)
            # Bat 2
            draw.line([(cx + size//2, cy - size//2), (cx + size//8, cy - size//8)], fill=w_color, width=hw)
            draw.line([(cx + size//8, cy - size//8), (cx - size//2, cy + size//2)], fill=w_color, width=bw)

        _draw_bats(W - 250*SC, 200*SC, 220*SC, 8)

        # รขโโฌรขโโฌ 3. OUTER CARD FRAME รขโโฌรขโโฌ
        draw.rounded_rectangle([30*SC, 30*SC, W-30*SC, H-30*SC], radius=30*SC, outline=GLASS_OUTLINE, width=2*SC)

        # รขโโฌรขโโฌ 4. HEADER DETAILS รขโโฌรขโโฌ
        header_txt = "รฐลธยย CRICORA ULTIMATE  |  " + mode.upper() + " STATS"
        draw.text((60*SC, 50*SC), header_txt, font=f_mode, fill=CYAN)
        draw.line([(60*SC, 90*SC), (W-60*SC, 90*SC)], fill=(255, 255, 255, 30), width=1*SC)

        # รขโโฌรขโโฌ 5. PLAYER DP (AVATAR) WITH NEON RING รขโโฌรขโโฌ
        av_size = 200 * SC
        initials = "".join(part[:1] for part in (name or "P").split()[:2]).upper()
        avatar = _create_avatar_image(avatar_bytes, av_size, initials)
        
        av_x, av_y = 60 * SC, 130 * SC
        img.alpha_composite(avatar, (av_x, av_y))

        # Multiple Neon Glowing Rings around DP
        draw.ellipse([av_x-4*SC, av_y-4*SC, av_x+av_size+4*SC, av_y+av_size+4*SC], outline=CYAN, width=3*SC)
        draw.ellipse([av_x-12*SC, av_y-12*SC, av_x+av_size+12*SC, av_y+av_size+12*SC], outline=(0, 229, 255, 50), width=1*SC)

        # รขโโฌรขโโฌ 6. PLAYER NAME & SUMMARY รขโโฌรขโโฌ
        text_x = 310 * SC
        safe_name = _clean_display_name(name or "Player", 18).upper()
        draw.text((text_x, 140*SC), safe_name, font=f_title, fill=WHITE)
        draw.text((text_x, 220*SC), f"ID: {user_id}", font=f_small, fill=MUTED)

        # Win/Loss Pill
        matches = stats.get("matches", 0)
        wins    = stats.get("wins", 0)
        losses  = stats.get("losses", max(matches - wins, 0))
        win_rate = stats.get("win_rate", 0)
        
        draw.rounded_rectangle([text_x, 260*SC, text_x + 280*SC, 320*SC], radius=15*SC, fill=GLASS_PANEL, outline=GLASS_OUTLINE, width=1*SC)
        wl_color = GREEN if wins >= losses else RED
        draw.text((text_x + 20*SC, 275*SC), f"{wins}W - {losses}L", font=f_value, fill=wl_color)
        draw.text((text_x + 190*SC, 282*SC), f"{win_rate}%", font=f_small, fill=MUTED)

        # Form tracker
        form = stats.get("form", [])
        if form:
            fx = text_x + 310*SC
            draw.text((fx, 270*SC), "FORM:", font=f_label, fill=MUTED)
            fx += 80*SC
            for res in form[-5:]:
                fc = GREEN if res == "W" else RED
                draw.ellipse([fx, 275*SC, fx+16*SC, 291*SC], fill=fc)
                fx += 24*SC

        # รขโโฌรขโโฌ 7. GLASS STATS GRID (4x2) รขโโฌรขโโฌ
        # Extract variables safely
        runs = stats.get("runs", 0)
        hs = stats.get("highest", 0)
        avg = stats.get("average", 0)
        sr = stats.get("strike_rate", 0)
        wickets = stats.get("wickets", 0)
        fours = stats.get("fours", 0)
        sixes = stats.get("sixes", 0)
        mom = stats.get("mom", 0)

        stat_cards = [
            ("TOTAL MATCHES", str(matches), CYAN),
            ("TOTAL RUNS", str(runs), GREEN),
            ("HIGHEST SCORE", f"{hs}*", WHITE),
            ("STRIKE RATE", f"{sr}", CYAN),
            ("BATTING AVG", str(avg), WHITE),
            ("TOTAL WICKETS", str(wickets), GREEN),
            ("BOUNDARIES (4s/6s)", f"{fours} / {sixes}", WHITE),
            ("POTM AWARDS", str(mom), CYAN),
        ]

        grid_y = 390 * SC
        card_w, card_h = 250 * SC, 110 * SC
        gap_x, gap_y = 22 * SC, 22 * SC
        start_x = 60 * SC

        for i, (label, value, color) in enumerate(stat_cards):
            col = i % 4
            row = i // 4
            x1 = start_x + col * (card_w + gap_x)
            y1 = grid_y + row * (card_h + gap_y)
            
            # Draw Glass Tile
            draw.rounded_rectangle([x1, y1, x1+card_w, y1+card_h], radius=16*SC, fill=GLASS_PANEL, outline=(255,255,255,20), width=1*SC)
            
            # Left edge neon accent
            draw.rounded_rectangle([x1, y1, x1+6*SC, y1+card_h], radius=6*SC, fill=color)
            
            # Text layout inside tile
            draw.text((x1 + 24*SC, y1 + 18*SC), str(value), font=f_value, fill=WHITE)
            draw.text((x1 + 24*SC, y1 + 72*SC), label, font=f_label, fill=MUTED)

        # รขโโฌรขโโฌ 8. FOOTER รขโโฌรขโโฌ
        footer_y = H - 80*SC
        draw.line([(60*SC, footer_y), (W-60*SC, footer_y)], fill=(255, 255, 255, 30), width=1*SC)
        
        brand_txt = "รขลกยก POWERED BY CRICORA ENGINE"
        bb = draw.textbbox((0,0), brand_txt, font=f_small)
        draw.text(((W - (bb[2]-bb[0]))//2, footer_y + 20*SC), brand_txt, font=f_small, fill=CYAN)

        # รขโโฌรขโโฌ 9. FINALIZE & EXPORT รขโโฌรขโโฌ
        final = img.convert("RGB").resize((1200, 740), Image.Resampling.LANCZOS)
        bio = BytesIO()
        final.save(bio, "PNG", optimize=True)
        bio.seek(0)
        return bio
        
    except Exception as e:
        import logging
        logging.getLogger(__name__).error("God-Level Stats image generation error: " + str(e))
        return None

# รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ
