def generate_mom_speech(player_name: str, runs: int, wickets: int, match_name: str = "") -> str:
    """Generate a random funny MOM acceptance speech personalised to the player."""
    speech = random.choice(_MOM_SPEECHES)
    intro = f"รฐลธลฝยค <b>{player_name}'s Acceptance Speech</b>\n"
    intro += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
    intro += f"<i>\"{speech}\"</i>\n\n"
    intro += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
    intro += f"รฐลธลลธ <b>Man of the Match</b> รขโ โ {player_name}\n"
    if runs > 0:
        intro += f"รฐลธยย {runs} runs"
    if wickets > 0:
        intro += f"  รขลกยพ {wickets} wickets"
    return intro

