async def start_auction_live_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """รฐลธลฝยฏ Start auction live callback"""
    query = update.callback_query
    await query.answer()
    
    chat = query.message.chat
    
    if chat.id not in active_auctions:
        await query.answer("รขยล No active auction!", show_alert=True)
        return
    
    auction = active_auctions[chat.id]
    
    # Validate before starting
    if not auction.auctioneer_id:
        await query.answer("รขลกย รฏยธย Please select an auctioneer first!", show_alert=True)
        return
    
    if len(auction.teams) < 2:
        await query.answer("รขลกย รฏยธย Need at least 2 teams!", show_alert=True)
        return
    
    if len(auction.player_pool) == 0:
        await query.answer("รขลกย รฏยธย Add players first using /aucplayer!", show_alert=True)
        return
    
    # Start auction
    auction.phase = AuctionPhase.AUCTION_LIVE
    
    await query.edit_message_text(
        text=(
            "รฐลธลฝยครฃโฌโ <b>AUCTION IS NOW LIVE!</b> รฃโฌโขรฐลธลฝยค\n\n"
            "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
            "  รฐลธโยจ BIDDING OPEN  \n"
            "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
            "รฐลธยฦรขโฌยรขโขโรฏยธย First player coming up any moment!\n"
            "รขลยจรฏยธย Use <code>/bid [amount]</code> to place bids!\n\n"
            "รฐลธยโฌ <i>May the best team win!</i>"
        ),
        parse_mode=ParseMode.HTML
    )
    
    # Start bringing players
    await asyncio.sleep(2)
    await bring_next_player(context, chat.id, auction)

