async def wallet_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """รฐลธโยฐ Show remaining purse"""
    chat = update.effective_chat
    if chat.id not in active_auctions:
        await update.message.reply_text("รฐลธลกยซ No active auction!", parse_mode=ParseMode.HTML)
        return
    auction = active_auctions[chat.id]
    msg = "รฐลธโยฐ <b>TEAM WALLETS</b>\n"
    msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
    sorted_teams = sorted(
        auction.teams.values(),
        key=lambda x: x.purse_remaining,
        reverse=True
    )
    for i, team in enumerate(sorted_teams, 1):
        emoji = "รฐลธยฅโก" if i == 1 else "รฐลธยฅห" if i == 2 else "รฐลธยฅโฐ" if i == 3 else "รฐลธยย"
        spent = 1000 - team.purse_remaining
        
        msg += f"{emoji} <b>{team.name}</b>\n"
        msg += f"รย  รย รฐลธโยฐ Purse: <b>{team.purse_remaining}</b>\n"
        msg += f"รย  รย รฐลธโยธ Spent: {spent}\n"
        msg += f"รย  รย รฐลธโยฅ Players: {len(team.players)}\n\n"
    msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ"
    await update.message.reply_text(msg, parse_mode=ParseMode.HTML)

