async def aucsummary_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """รฐลธโล  Show auction summary"""
    chat = update.effective_chat
    if chat.id not in active_auctions:
        await update.message.reply_text(
            "รขยล <b>NO ACTIVE AUCTION!</b>\n\n"
            "Start an auction first.",
            parse_mode=ParseMode.HTML
        )
        return
    auction = active_auctions[chat.id]
    msg = "รฐลธโล  <b>AUCTION SUMMARY</b>\n"
    msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
    for team_name, team in auction.teams.items():
        msg += f"รฐลธยย <b>{team_name}</b>\n"
        msg += f"รฐลธโยฐ <b>Purse:</b> {team.purse_remaining}/1000\n"
        msg += f"รฐลธโยฅ <b>Players:</b> {len(team.players)}\n\n"
        if team.players:
            msg += "<b>Squad:</b>\n"
            for p in team.players:
                msg += f" รขโฌยข {p['player_name']} (รฐลธโยฐ{p['price']})\n"
            msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
    msg += f"รฐลธโล  <b>Players in Pool:</b> {len(auction.player_pool)}\n"
    msg += f"รขยล <b>Unsold Players:</b> {len(auction.unsold_players)}"
    
    # Send with pagination if needed
    if len(msg) <= 4096:
        await update.message.reply_text(msg, parse_mode=ParseMode.HTML)
    else:
        # Split into chunks
        lines = msg.split("\n")
        chunk = ""
        for line in lines:
            if len(chunk) + len(line) + 1 > 4000:
                await update.message.reply_text(chunk, parse_mode=ParseMode.HTML)
                chunk = line + "\n"
            else:
                chunk += line + "\n"
        if chunk.strip():
            await update.message.reply_text(chunk, parse_mode=ParseMode.HTML)

async def end_auction(context: ContextTypes.DEFAULT_TYPE, chat_id: int, auction: Auction):
    """รฐลธยโ  End auction with COMPLETE SCORECARD"""
    auction.phase = AuctionPhase.AUCTION_ENDED
    # รฐลธลฝยฌ ENDING GIF
    end_gif = GIFS.get("auction_end")
    msg = (
        "รฐลธยโ  <b>AUCTION COMPLETE!</b>\n"
        "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
        "รฐลธลฝโฐ All players have been auctioned!\n\n"
        "รฐลธโล  Preparing Final Scorecard...\n\n"
        "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ"
    )
    try:
        await context.bot.send_animation(
            chat_id,
            animation=end_gif,
            caption=msg,
            parse_mode=ParseMode.HTML
        )
    except:
        await context.bot.send_photo(
            chat_id,
            photo=MEDIA_ASSETS.get("auction_end"),
            caption=msg,
            parse_mode=ParseMode.HTML
        )
    await asyncio.sleep(3)
    # รฐลธโโน COMPLETE SCORECARD
    scorecard = "รฐลธยโ  <b>AUCTION FINAL SCORECARD</b>\n"
    scorecard += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
    # Sort teams by total spent
    sorted_teams = sorted(
        auction.teams.values(),
        key=lambda x: x.total_spent,
        reverse=True
    )
    for i, team in enumerate(sorted_teams, 1):
        medal = "รฐลธยฅโก" if i == 1 else "รฐลธยฅห" if i == 2 else "รฐลธยฅโฐ" if i == 3 else f"{i}."
        scorecard += f"{medal} <b>{team.name}</b>\n"
        scorecard += f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        scorecard += f"รฐลธโยฐ <b>Spent:</b> {team.total_spent} | <b>Purse Left:</b> {team.purse_remaining}\n"
        scorecard += f"รฐลธโยฅ <b>Squad ({len(team.players)}):</b>\n\n"
        # Sort players by price
        sorted_players = sorted(team.players, key=lambda x: x['price'], reverse=True)
        for p in sorted_players:
            p_tag = f'<a href=\"tg://user?id={p['player_id']}\">{p['player_name']}</a>'
            scorecard += f" รขโฌยข {p_tag} - รฐลธโยฐ{p['price']}\n"
        scorecard += "\n"
    # รขยล UNSOLD SUMMARY
    if auction.unsold_players:
        scorecard += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        scorecard += f"รขยล <b>UNSOLD PLAYERS ({len(auction.unsold_players)}):</b>\n\n"
        # Show top 5 unsold
        for i, player_data in enumerate(auction.unsold_players[:5], 1):
            name = player_data if isinstance(player_data, str) else player_data.get('player_name', 'Unknown')
            scorecard += f" {i}. {name}\n"
        # If more unsold exist
        remaining = len(auction.unsold_players) - 5
        if remaining > 0:
            scorecard += f"\n ... and {remaining} more\n"
    scorecard += "\nรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
    scorecard += "รฐลธลฝโฐ <b>Thank you for participating!</b>"
    
    # Send with pagination if message is too long
    if len(scorecard) <= 4096:
        await context.bot.send_message(chat_id, scorecard, parse_mode=ParseMode.HTML)
    else:
        # Split by teams
        lines = scorecard.split("\n")
        chunk = ""
        page = 1
        for line in lines:
            if len(chunk) + len(line) + 1 > 4000:
                await context.bot.send_message(chat_id, chunk.rstrip(), parse_mode=ParseMode.HTML)
                chunk = f"<i>(continued...)</i>\n{line}\n"
                page += 1
            else:
                chunk += line + "\n"
        if chunk.strip():
            await context.bot.send_message(chat_id, chunk.rstrip(), parse_mode=ParseMode.HTML)
    # Cleanup
    if chat_id in active_auctions:
        del active_auctions[chat_id]


async def stats_view_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handles Stats Menu Clicks with Tree-Style Formatting - DATABASE VERSION"""
    query = update.callback_query
    await query.answer()
    
    try:
        parts = query.data.split("_")
        mode = parts[2]  # 'solo' or 'team'
        target_id = int(parts[3])
    except:
        return

    # ========== FETCH FROM DATABASE ==========
    conn = sqlite3.connect(DB_PATH)
    c = conn.cursor()
    
    c.execute("SELECT * FROM user_stats WHERE user_id = ?", (target_id,))
    db_stats = c.fetchone()
    
    # Count solo matches
    c.execute("""
        SELECT COUNT(*) FROM match_history 
        WHERE match_type = 'SOLO' 
        AND (player_of_match = ? OR group_id IN 
            (SELECT group_id FROM match_history WHERE match_type = 'SOLO'))
    """, (target_id,))
    solo_matches = c.fetchone()[0] if c.fetchone() else 0
    
    # Count solo wins (top 3 finishes)
    c.execute("""
        SELECT COUNT(*) FROM match_history 
        WHERE match_type = 'SOLO' AND player_of_match = ?
    """, (target_id,))
    solo_wins = c.fetchone()[0] if c.fetchone() else 0
    
    conn.close()
    
    # Get Player Name
    try:
        chat = await context.bot.get_chat(target_id)
        name = chat.first_name
    except:
        name = "Player"

    # ========== PARSE DATABASE STATS ==========
    if db_stats:
        (user_id, username, first_name, total_runs, total_balls_faced, total_fours,
         total_sixes, total_fifties, total_hundreds, highest_score, times_not_out,
         total_wickets, total_balls_bowled, total_runs_conceded, total_maidens,
         best_bowling_wickets, best_bowling_runs, five_wicket_hauls,
         matches_played, matches_won, player_of_match_count, last_updated) = db_stats
    else:
        # No stats found
        await query.message.edit_text(
            "รฐลธโล  No stats found!\n"
            "Play some matches to build your profile! รฐลธยย"
        )
        return

