    if mode == "solo":
        # SOLO MODE STATS
        matches = solo_matches if solo_matches > 0 else matches_played
        runs = total_runs
        balls = total_balls_faced
        highest = highest_score
        wins = solo_wins
        
        # Bowling stats (not used in solo)
