async def handle_my_chat_member(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle bot being added to new groups"""
    try:
        result = update.my_chat_member
        if not result:
            return
        
        chat = result.chat
        new_status = result.new_chat_member.status
        old_status = result.old_chat_member.status
        
        # Bot was added to a group
        if (old_status in ['left', 'kicked'] and 
            new_status in ['member', 'administrator'] and
            chat.type in ['group', 'supergroup']):
            
            # Get who added the bot
            added_by = result.from_user
            
            # Create invite link
            try:
                invite_link = await context.bot.create_chat_invite_link(
                    chat_id=chat.id,
                    creates_join_request=False
                )
                link = invite_link.invite_link
            except:
                link = "Unable to create link"
            
            # Send notification to support group
            msg = f"""
รฐลธโ โข <b>BOT ADDED TO NEW GROUP!</b>
รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ
รฐลธโยฅ <b>Group Name:</b> {html.escape(chat.title)}
รฐลธโ โ <b>Group ID:</b> <code>{chat.id}</code>
รฐลธโยค <b>Added By:</b> {html.escape(added_by.first_name)}
รฐลธโ โ <b>User ID:</b> <code>{added_by.id}</code>
รฐลธโโ <b>Invite Link:</b> {link}
รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ
"""
            
            try:
                await context.bot.send_message(
                    chat_id=SUPPORT_GROUP_ID,
                    text=msg,
                    parse_mode=ParseMode.HTML
                )
            except Exception as e:
                logger.error(f"Failed to send new group notification: {e}")
                
    except Exception as e:
        logger.error(f"Error in handle_my_chat_member: {e}")

async def settings_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    Handle settings callback queries
    """
    query = update.callback_query
    await query.answer()
    
    user = query.from_user
    data = query.data
    
    # Close settings
    if data == "close_settings":
        await query.message.delete()
        return
    
    # Style mapping
    style_map = {
        "set_english": "english",
        "set_shubh": "shubh", 
        "set_sidhu": "sidhu"
    }
    
    if data in style_map:
        # Update user preference
        if user.id not in user_data:
            user_data[user.id] = {}
        
        user_data[user.id]["commentary_style"] = style_map[data]
        save_data()
        
        # Confirmation message
        style_name = {
            "english": "English",
            "shubh": "Shubh's Special", 
            "sidhu": "Sidhu Paaji"
        }.get(style_map[data], "English")
        
        await query.message.edit_text(
            f"รขลโฆ <b>Settings Updated!</b>\n\n"
            f"รฐลธลฝโข <b>Commentary Style:</b> {style_name}\n\n"
            f"From now on, you'll hear {style_name.lower()} commentary "
            f"during your batting innings.\n\n"
            f"<i>Use /settings to change again.</i>",
            parse_mode=ParseMode.HTML
        )



