async def broadcastpin_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    รฐลธโล BROADCAST + PIN TO GROUPS
    Usage: Reply to ANY message with /broadcastpin
    Bot forwards and pins it in all groups
    """
    user = update.effective_user
    if user.id != OWNER_ID and user.id not in POWERED_USERS:
        return

    if not update.message.reply_to_message:
        await update.message.reply_text(
            "รขลกย รฏยธย <b>Usage:</b> Reply to any message with <code>/broadcastpin</code>\n\n"
            "Bot will forward and PIN that message to all groups.",
            parse_mode=ParseMode.HTML
        )
        return

    target_message = update.message.reply_to_message
    
    status_msg = await update.message.reply_text(
        "รฐลธโยข <b>BROADCAST + PIN STARTED</b>\n"
        "รขยยณ <i>Forwarding & pinning to all groups...</i>",
        parse_mode=ParseMode.HTML
    )
    
    success = 0
    failed = 0
    pinned = 0
    
    for chat_id in list(registered_groups.keys()):
        if chat_id in banned_groups:
            failed += 1
            continue
            
        try:
            # Forward message
            sent_msg = await context.bot.forward_message(
                chat_id=chat_id,
                from_chat_id=target_message.chat_id,
                message_id=target_message.message_id
            )
            success += 1
            
            # Try to pin
            try:
                await context.bot.pin_chat_message(
                    chat_id=chat_id,
                    message_id=sent_msg.message_id,
                    disable_notification=False
                )
                pinned += 1
            except Exception as pin_error:
                logger.warning(f"Could not pin in {chat_id}: {pin_error}")
            
            await asyncio.sleep(0.05)
        except Exception as e:
            failed += 1
            logger.error(f"Failed broadcast to group {chat_id}: {e}")

    report = (
        "รขลโฆ <b>BROADCAST + PIN COMPLETE!</b>\n"
        "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n\n"
        "รฐลธโล  <b>GROUPS</b>\n"
        f"   รขลโฆ Sent: <code>{success}</code>\n"
        f"   รฐลธโล Pinned: <code>{pinned}</code>\n"
        f"   รขยล Failed: <code>{failed}</code>\n"
        f"   รฐลธลกยซ Banned: <code>{len(banned_groups)}</code>\n"
        f"   รฐลธโล  Total: <code>{len(registered_groups)}</code>\n\n"
        "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ"
    )
    
    await status_msg.edit_text(report, parse_mode=ParseMode.HTML)


