async def endauction_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """End the auction (host/admin only)"""
    
    if update.effective_chat.type == "private":
        await update.message.reply_text("รขยล Use this in a group!")
        return

    group_id = update.effective_chat.id
    user_id = update.effective_user.id
    
    auction = active_auctions.get(group_id)
    
    if not auction:
        await update.message.reply_text("รขยล No active auction to end!")
        return
    
    try:
        member = await update.effective_chat.get_member(user_id)
        is_admin = member.status in ["creator", "administrator"]
    except:
        is_admin = False
    
    is_host = (user_id == auction.host_id)
    is_owner = (user_id == OWNER_ID)
    
    if not (is_host or is_admin or is_owner):
        await update.message.reply_text("รขยล Only host, admins, or bot owner can end the auction!")
        return
    
    if auction.bid_timer_task:
        auction.bid_timer_task.cancel()
        auction.bid_timer_task = None
    
    sold_count = len(auction.sold_players)
    remaining_count = len(auction.player_pool)
    unsold_count = len(auction.unsold_players)

    confirm_kb = InlineKeyboardMarkup([[
        InlineKeyboardButton("รขลโฆ Yes, End Auction", callback_data=f"confirm_endauction_{group_id}"),
        InlineKeyboardButton("รขยล Cancel", callback_data="cancel_endauction")
    ]])

    await update.message.reply_text(
        f"รฐลธยย <b>END AUCTION?</b>\n\n"
        f"รขลโฆ Sold: <b>{sold_count}</b>  |  รขยล Unsold: <b>{unsold_count}</b>  |  รขยยณ Remaining: <b>{remaining_count}</b>\n\n"
        f"Are you sure you want to officially end the auction?\n"
        f"<i>The auction can still continue if you cancel.</i>",
        parse_mode=ParseMode.HTML,
        reply_markup=confirm_kb
    )

async def end_confirmation_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    
    data = query.data
    group_id = update.effective_chat.id
    user_id = update.effective_user.id
    
    # ==========================================
    # รขลโฆ ENDMATCH CONFIRMATION (NO STATS SAVED)
    # ==========================================
    if data == "confirm_endmatch":
        match = active_matches.get(group_id)
        if not match:
            await query.edit_message_text("รขยล No active match found.")
            return
        
        # รฐลธโย CANCEL ALL TASKS
        match.phase = GamePhase.MATCH_ENDED
        
        if hasattr(match, 'ball_timeout_task') and match.ball_timeout_task:
            match.ball_timeout_task.cancel()
        if hasattr(match, 'batsman_selection_task') and match.batsman_selection_task:
            match.batsman_selection_task.cancel()
        if hasattr(match, 'bowler_selection_task') and match.bowler_selection_task:
            match.bowler_selection_task.cancel()
        if hasattr(match, 'join_phase_task') and match.join_phase_task:
            match.join_phase_task.cancel()
        
        # Unpin message
        try:
            if match.main_message_id:
                await context.bot.unpin_chat_message(
                    chat_id=group_id, 
                    message_id=match.main_message_id
                )
        except Exception as e:
            logger.debug(f"Could not unpin message: {e}")
        
        # Generate summary image (optional, no stats saved)
        if match.game_mode == "TEAM":
            try:
                if match.current_batting_team and match.current_bowling_team:
                    if match.current_batting_team.score > match.current_bowling_team.score:
                        winner_team = match.current_batting_team
                    else:
                        winner_team = match.current_bowling_team
                    
                    bio = await generate_team_end_image_v3(match, winner_team.name, context)
                    if bio:
                        await context.bot.send_photo(
                            chat_id=group_id,
                            photo=bio,
                            caption=f"รฐลธยย {match.group_name} - Match Ended (Stats Not Saved) รฐลธยย"
                        )
            except Exception as e:
                logger.error(f"Error generating team end image: {e}")
        
        # รขยล DELETE MATCH (NO STATS SAVED)
        if group_id in active_matches:
            del active_matches[group_id]
        if group_id in processing_commands:
            del processing_commands[group_id]
        
        await query.edit_message_text(
            "รขโขยญรขโยรขโย รฐลธโบโ MATCH ENDED รขโยรขโยรขโยรขโยรขโย\n"
            "รขโฦ รขลกย  Match was forcefully stopped!\n"
            "รขโฦ รขยล Stats were NOT saved to the database.\n"
            "รขโยฃรขโยรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
            "รขโฦ รฐลธลฝยฎ Use /game to start a new match!\n"
            "รขโขยฐรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโย\n",
            parse_mode=ParseMode.HTML
        )
        return
    
    # ==========================================
    # รขลโฆ ENDMATCH CONFIRMATION
    # ==========================================
    if data.startswith("confirm_endmatch_"):
        chat_id = int(data.split("_")[2])
        
        if chat_id not in active_matches:
            await query.message.edit_text("รขลกย รฏยธย Match already ended.")
            return
        
        match = active_matches[chat_id]
        
        # รฐลธโย TRIPLE LOCK MECHANISM
        match.phase = GamePhase.MATCH_ENDED
        
        if match.ball_timeout_task: match.ball_timeout_task.cancel()
        if match.batsman_selection_task: match.batsman_selection_task.cancel()
        if match.bowler_selection_task: match.bowler_selection_task.cancel()
        if hasattr(match, 'join_phase_task') and match.join_phase_task: 
            match.join_phase_task.cancel()
        
        try:
            if match.main_message_id:
                await context.bot.unpin_chat_message(chat_id=chat_id, message_id=match.main_message_id)
        except: pass
        
        del active_matches[chat_id]

        # รฐลธลฝยฌ DONE MESSAGE (removed animation URL fetch that fails on some servers)
        await query.message.reply_text(
            "รฐลธยย <b>MATCH ENDED!</b>\n\nThe match was forcefully stopped.\nรฐลธลฝยฎ Use /game to start again!",
            parse_mode=ParseMode.HTML
        )

        return
    
    # ==========================================
    # รขยล CANCEL ENDMATCH (single handler)
    # ==========================================
    elif data == "cancel_endmatch":
        await query.edit_message_text(
            "รขโยถ <b>Match Continues!</b>\nGame is still active รขโ โ play on! รขลกยก",
            parse_mode=ParseMode.HTML
        )

    # ==========================================
    # รขลโฆ ENDSOLO CONFIRMATION (NO STATS SAVED)
    # ==========================================
    elif data.startswith("confirm_endsolo_"):
        chat_id = int(data.split("_")[2])
        
        if chat_id not in active_matches:
            await query.edit_message_text("รขลกย รฏยธย Solo match already ended.")
            return
        
        match = active_matches[chat_id]
        
        # รฐลธโย CANCEL ALL TASKS
        match.phase = GamePhase.MATCH_ENDED
        
        if hasattr(match, 'ball_timeout_task') and match.ball_timeout_task:
            match.ball_timeout_task.cancel()
        if hasattr(match, 'solo_timer_task') and match.solo_timer_task:
            match.solo_timer_task.cancel()
        if hasattr(match, 'join_phase_task') and match.join_phase_task:
            match.join_phase_task.cancel()
        
        # Unpin message
        try:
            if match.main_message_id:
                await context.bot.unpin_chat_message(
                    chat_id=chat_id,
                    message_id=match.main_message_id
                )
        except Exception as e:
            logger.debug(f"Could not unpin message: {e}")
        
        # Generate summary image (optional, no stats saved)
        try:
            await generate_solo_top3_image(sorted_players)

        except Exception as e:
            logger.error(f"Error generating solo end image: {e}")
        
        # รขยล DELETE MATCH (NO STATS SAVED)
        if chat_id in active_matches:
            del active_matches[chat_id]
        if chat_id in processing_commands:
            del processing_commands[chat_id]
        
        await query.edit_message_text(
            "รฐลธยย <b>SOLO MATCH ENDED!</b>\n\n"
            "รขลกย รฏยธย Match was forcefully stopped.\n"
            "รขยล Stats were NOT saved.\n\n"
            "รฐลธลฝยฎ Use /game to start a new match!",
            parse_mode=ParseMode.HTML
        )
        return

    # ==========================================
    # รขยล CANCEL ENDSOLO
    # ==========================================
    elif data == "cancel_endsolo":
        await query.message.edit_text(
            "รขโยถ <b>Solo Battle Continues!</b>\nFight on! รขลกโรฏยธย",
            parse_mode=ParseMode.HTML
        )

    # ==========================================
    # รขลโฆ ENDAUCTION CONFIRMATION
    # ==========================================
    elif data.startswith("confirm_endauction_"):
        chat_id = int(data.split("_")[2])
        
        if chat_id not in active_auctions:
            await query.message.edit_text("รขลกย รฏยธย Auction already ended.")
            return
        
        auction = active_auctions[chat_id]
        auction.phase = AuctionPhase.AUCTION_ENDED
        
        if auction.bid_timer_task:
            auction.bid_timer_task.cancel()

        # รขลโฆ FIX: Use reply_text instead of reply_animation (URL fetch fails on some servers)
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass
        await query.message.reply_text(
            "รฐลธยย <b>ENDING AUCTION...</b>\nรฐลธโล  Generating final summary...",
            parse_mode=ParseMode.HTML
        )

        await asyncio.sleep(1)
        await end_auction(context, chat_id, auction)
        return

    # ==========================================
    # รขยล CANCEL ENDAUCTION
    # ==========================================
    elif data == "cancel_endauction":
        await query.message.edit_text(
            "รขโยถ <b>Auction Continues!</b>\nBidding still active รขโ โ go on! รฐลธโยธ",
            parse_mode=ParseMode.HTML
        )


async def get_all_file_ids(update: Update, context: ContextTypes.DEFAULT_TYPE):
    msg = update.message
    file_id = None
    media_type = None

    # --- LIST OF CHECKS ---
    
    # 1. Photo (Yeh list hoti hai, last wali best quality)
    if msg.photo:
        file_id = msg.photo[-1].file_id
        media_type = "รฐลธโยธ Photo"

    # 2. GIF (Animation)
    elif msg.animation:
        file_id = msg.animation.file_id
        media_type = "รฐลธลฝลพรฏยธย GIF"

    # 3. Video
    elif msg.video:
        file_id = msg.video.file_id
        media_type = "รฐลธลฝยฅ Video"

    # 4. Document (Files/Zip/Pdf)
    elif msg.document:
        file_id = msg.document.file_id
        media_type = "รฐลธโย Document"

    # 5. Audio (Songs/MP3)
    elif msg.audio:
        file_id = msg.audio.file_id
        media_type = "รฐลธลฝยต Audio"

    # 6. Voice Note
    elif msg.voice:
        file_id = msg.voice.file_id
        media_type = "รฐลธลฝยค Voice Note"

    # 7. Sticker
    elif msg.sticker:
        file_id = msg.sticker.file_id
        media_type = "รฐลธยคยก Sticker"
        
    # 8. Video Note (Gol wala video)
    elif msg.video_note:
        file_id = msg.video_note.file_id
        media_type = "รฐลธลธยฃ Video Note"

    # --- RESULT ---
    if file_id:
        await msg.reply_text(
            f"<b>{media_type} Detect hua!</b>\n\nรฐลธโ โ <b>File ID:</b>\n<code>{file_id}</code>",
            parse_mode=ParseMode.HTML
        )
    else:
        # Agar user ne sirf text likha ho
        await msg.reply_text("Bhai text mat bhejo, koi Media (Photo/GIF/File) bhejo.")

