async def commentary_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    รฐลธลฝโขรฏยธย ADMIN ONLY: Change commentary style for entire group
    Usage: /commentary [english/shubh/sidhu]
    """
    chat = update.effective_chat
    user = update.effective_user
    
    # Check if group
    if chat.type == "private":
        await update.message.reply_text("This command only works in groups!")
        return
    
    # Check if user is admin
    try:
        member = await context.bot.get_chat_member(chat.id, user.id)
        if member.status not in ["creator", "administrator"]:
            await update.message.reply_text(
                "รขลกย รฏยธย <b>Admin Only!</b>\n"
                "Only group admins can change commentary style.",
                parse_mode=ParseMode.HTML
            )
            return
    except Exception as e:
        logger.error(f"Admin check failed: {e}")
        await update.message.reply_text("รขลกย รฏยธย Could not verify admin status.")
        return
    
    # Check arguments
    if not context.args:
        # Show current settings with buttons
        current_style = registered_groups.get(chat.id, {}).get("commentary_style", "english")
        
        keyboard = [
            [InlineKeyboardButton("รฐลธโกยฌรฐลธโกยง English", callback_data=f"gcommentary_english_{chat.id}")],
            [InlineKeyboardButton("รขลกย รฏยธย Shubh's Special", callback_data=f"gcommentary_shubh_{chat.id}")],
            [InlineKeyboardButton("รฐลธหลฝ Sidhu Style", callback_data=f"gcommentary_sidhu_{chat.id}")]
        ]
        reply_markup = InlineKeyboardMarkup(keyboard)
        
        msg = f"รฐลธลฝโขรฏยธย <b>GROUP COMMENTARY SETTINGS</b>\n"
        msg += "รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
        msg += f"รฐลธโยข <b>Current Style:</b> {current_style.upper()}\n\n"
        msg += "<b>Options:</b>\n"
        msg += "รขโฌยข รฐลธโกยฌรฐลธโกยง <b>English:</b> Professional commentary\n"
        msg += "รขโฌยข รขลกย รฏยธย <b>Shubh's Special:</b> Hindi+English mix\n"
        msg += "รขโฌยข รฐลธหลฝ <b>Sidhu:</b> Fun Punjabi style\n\n"
        msg += "<i>Click button to change for all group matches.</i>"
        
        # Send with photo
        try:
            await update.message.reply_photo(
                photo=COMMENTARY_PHOTO,
                caption=msg,
                reply_markup=reply_markup,
                parse_mode=ParseMode.HTML
            )
        except Exception as e:
            logger.error(f"Error sending commentary photo: {e}")
            # Fallback to text
            await update.message.reply_text(msg, reply_markup=reply_markup, parse_mode=ParseMode.HTML)
        return
    
    # Process text command
    style = context.args[0].lower()
    valid_styles = ["english", "shubh", "sidhu"]
    
    if style not in valid_styles:
        await update.message.reply_text(
            "รขลกย รฏยธย <b>Invalid style!</b>\n\n"
            "Available styles:\n"
            "รขโฌยข <code>english</code>\n"
            "รขโฌยข <code>shubh</code>\n"
            "รขโฌยข <code>sidhu</code>\n\n"
            "Example: <code>/commentary Shubh</code>",
            parse_mode=ParseMode.HTML
        )
        return
    
    # Save to group settings
    if chat.id not in registered_groups:
        registered_groups[chat.id] = {
            "group_id": chat.id,
            "group_name": chat.title,
            "total_matches": 0,
            "commentary_style": style
        }
    else:
        registered_groups[chat.id]["commentary_style"] = style
    
    save_data()
    
    style_name = {
        "english": "English",
        "shubh": "Shubh's Special",
        "sidhu": "Sidhu Paaji"
    }.get(style, "English")
    
    await update.message.reply_text(
        f"รขลโฆ <b>Group Commentary Updated!</b>\n\n"
        f"รฐลธลฝโขรฏยธย <b>New Style:</b> {style_name}\n"
        f"รฐลธโยฅ <b>For:</b> All matches in this group\n"
        f"รฐลธโยฎ <b>Changed by:</b> {user.first_name} (Admin)\n\n"
        f"<i>From now on, all matches will use {style_name.lower()} commentary.</i>",
        parse_mode=ParseMode.HTML
    )



