async def groupapprove_tournament_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """รฐลธยย Approve group for tournament registration"""
    if update.effective_user.id not in [OWNER_ID, SECOND_APPROVER_ID]:
        await update.message.reply_text("รฐลธยย Only organizers can approve groups for tournaments!")
        return
    
    if update.effective_chat.type == "private":
        if not context.args:
            await update.message.reply_text(
                "รฐลธยย Tournament & Registration Approval\n"
                "Usage: `/groupapprove <group_id>`\n"
                "Example: `/groupapprove -1001234567890`",
                parse_mode=ParseMode.MARKDOWN
            )
            return
        try:
            group_id = int(context.args[0])
        except:
            await update.message.reply_text("รฐลธยย Invalid group ID!")
            return
    else:
        group_id = update.effective_chat.id
    
    conn = sqlite3.connect(TOURNAMENT_DB_PATH)
    c = conn.cursor()
    
    try:
        chat = await context.bot.get_chat(group_id)
        group_name = chat.title
    except:
        group_name = "Unknown Group"
    
    c.execute('INSERT OR REPLACE INTO tournament_groups (group_id, group_name, approved_at, expires_at, reminder_sent) VALUES (?, ?, CURRENT_TIMESTAMP, ?, 0)', 
              (group_id, group_name, (datetime.now() + timedelta(days=30)).isoformat()))
    conn.commit()
    conn.close()
    
    TOURNAMENT_APPROVED_GROUPS.add(group_id)
    
    await update.message.reply_text(
        f"รฐลธยย Tournament & Registration Approved!\n"
        f"Group: {group_name}\n"
        f"ID: `{group_id}`\n\n"
        f"Ready for player registration!",
        parse_mode=ParseMode.MARKDOWN
    )

async def registration_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """รฐลธยย Open tournament registration"""
    if update.effective_user.id not in [OWNER_ID, SECOND_APPROVER_ID]:
        await update.message.reply_text("รฐลธยย Only organizers can open registration!")
        return
    
    if not context.args:
        await update.message.reply_text(
            "รฐลธยย Open Registration\n"
            "Usage: `/registration <group_id>`",
            parse_mode=ParseMode.MARKDOWN
        )
        return
    
    try:
        group_id = int(context.args[0])
    except:
        await update.message.reply_text("รฐลธยย Invalid group ID!")
        return

    if group_id not in TOURNAMENT_APPROVED_GROUPS:
        return
    
    if group_id in REGISTRATION_ACTIVE:
        await update.message.reply_text("รฐลธยย Registration already active for this group!")
        return
    
    context.user_data['awaiting_tournament_name'] = group_id
    await update.message.reply_text(
        "รฐลธยย Opening Registration\n"
        "What is the tournament name?\n"
        "Reply with the name (e.g., 'IPL 2026')",
        parse_mode=ParseMode.MARKDOWN
    )

