async def scorecard_refresh_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """รฐลธโโ Refresh scorecard from inline button"""
    query = update.callback_query
    await query.answer("รฐลธโโ Refreshing...", show_alert=False)
    try:
        group_id = int(query.data.split("_")[-1])
    except Exception:
        group_id = update.effective_chat.id

    match = active_matches.get(group_id)
    if not match:
        await query.answer("รขยล No active match!", show_alert=True)
        return

    def _bat_line(pl, team):
        _sr = round((pl.runs / max(pl.balls_faced, 1)) * 100, 1)
        not_out = "*" if not pl.is_out and pl.balls_faced > 0 else ""
        return (
            f"รขโฦ รฐลธโยค {html.escape(pl.first_name[:16])}{not_out} รขลพโ {pl.runs} ({pl.balls_faced}b)  |  SR: {_sr}\n"
        )

    def _bowl_line(pl):
        if pl.balls_bowled == 0: return ""
        _ov   = format_overs(pl.balls_bowled)
        _econ = round(pl.runs_conceded / max(pl.balls_bowled / 6, 0.1), 2)
        return f"รขโฦ รฐลธโยค {html.escape(pl.first_name[:16])} รขลพโ {pl.wickets}/{pl.runs_conceded} ({_ov} ) | รฐลธโโฐ Eco: {_econ}\n"

    def _inn_block(bat_team, bowl_team, inn_label, inn_num):
        rr = round(bat_team.score / (bat_team.balls / 6), 2) if bat_team.balls > 0 else 0
        extras = bat_team.extras if hasattr(bat_team, 'extras') else 0
        inn_ordinal = "1st" if inn_num == "1st" else "2nd"
        s = (
            f"รขโขยญรขโยรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
            f"รขโฦ รฐลธยโ  {inn_ordinal} INNINGS รขลพโ {html.escape(bat_team.name)}\n"
            f"รขโฦ รฐลธโล  {bat_team.score}/{bat_team.wickets} ({format_overs(bat_team.balls)} ) | รฐลธโห RR: {rr}\n"
            f"รขโฦ รขลกโรฏยธย Extras: {extras}\n"
            f"รขโยฃรขโยรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
            f"รขโฦ รฐลธยย BATTING\n"
        )
        batters = [p for p in bat_team.players if p.balls_faced > 0 or p.is_out]
        for pl in batters:
            s += _bat_line(pl, bat_team)
        if not batters:
            s += "รขโฦ <i>Not started yet</i>\n"
        s += f"รขโยฃรขโยรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\nรขโฦ รฐลธยฅลฝ BOWLING\n"
        bowlers = [p for p in bowl_team.players if p.balls_bowled > 0]
        for pl in bowlers:
            s += _bowl_line(pl)
        if not bowlers:
            s += "รขโฦ <i>No bowlers yet</i>\n"
        s += "รขโขยฐรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโยรขโย\n"
        return s

    first  = match.batting_first or match.team_x
    second = match.team_y if first == match.team_x else match.team_x

    now = datetime.now().strftime("%d %b %Y  %H:%M")
    text = f"รฐลธโล  Cricoverse Scorecard\n"

    text += _inn_block(first, second, "1ST", "1st")
    if match.innings >= 2:
        if match.target > 0:
            _nd = match.target - second.score
            _bl = (match.total_overs * 6) - second.balls
            _rr = round(_nd / (_bl / 6), 2) if _bl > 0 else 0
            text += f"รฐลธลฝยฏ Target: {match.target} Runs\n"
        text += _inn_block(second, first, "2nd Innings", "2nd")
    if match.current_partnership_runs > 0:
        text += f"รฐลธยคย <b>Partnership:</b> {match.current_partnership_runs}({match.current_partnership_balls})\n"
    text += "\nรฐลธโโฐ Tap Refresh for latest scores!"

    refresh_kb = InlineKeyboardMarkup([[
        InlineKeyboardButton("รฐลธโโ Refresh Scorecard", callback_data=f"scorecard_refresh_{group_id}")
    ]])

    # Telegram caption limit is 1024 chars; if longer, truncate with note
    display_text = text if len(text) <= 1024 else text[:1020] + "\n<i>รขโฌยฆuse /scorecard for full view</i>"

    try:
        await query.edit_message_caption(caption=display_text, parse_mode=ParseMode.HTML, reply_markup=refresh_kb)
    except Exception:
        try:
            await query.edit_message_text(text=display_text, parse_mode=ParseMode.HTML, reply_markup=refresh_kb)
        except Exception:
            await query.answer("รขลโฆ Already up to date!", show_alert=False)


