async def qbatting_confirm_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle qbatting confirmation"""
    query = update.callback_query
    await query.answer()
    user = query.from_user
    parts = query.data.split("_")

    if query.data.startswith("qbat_cancel_"):
        await query.message.edit_text("รขยล <b>Queue cancelled.</b>", parse_mode=ParseMode.HTML)
        return

    if query.data.startswith("qbat_confirm_"):
        try:
            group_id = int(parts[2])
            player_uid = int(parts[3])
            serial = int(parts[4])
        except (IndexError, ValueError):
            await query.answer("รขยล Invalid data.", show_alert=True)
            return

        if group_id not in active_matches:
            await query.message.edit_text("รขยล No active match.", parse_mode=ParseMode.HTML)
            return

        match = active_matches[group_id]
        bat_team = match.current_batting_team

        # Batting captain or host can confirm
        is_captain = bool(bat_team.captain_id and user.id == bat_team.captain_id)
        is_host = (user.id == match.host_id)
        if not is_captain and not is_host:
            await query.answer("รฐลธลกยซ Only the batting captain or host can confirm!", show_alert=True)
            return

        player = bat_team.get_player(player_uid)
        if not player:
            await query.message.edit_text("รฐลธลกยซ Player not found in team.", parse_mode=ParseMode.HTML)
            return
        if player.is_out:
            await query.message.edit_text(f"รฐลธโโฌ {player.first_name} is already OUT!", parse_mode=ParseMode.HTML)
            return

        q = _get_queue(group_id, "batting")
        if player_uid in q:
            await query.message.edit_text(f"รขลกย รฏยธย {player.first_name} is already in the queue.", parse_mode=ParseMode.HTML)
            return
        if len(q) >= 3:
            await query.message.edit_text("รฐลธลกยซ Queue is full (max 3).", parse_mode=ParseMode.HTML)
            return

        q.append(player_uid)
        pos = len(q)
        queue_names = [bat_team.get_player(uid).first_name for uid in q if bat_team.get_player(uid)]

        await query.message.edit_text(
            f"รขลโฆ <b>BATTING QUEUE UPDATED!</b>\n"
            f"รขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌรขโโฌ\n"
            f"รฐลธยย <b>{player.first_name}</b> added at position #{pos}\n"
            f"รฐลธโโน <b>Queue:</b> {' รขโ โ '.join(queue_names)}\n\n"
            f"<i>Next wicket, this batsman walks in automatically!</i>",
            parse_mode=ParseMode.HTML
        )



